-- Poems batch 34
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('5c980c4e-a8b9-4db8-9c46-8b05b644636d','寄崔先生','溫庭筠','唐','唐诗','tang','','[]','往年江海別元卿，家近山陽古郡城。',64,'全唐诗/poet.tang.32000.json','["往年江海別元卿，家近山陽古郡城。", "蓮浦香中離席散，柳堤風裏釣船橫。", "星霜荏苒無音信，煙水微茫變姓名。", "菰黍正肥魚正美，五侯門下負平生。"]'),
('6d68ac4e-db5a-4d16-8b80-5b5f035559b2','敬荅李先生','溫庭筠','唐','唐诗','tang','','[]','七里灘聲舜廟前，杏花初盛草芊芊。',64,'全唐诗/poet.tang.32000.json','["七里灘聲舜廟前，杏花初盛草芊芊。", "綠昏晴氣春風岸，紅漾輕綸野水天。", "不爲傷離成極望，更因行樂惜流年。", "一瓢無事麛裘暖，手弄溪波坐釣船。"]'),
('3eca4a53-2996-4fa4-8666-c94201243541','宿灃曲僧舍','溫庭筠','唐','唐诗','tang','','[]','東郊和氣新，芳靄遠如塵。',48,'全唐诗/poet.tang.32000.json','["東郊和氣新，芳靄遠如塵。", "客舍停疲馬，僧牆畫故人。", "沃田桑景晚，平野菜花春。", "更想嚴家瀨，微風蕩白蘋。"]'),
('9b78e2c8-f630-4cce-b91a-08bff2b84616','宿一公精舍','溫庭筠','唐','唐诗','tang','','[]','夜闌黃葉寺，瓶錫兩俱能。',48,'全唐诗/poet.tang.32000.json','["夜闌黃葉寺，瓶錫兩俱能。", "松下石橋路，雨中山殿燈。", "茶爐天姥客，棊席剡溪僧。", "還笑長門賦，高秋臥茂陵。"]'),
('b68fa0cc-21c8-4c35-a0f9-2268070d3559','月中宿雲居寺上方','溫庭筠','唐','唐诗','tang','','[]','虛閤披衣坐，寒堦踏葉行。',48,'全唐诗/poet.tang.32000.json','["虛閤披衣坐，寒堦踏葉行。", "衆星中夜少，圓月上方明。", "靄盡無林色，喧餘有澗聲。", "祗應愁恨事，還逐曉光生。"]'),
('00386e6d-492f-4531-a527-69b20c28d345','登盧氏臺','溫庭筠','唐','唐诗','tang','','[]','勝地當通邑，前山有故居。',48,'全唐诗/poet.tang.32000.json','["勝地當通邑，前山有故居。", "臺高秋盡出，林斷野無餘。", "白露鳴蛩急，晴天度雁疎。", "由來放懷地，非獨在吾廬。"]'),
('08beb140-b310-459c-bde8-fee049e1d102','牡丹二首 一','溫庭筠','唐','唐诗','tang','','[]','輕陰隔翠幃，宿雨泣晴暉。',48,'全唐诗/poet.tang.32000.json','["輕陰隔翠幃，宿雨泣晴暉。", "醉後佳期在，歌餘舊意非。", "蝶繁經粉住，蜂重抱香歸。", "莫惜薰爐夜，因風到舞衣。"]'),
('aa9e8394-46b3-41a0-b483-4342a5d54058','牡丹二首 二','溫庭筠','唐','唐诗','tang','','[]','水漾晴紅壓疊波，曉來金粉覆庭莎。',64,'全唐诗/poet.tang.32000.json','["水漾晴紅壓疊波，曉來金粉覆庭莎。", "裁成豔思偏應巧，分得春光最數多。", "欲綻似含雙靨笑，正繁疑有一聲歌。", "華堂客散簾垂地，想凭闌干歛翠蛾。"]'),
('eea9e459-2092-4f7d-a28b-1e7b3d0af58c','反生桃花發因題','溫庭筠','唐','唐诗','tang','','[]','疾眼逢春四壁空，夜來山雪破東風。',64,'全唐诗/poet.tang.32000.json','["疾眼逢春四壁空，夜來山雪破東風。", "未知王母千年熟，且共劉郎一笑同。", "已落又開橫晚翠，似無如有帶朝紅。", "僧虔蠟炬高三尺，莫惜連宵照露叢。"]'),
('915f4d25-28e2-4a3c-82de-6af7e241e0dc','杏花','溫庭筠','唐','唐诗','tang','','[]','紅花初綻雪花繁，重疊高低滿小園。',64,'全唐诗/poet.tang.32000.json','["紅花初綻雪花繁，重疊高低滿小園。", "正見盛時猶悵望，豈堪開處已繽翻。", "情爲世累詩千首，醉是吾鄉酒一樽。", "杳杳豔歌春日午，出牆何處隔朱門。"]'),
('6bf84891-b511-41a5-99ed-5bb23f9b8ca3','和太常杜少卿東都脩[行]里有嘉蓮','溫庭筠','唐','唐诗','tang','','[]','春秋罷注直銅龍，舊宅嘉蓮照水紅。',64,'全唐诗/poet.tang.32000.json','["春秋罷注直銅龍，舊宅嘉蓮照水紅。", "兩處龜巢清露裏，一時魚躍翠莖東。", "同心表瑞荀池上，半面分妝樂鏡中。", "應爲臨川多麗句，故持重豔向西風。"]'),
('f9283238-3bd2-4a4d-890b-e31483c7906b','題磁嶺海棠花','溫庭筠','唐','唐诗','tang','','[]','幽態竟誰賞，歲華空與期。',48,'全唐诗/poet.tang.32000.json','["幽態竟誰賞，歲華空與期。", "島迴香盡處，泉照豔濃時。", "蜀彩淡搖曳，吳妝低怨思。", "王孫又誰恨，惆悵下山遲。"]'),
('66aafecf-6095-4a95-917c-e509fd56cb86','苦楝花','溫庭筠','唐','唐诗','tang','','[]','院裏鶯歌歇，牆頭蝶舞孤。',48,'全唐诗/poet.tang.32000.json','["院裏鶯歌歇，牆頭蝶舞孤。", "天香薰羽葆，宮紫暈流蘇。", "晻曖迷青瑣，氤氳向畫圖。", "只應春惜別，留與博山爐。"]'),
('385c76fb-c45b-49e3-9958-91fb3b08b927','自有扈至京師已後朱櫻之期','溫庭筠','唐','唐诗','tang','','[]','露圓霞赤數千枝，銀籠誰家寄所思。',64,'全唐诗/poet.tang.32000.json','["露圓霞赤數千枝，銀籠誰家寄所思。", "秦苑飛禽諳熟早，杜陵遊客恨來遲。", "空看翠幄成陰日，不見紅珠滿樹時。", "盡日徘徊濃影下，祗應重作釣魚期。"]'),
('cde19b81-d062-4bca-915d-352157c3a198','答段柯古見嘲','溫庭筠','唐','唐诗','tang','','[]','彩翰殊翁金繚繞，一千二百逃飛鳥。',32,'全唐诗/poet.tang.32000.json','["彩翰殊翁金繚繞，一千二百逃飛鳥。", "尾薪橋下未爲癡，暮雨朝雲世間少。"]'),
('eb424b41-4b6e-4c5b-979b-b109cae6db68','蓮花','溫庭筠','唐','唐诗','tang','','["\u8377\u82b1", "\u548f\u7269", "\u548f\u7269\u8bd7"]','綠塘搖灩接星津，軋軋蘭橈入白蘋。',32,'全唐诗/poet.tang.32000.json','["綠塘搖灩接星津，軋軋蘭橈入白蘋。", "應爲洛神波上韈，至今蓮蘂有香塵。"]'),
('ce747c86-a756-4fdb-83f8-a0216dcbf3ab','過吳景帝陵','溫庭筠','唐','唐诗','tang','','[]','王氣銷來水淼茫，豈能才與命相妨。',32,'全唐诗/poet.tang.32000.json','["王氣銷來水淼茫，豈能才與命相妨。", "虛開直瀆三千里，青蓋何曾到洛陽。"]'),
('03ad4be6-155c-4ce6-a085-4d06ccf0a140','龍尾驛婦人圖','溫庭筠','唐','唐诗','tang','','[]','慢笑開元有倖臣，直敎天子到蒙塵。',32,'全唐诗/poet.tang.32000.json','["慢笑開元有倖臣，直敎天子到蒙塵。", "今來看畫猶如此，何況親逢絕世人。"]'),
('eb4e0a9a-e59b-4650-9e2b-335ef5f83f4f','薛氏池垂釣','溫庭筠','唐','唐诗','tang','','[]','池塘經雨更蒼蒼，萬點荷珠曉氣涼。',32,'全唐诗/poet.tang.32000.json','["池塘經雨更蒼蒼，萬點荷珠曉氣涼。", "朱瑀空偷御溝水，錦鱗紅尾屬嚴光。"]'),
('d56fe90a-6357-40d4-9ae3-3ec98f03a01e','簡同志','溫庭筠','唐','唐诗','tang','','[]','開濟由來變盛衰，五車纔得號鎡基。',32,'全唐诗/poet.tang.32000.json','["開濟由來變盛衰，五車纔得號鎡基。", "留侯功業何容易，一卷兵書作帝師。"]'),
('8d1895aa-a267-42d3-8acf-be58cfee7df0','瑟瑟釵','溫庭筠','唐','唐诗','tang','','[]','翠染冰輕透露光，墮雲孫壽有餘香。',32,'全唐诗/poet.tang.32000.json','["翠染冰輕透露光，墮雲孫壽有餘香。", "只因七夕回天浪，添作湘妃淚兩行。"]'),
('0e4058d3-9158-434a-ad2c-d46ed5cc73e2','元日','溫庭筠','唐','唐诗','tang','','[]','神耀破氛昏，新陽入晏溫。',48,'全唐诗/poet.tang.32000.json','["神耀破氛昏，新陽入晏溫。", "緒風調玉吹，端日應銅渾。", "威鳳蹌瑤簴，升龍護璧門。", "雨暘春令煦，裘冕晬容尊。"]'),
('575c2162-ca4d-48be-82c8-f6afda95ae39','二月十五日櫻桃盛開自所居躡履吟翫競名王澤章洋才','溫庭筠','唐','唐诗','tang','','[]','曉覺籠煙重，春深染雪輕。',48,'全唐诗/poet.tang.32000.json','["曉覺籠煙重，春深染雪輕。", "靜應留得蝶，繁欲不勝鶯。", "影亂晨飆急，香多夜雨晴。", "似將千萬恨，西北爲卿卿。"]'),
('323a84b9-bb22-4e62-b77a-3f051f2ab401','寒食節日寄楚望二首 一','溫庭筠','唐','唐诗','tang','','[]','芳蘭無意綠，弱柳何窮縷。',96,'全唐诗/poet.tang.32000.json','["芳蘭無意綠，弱柳何窮縷。", "心斷入淮山，夢長穿楚雨。", "繁花如二八，好月當三五。", "愁碧竟平臯，韶紅換幽圃。", "流鶯隱員樹，乳燕喧餘哺。", "曠望戀曾臺，離憂集環堵。", "當年不自遣，晚得終何補。", "鄭谷有樵蘇，歸來要腰斧。"]'),
('057cfa1b-fb2e-4c46-8c82-e5de0e499b20','寒食節日寄楚望二首 二','溫庭筠','唐','唐诗','tang','','[]','家乏兩千萬，時當一百五。',96,'全唐诗/poet.tang.32000.json','["家乏兩千萬，時當一百五。", "颸颸楊柳風，穰穰櫻桃雨。", "年芳苦沈潦，心事如摧櫓。", "金犢近蘭汀，銅龍接花塢。", "青蔥建楊宅，隱轔端門鼓。", "綵素拂庭柯，輕毬落鄰圃。", "三春謝游衍，一笑牽規矩。", "獨有恩澤侯，歸來看楚舞。"]'),
('65c96a3e-fba7-4cf8-af72-5f1f57762462','清明日','溫庭筠','唐','唐诗','tang','','["\u6e05\u660e\u8282", "\u8e0f\u9752"]','清娥畫扇中，春樹鬱金紅。',48,'全唐诗/poet.tang.32000.json','["清娥畫扇中，春樹鬱金紅。", "出犯繁花露，歸穿弱柳風。", "馬驕偏避幰，雞駭乍開籠。", "柘彈何人發，黃鸝隔故宮。"]'),
('0dfa0f12-2290-4904-a663-bcb7480d077e','禁火日','溫庭筠','唐','唐诗','tang','','[]','駘蕩清明日，儲胥小苑東。',48,'全唐诗/poet.tang.32000.json','["駘蕩清明日，儲胥小苑東。", "舞衫萱草綠，春鬢杏花紅。", "馬轡輕銜雪，車衣弱向風。", "□愁聞百舌，殘睡正朦朧。"]'),
('c5841edd-bd55-42c2-b84e-0d7f743ff116','嘲三月十八日雪','溫庭筠','唐','唐诗','tang','','["\u68a8\u82b1", "\u5199\u96ea", "\u96ea"]','三月雪連夜，未應傷物華。',24,'全唐诗/poet.tang.32000.json','["三月雪連夜，未應傷物華。", "只緣春欲盡，留著伴梨花。"]'),
('2d31960c-d25a-4a87-bfb0-b98efa79bf47','楊柳八首 一','溫庭筠','唐','唐诗','tang','','[]','宜春苑外最長條。',32,'全唐诗/poet.tang.32000.json','["宜春苑外最長條。", "閑褭春風伴舞腰，正是玉人腸斷處。", "一渠春水赤闌橋。"]'),
('4656ce47-275b-4a86-9dbd-da18c4c0ffbf','楊柳八首 二','溫庭筠','唐','唐诗','tang','','[]','南內牆東御路旁，預知春色柳絲黃。',32,'全唐诗/poet.tang.32000.json','["南內牆東御路旁，預知春色柳絲黃。", "杏花未肯無情思，何是情人最斷腸。"]'),
('16c21dcb-a84e-4068-b934-c0a5518aa478','楊柳八首 三','溫庭筠','唐','唐诗','tang','','["\u548f\u7269", "\u67f3\u6811", "\u5199\u4eba", "\u548f\u7269\u8bd7"]','蘇小門前柳萬條，毶毶金線拂平橋。',32,'全唐诗/poet.tang.32000.json','["蘇小門前柳萬條，毶毶金線拂平橋。", "黃鶯不語東風起，深閉朱門伴細腰。"]'),
('1c03ffdd-3b92-4582-9930-b8a07a3ba179','楊柳八首 四','溫庭筠','唐','唐诗','tang','','[]','金縷毶毶碧瓦溝，六宮眉黛惹春愁。',32,'全唐诗/poet.tang.32000.json','["金縷毶毶碧瓦溝，六宮眉黛惹春愁。", "晚來更帶龍池雨，半拂闌干半入樓。"]'),
('654a58d7-6cfc-4435-a218-f733476a3e58','楊柳八首 五','溫庭筠','唐','唐诗','tang','','[]','館娃宮外鄴城西，遠映征帆近拂堤。',32,'全唐诗/poet.tang.32000.json','["館娃宮外鄴城西，遠映征帆近拂堤。", "繫得王孫歸意切，不關春草綠萋萋。"]'),
('f86ff3bb-c21e-4aee-84f4-b40ad7141140','楊柳八首 六','溫庭筠','唐','唐诗','tang','','[]','兩兩黃鸝色似金，褭枝啼露動芳音。',32,'全唐诗/poet.tang.32000.json','["兩兩黃鸝色似金，褭枝啼露動芳音。", "春來幸自長如線，可惜牽纏蕩子心。"]'),
('1322d148-cf71-42ff-90f1-1aae04a5726d','楊柳八首 七','溫庭筠','唐','唐诗','tang','','["\u67f3\u6811", "\u5bab\u5ef7", "\u5199\u666f"]','御柳如絲映九重，鳳皇窗柱繡芙蓉。',32,'全唐诗/poet.tang.32000.json','["御柳如絲映九重，鳳皇窗柱繡芙蓉。", "景陽樓畔千條露，一面新妝待曉鐘。"]'),
('5d777d8e-a869-415a-b8d3-b74b98b5288a','楊柳八首 八','溫庭筠','唐','唐诗','tang','','[]','織錦機邊鶯語頻，停梭垂淚憶征人。',32,'全唐诗/poet.tang.32000.json','["織錦機邊鶯語頻，停梭垂淚憶征人。", "塞門三月猶蕭索，縱有垂楊未覺春。"]'),
('e65b8909-1235-4fbd-9f5d-40d81d4b3112','客愁','溫庭筠','唐','唐诗','tang','','[]','客愁看柳色，日日逐春深。',24,'全唐诗/poet.tang.32000.json','["客愁看柳色，日日逐春深。", "蕩漾春風裏，誰知歷亂心。"]'),
('fa812073-86cf-4b9d-9539-3bee917a5cf2','和周繇','溫庭筠','唐','唐诗','tang','','[]','齊馬馳千駟，盧姬逞十三。',72,'全唐诗/poet.tang.32000.json','["齊馬馳千駟，盧姬逞十三。", "玳筵方喜睞，金勒自䟃𧽼。", "墮珥情初洽，鳴鞭戰未酣。", "神交花冉冉，眉語柳毶毶。", "却略青鸞鏡，翹翻翠鳳篸。", "專城有佳對，寧肯顧春蠶。"]'),
('3b06a903-4fa6-48a9-9dd4-55ea26e92afc','光風亭夜宴妓有醉毆者','溫庭筠','唐','唐诗','tang','','[]','吳國初成陣，王家欲解圍。',24,'全唐诗/poet.tang.32000.json','["吳國初成陣，王家欲解圍。", "拂巾雙雉呌，飄瓦兩鴛飛。"]'),
('688fb8de-66a2-4b46-a27b-4de5336730b2','南歌子詞二首 一','溫庭筠','唐','唐诗','tang','','[]','一尺深紅勝麴塵，天生舊物不如新。',32,'全唐诗/poet.tang.32000.json','["一尺深紅勝麴塵，天生舊物不如新。", "合歡桃核終堪恨，裏許元來別有人。"]'),
('c537e4db-502d-45dd-a795-aed2d2a95d6d','南歌子詞二首 二','溫庭筠','唐','唐诗','tang','','[]','井底點燈深燭伊，共郎長行莫圍棊。',32,'全唐诗/poet.tang.32000.json','["井底點燈深燭伊，共郎長行莫圍棊。", "玲瓏骰子安紅豆，入骨相思知不知。"]'),
('c80158ca-6953-4032-a5c8-87891536a441','題李衛公詩二首 一','溫庭筠','唐','唐诗','tang','','[]','蒿棘深春衛國門，九年於此盜乾坤。',64,'全唐诗/poet.tang.32000.json','["蒿棘深春衛國門，九年於此盜乾坤。", "兩行密疏傾天下，一夜陰謀達至尊。", "肉視具僚忘匕箸，氣吞同列削寒溫。", "當時誰是承恩者，肯有餘波達鬼邨。"]'),
('e707b6c3-ba99-478c-bd91-9accdb6409c5','題李衛公詩二首 二','溫庭筠','唐','唐诗','tang','','[]','勢欲凌雲威觸天，權傾諸夏力排山。',64,'全唐诗/poet.tang.32000.json','["勢欲凌雲威觸天，權傾諸夏力排山。", "三年驥尾有人附，一日龍鬚無路攀。", "畫閤不開梁燕去，朱門罷埽乳鴉還。", "千巖萬壑應惆悵，流水斜傾出武關。"]'),
('81b2b013-93a2-4e0b-853a-5b005bac410c','題谷隱蘭若','溫庭筠','唐','唐诗','tang','','[]','風帶巢熊拗樹聲，老僧相引入雲行。',32,'全唐诗/poet.tang.32000.json','["風帶巢熊拗樹聲，老僧相引入雲行。", "半坡新路畬纔了，一谷寒煙燒不成。"]'),
('30da3614-2556-4eaa-bfa8-a97145f54895','觀棋','溫庭筠','唐','唐诗','tang','','[]','閑對楸枰傾一壺，黃華坪上幾成盧。',32,'全唐诗/poet.tang.32000.json','["閑對楸枰傾一壺，黃華坪上幾成盧。", "他時謁帝銅龍水，便賭宣城太守無。"]'),
('64994a46-d3eb-436b-880f-a297a858fcc0','句','溫庭筠','唐','唐诗','tang','','[]','春水碧于天，畫船聽雨眠。',28,'全唐诗/poet.tang.32000.json','["春水碧于天，畫船聽雨眠。", "綠樹遶村含細雨，寒潮背郭捲平沙。"]'),
('ef67c8e4-b627-4ffa-a8b1-c5cdffa35591','觀山燈獻徐尚書 一','段成式','唐','唐诗','tang','','[]','風杪影凌亂，露輕光陸離。',48,'全唐诗/poet.tang.32000.json','["風杪影凌亂，露輕光陸離。", "如霞散仙掌，似燒上峨嵋。", "道樹千花發，扶桑九日移。", "因山成衆像，不復藉蟠螭。"]'),
('324cd202-c348-4456-b024-6940f1f5dc50','觀山燈獻徐尚書 二','段成式','唐','唐诗','tang','','[]','湧出多寶塔，往來飛錫僧。',48,'全唐诗/poet.tang.32000.json','["湧出多寶塔，往來飛錫僧。", "分明三五月，傳照百千燈。", "馴狖移高柱，慶雲遮半層。", "夜深寒焰白，猶自綴金繩。"]'),
('f9916f6e-0186-419c-9021-4ac53631f1fb','觀山燈獻徐尚書 三','段成式','唐','唐诗','tang','','[]','磊落風初定，輕明雲乍妨。',48,'全唐诗/poet.tang.32000.json','["磊落風初定，輕明雲乍妨。", "疎中搖月彩，繁處雜星芒。", "火樹枝柯密，燭龍鱗甲張。", "窮愁讀書者，應得假餘光。"]'),
('8eed3916-7d7a-42b6-817f-0c7f1dd360a6','和徐商賀盧員外賜緋','段成式','唐','唐诗','tang','','[]','雲雨軒懸鶯語新，一篇佳句占陽春。',64,'全唐诗/poet.tang.32000.json','["雲雨軒懸鶯語新，一篇佳句占陽春。", "銀黃年少偏欺酒，金紫風流不讓人。", "連璧座中斜日滿，貫珠歌裏落花頻。", "莫辭倒載吟歸去，看欲東山又吐茵。"]'),
('94171fc7-7ada-4034-85ec-2890c7e28be1','河出榮光','段成式','唐','唐诗','tang','','[]','符命自陶唐，吾君應會昌。',96,'全唐诗/poet.tang.32000.json','["符命自陶唐，吾君應會昌。", "千年清德水，九折滿榮花。", "極岸浮佳氣，微波照夕陽。", "澄輝明貝闕，散彩入龍堂。", "近帶關雲紫，遙連日道黃。", "馮夷矜海若，漢武貴宣房。", "漸沒孤槎影，仍呈一葦航。", "撫躬悲未濟，作頌喜時康。"]'),
('d2e631ad-5333-434d-b1d5-d252fd9b8393','哭李羣玉','段成式','唐','唐诗','tang','','[]','曾話黃陵事，今爲白日摧。',24,'全唐诗/poet.tang.32000.json','["曾話黃陵事，今爲白日摧。", "老無兒女累，誰哭到泉臺。"]'),
('8a112dc1-add5-4247-80d2-72e3528d17c4','寄溫飛卿牋紙','段成式','唐','唐诗','tang','','[]','三十六鱗充使時，數番猶得裹相思。',32,'全唐诗/poet.tang.32000.json','["三十六鱗充使時，數番猶得裹相思。", "待將袍襖重抄了，盡寫襄陽播掿詞。"]'),
