('d2c9f40a-d762-4408-bf15-9740be986004','戲高侍御七首 四','段成式','唐','唐诗','tang','','[]','自等腰身尺六疆，兩重危鬢盡釵長。',32,'全唐诗/poet.tang.32000.json','["自等腰身尺六疆，兩重危鬢盡釵長。", "欲熏羅薦嫌龍腦，須爲尋求石葉香。"]'),
('c6c766cd-983a-4838-961b-e8a9df052f68','戲高侍御七首 五','段成式','唐','唐诗','tang','','[]','別起青樓作幾層，斜陽幔卷鹿盧繩。',32,'全唐诗/poet.tang.32000.json','["別起青樓作幾層，斜陽幔卷鹿盧繩。", "厭裁魚子深紅纈，泥覓蜻蜓淺碧綾。"]'),
('785ab22b-9918-4e6f-8e9b-765d349a3893','戲高侍御七首 六','段成式','唐','唐诗','tang','','[]','詐嫌嚼貝磨衣鈍，私帶男錢壓鬢低。',32,'全唐诗/poet.tang.32000.json','["詐嫌嚼貝磨衣鈍，私帶男錢壓鬢低。", "不獨邯鄲新嫁女，四枝鬟上插通犀。"]'),
('dc7cc5a1-b2b6-4b0c-89bf-03aa69997924','戲高侍御七首 七','段成式','唐','唐诗','tang','','[]','可羨羅敷自有失，愁中漫捋白髭鬚。',32,'全唐诗/poet.tang.32000.json','["可羨羅敷自有失，愁中漫捋白髭鬚。", "豹錢驄子能擎舉，兼著連乾許換無。"]'),
('f1f0510b-fe10-4f67-8650-dcba336859b5','送僧二首 一','段成式','唐','唐诗','tang','','[]','形神不滅論初成，愛馬乘閑入帝京。',32,'全唐诗/poet.tang.32000.json','["形神不滅論初成，愛馬乘閑入帝京。", "四十三年虛過了，方知僧裏有唐生。"]'),
('59558c6f-0387-4b99-bf67-a8a4b3d8b7d0','送僧二首 二','段成式','唐','唐诗','tang','','[]','想到頭陀最上方，桂陰猶認惠宗房。',32,'全唐诗/poet.tang.32000.json','["想到頭陀最上方，桂陰猶認惠宗房。", "因行戀燒歸來晚，窗下猶殘一字香。"]'),
('344de048-edd9-4c3b-8aef-698575b0eb52','猨','段成式','唐','唐诗','tang','','[]','却憶書齋值晚晴，挽枝閑嘯激蟬清。',32,'全唐诗/poet.tang.32000.json','["却憶書齋值晚晴，挽枝閑嘯激蟬清。", "影沈巴峽夜巖色，蹤絕石塘寒瀨聲。"]'),
('661ac598-01ca-49f5-a3b3-f64b4b01e545','送穆郎中赴闕','段成式','唐','唐诗','tang','','[]','應念愁中恨索居，鸝歌聲裏且踟蹰。',32,'全唐诗/poet.tang.32000.json','["應念愁中恨索居，鸝歌聲裏且踟蹰。", "若逢金馬門前客，爲說虞卿久著書。"]'),
('40858229-9008-4672-bf96-25fffd5a8059','題商山廟','段成式','唐','唐诗','tang','','[]','偶出雲泉謁禮闈，篇章曾沐漢皇知。',32,'全唐诗/poet.tang.32000.json','["偶出雲泉謁禮闈，篇章曾沐漢皇知。", "無謀靜國東歸去，羞過商山四老祠。"]'),
('b8c901ac-db86-4ad5-a544-84adc0d82772','折楊柳七首 一','段成式','唐','唐诗','tang','','[]','枝枝交影鎖長門，嫩色曾沾雨露恩。',32,'全唐诗/poet.tang.32000.json','["枝枝交影鎖長門，嫩色曾沾雨露恩。", "鳳輦不來春欲盡，空留鶯語到黃昏。"]'),
('a3c6ee3e-05db-4b36-960e-4ec6f98f0179','折楊柳七首 二','段成式','唐','唐诗','tang','','[]','水殿年年占早芳，柔條偏惹御爐香。',32,'全唐诗/poet.tang.32000.json','["水殿年年占早芳，柔條偏惹御爐香。", "而今萬乘多巡狩，輦路無陰綠草長。"]'),
('547b5b7f-6ef0-42f8-8567-ae9b959c0686','折楊柳七首 三','段成式','唐','唐诗','tang','','[]','玉樓煙薄不勝芳，金屋寒輕翠帶長。',32,'全唐诗/poet.tang.32000.json','["玉樓煙薄不勝芳，金屋寒輕翠帶長。", "公子驊騮往何處，綠陰堪繫紫遊韁。"]'),
('4e0357e3-ef40-46ff-97dd-1b281fd1b7d5','折楊柳七首 四','段成式','唐','唐诗','tang','','[]','嫩葉初齊不耐寒，風和時拂玉欄干。',32,'全唐诗/poet.tang.32000.json','["嫩葉初齊不耐寒，風和時拂玉欄干。", "君王去日曾攀折，泣雨傷春翠黛殘。"]'),
('92e44639-ccf9-45ef-8cb9-3b275fda625f','折楊柳七首 五','段成式','唐','唐诗','tang','','[]','微黃纔綻未成陰，繡戶珠簾相映深。',32,'全唐诗/poet.tang.32000.json','["微黃纔綻未成陰，繡戶珠簾相映深。", "長恨早梅無賴極，先將春色出前林。"]'),
('87b51d41-c5ce-462d-8d58-2af2c68cfb7c','折楊柳七首 六','段成式','唐','唐诗','tang','','[]','隋家堤上已成塵，漢將營邊不復春。',32,'全唐诗/poet.tang.32000.json','["隋家堤上已成塵，漢將營邊不復春。", "只向江南幷塞北，酒旗相伴惹行人。"]'),
('e0e7744c-d7c9-44bb-9887-812a44dc9a5b','折楊柳七首 七','段成式','唐','唐诗','tang','','[]','陌上河邊千萬枝，怕寒愁雨盡低垂。',32,'全唐诗/poet.tang.32000.json','["陌上河邊千萬枝，怕寒愁雨盡低垂。", "黃金穟短人多折，已恨東風不展眉。"]'),
('bb953f9d-e974-4b2a-b2d2-e577e58c5914','哭李羣玉','段成式','唐','唐诗','tang','','[]','酒裏詩中三十年，縱橫唐突世喧喧。',32,'全唐诗/poet.tang.32000.json','["酒裏詩中三十年，縱橫唐突世喧喧。", "明時不作禰衡死，傲盡公卿歸九泉。"]'),
('a8b11e18-8072-4388-adca-8223bfe8efd1','漢宮詞二首 一','段成式','唐','唐诗','tang','','[]','歌舞初承恩寵時，六宮學妾畫蛾眉。',32,'全唐诗/poet.tang.32000.json','["歌舞初承恩寵時，六宮學妾畫蛾眉。", "君王厭世妾頭白，聞唱歌聲却淚垂。"]'),
('07dde93a-e961-47d2-9b95-851ff061836d','漢宮詞二首 二','段成式','唐','唐诗','tang','','[]','二八能歌得進名，人言選入便光榮。',32,'全唐诗/poet.tang.32000.json','["二八能歌得進名，人言選入便光榮。", "豈知妃后多嬌妬，不許君前唱一聲。"]'),
('f27ff619-51ec-4698-93da-6b7751d8eaf2','醉中吟','段成式','唐','唐诗','tang','','[]','只愛糟牀滴滴聲，長愁聲絕又醒醒。',32,'全唐诗/poet.tang.32000.json','["只愛糟牀滴滴聲，長愁聲絕又醒醒。", "人間榮辱不常定，唯有南山依舊青。"]'),
('e061e66b-71f5-484e-b85b-a80285f86faf','桃源僧舍看花','段成式','唐','唐诗','tang','','[]','前年帝里探春時，寺寺名花我盡知。',32,'全唐诗/poet.tang.32000.json','["前年帝里探春時，寺寺名花我盡知。", "今日長安已灰燼，忍能南國對芳枝。"]'),
('77e3d5ee-5291-49b6-87b8-e34259d02eaf','和周繇見嘲','段成式','唐','唐诗','tang','','[]','才甘魚目並，藝怯馬蹄間。',72,'全唐诗/poet.tang.32000.json','["才甘魚目並，藝怯馬蹄間。", "王謝初飛蓋，姬姜盡下山。", "縛雞方角逐，射雉豈開顏。", "亂翠移林色，狂紅照座殷。", "防梭齒雖在，乞帽鬢慙斑。", "儻恕相如瘦，應容累騎還。"]'),
('c845b275-f883-4f4c-b91f-a2592325c268','和張希復詠宣律和尚袈裟','段成式','唐','唐诗','tang','','[]','南山披時寒夜中，一角不動毗嵐風。',32,'全唐诗/poet.tang.32000.json','["南山披時寒夜中，一角不動毗嵐風。", "何人見此生慙媿，斷續猶應護得龍。"]'),
('fd8d1f57-5922-4c88-8d7b-859f871d39c7','句','段成式','唐','唐诗','tang','','[]','高談敬風鑒，古貌怯冰稜。',136,'全唐诗/poet.tang.32000.json','["高談敬風鑒，古貌怯冰稜。", "虱暴妨歸夢，蟲喧徹曙更。", "夢裏思甘露，言中惜惠燈。", "新破毗曇義，相期卜夜論。", "隨樵劫猨藏，隈石覷熊緣。", "[捽]胡雲彩落，疻面月痕消。", "擲履仙鳧起，撦衣蝴蝶飄。", "羞中含薄怒，顰裏帶餘嬌。", "醒後猶攘臂，歸時更折腰。", "狂夫自纓絕，眉勢倩人描。", "不願石郎戴笠，難甘玉女披衣。"]'),
('bc0d549b-88a1-41eb-b24a-5e93327ceb9d','皎皎詞','劉駕','唐','唐诗','tang','','[]','皎皎復皎皎，逢時即爲好。',48,'全唐诗/poet.tang.32000.json','["皎皎復皎皎，逢時即爲好。", "高秋亦有花，不及當春草。", "班姬入後宮，飛燕舞東風。", "青娥中夜起，長歎月明裏。"]'),
('0e05b13b-fff6-47d7-ad13-1c95995b019c','長安旅舍紓情投先達','劉駕','唐','唐诗','tang','','[]','岐路不在地，馬蹄徒苦辛。',96,'全唐诗/poet.tang.32000.json','["岐路不在地，馬蹄徒苦辛。", "上國聞姓名，不如山中人。", "大宅滿六街，此身入誰門。", "愁心日散亂，有似空中塵。", "白露下長安，百蟲鳴草根。", "方當秋賦日，却憶歸山村。", "靜女頭欲白，良媒況我鄰。", "無令苦長歎，長歎銷人魂。"]'),
('a94e5511-ebc4-4777-8f91-e5026e6154bf','送友下第遊鴈門','劉駕','唐','唐诗','tang','','[]','相別灞水湄，夾水柳依依。',120,'全唐诗/poet.tang.32000.json','["相別灞水湄，夾水柳依依。", "我願醉如死，不見君去時。", "所詣星斗北，直行到猶遲。", "況復挈空囊，求人悲路岐。", "北門記室賢，愛我學古詩。", "待君如待我，此事固不疑。", "鴈門春色外，四月鴈未歸。", "主人拂金臺，延客夜開扉。", "舒君鬱鬱懷，飲彼白玉巵。", "若不化女子，功名豈無期。"]'),
('156ffb02-1b3a-4184-bda4-63b082c75a2f','讀史','劉駕','唐','唐诗','tang','','[]','平地見天涯，登高天更遠。',60,'全唐诗/poet.tang.32000.json','["平地見天涯，登高天更遠。", "功名及所望，岐路又滿眼。", "萬金買園林，千金修池館。", "他人厭遊覽，身獨戀軒冕。", "唯有漢二疎，應覺還家晚。"]'),
('9bed8b8f-b8b1-4613-b6b3-de5db26baf51','反賈客樂','劉駕','唐','唐诗','tang','','[]','無言賈客樂，賈客多無墓。',36,'全唐诗/poet.tang.32000.json','["無言賈客樂，賈客多無墓。", "行舟觸風浪，盡入魚腹去。", "農夫更苦辛，所以羨爾身。"]'),
('954e88e0-4739-4b63-9e78-f03e3642d795','送李垣先輩歸嵩少舊居','劉駕','唐','唐诗','tang','','[]','高秋灞滻路，游子多慘戚。',72,'全唐诗/poet.tang.32000.json','["高秋灞滻路，游子多慘戚。", "君於此地行，獨以尋春色。", "文章滿人口，高第非苟得。", "要路在長安，歸山却爲客。", "□□□□□，狂歌罷歎息。", "我豈無故山，千里同外國。"]'),
('e077249a-264b-4f01-97dc-c37c03b1d204','苦寒吟','劉駕','唐','唐诗','tang','','["\u51ac\u5929", "\u751f\u6d3b", "\u51c4\u51c9"]','百泉凍皆咽，我吟寒更切。',60,'全唐诗/poet.tang.32000.json','["百泉凍皆咽，我吟寒更切。", "半夜倚喬松，不覺滿衣雪。", "竹竿有甘苦，我愛抱苦節。", "鳥聲有悲歡，我愛口流血。", "潘生若解吟，更早生白髮。"]'),
('a35d2be2-cf3a-4fa7-91a6-0760c20e17b8','上巳日','劉駕','唐','唐诗','tang','','[]','上巳曲江濱，喧於市朝路。',72,'全唐诗/poet.tang.32000.json','["上巳曲江濱，喧於市朝路。", "相尋不見者，此地皆相遇。", "日光去此遠，翠幕張如霧。", "何事歡娛中，易覺春城暮。", "物情重此節，不是愛芳樹。", "明日花更多，何人肯回顧。"]'),
('e51cd23e-b029-4192-903d-4fa04135cd85','春臺','劉駕','唐','唐诗','tang','','[]','臺上樹陰合，臺前流水多。',48,'全唐诗/poet.tang.32000.json','["臺上樹陰合，臺前流水多。", "青春不出門，坐見野田花。", "誰能學公子，走馬逐香車。", "六街塵滿衣，鼓絕方還家。"]'),
('ba168742-b63d-4440-9f72-cf9dcbb809e6','釣臺懷古','劉駕','唐','唐诗','tang','','[]','澄流可濯纓，嚴子但垂綸。',84,'全唐诗/poet.tang.32000.json','["澄流可濯纓，嚴子但垂綸。", "孤坐九層石，遠笑清渭濱。", "潛龍飛上天，四海豈無雲。", "清氣不零雨，安使洗塵氛。", "我來吟高風，髣髴見斯人。", "江月尚皎皎，江石亦磷磷。", "如何臺下路，明日又迷津。"]'),
('fa3dec00-8c3a-4be8-896e-a0c1124e2dcc','勵志','劉駕','唐','唐诗','tang','','[]','白髮豈有情，貴賤同日生。',72,'全唐诗/poet.tang.32000.json','["白髮豈有情，貴賤同日生。", "二輪不暫駐，似趂長安程。", "前堂吹參差，不作緱山聲。", "後園植木槿，月照無餘英。", "及時立功德，身後猶光明。", "仲尼亦爲土，魯人焉敢耕。"]'),
('51f0299f-1343-44c2-8f6f-3d519c61d185','桑婦','劉駕','唐','唐诗','tang','','[]','牆下桑葉盡，春蠶半未老。',72,'全唐诗/poet.tang.32000.json','["牆下桑葉盡，春蠶半未老。", "城南路迢迢，今日起更早。", "四鄰無去伴，醉臥青樓曉。", "妾顏不如誰，所貴守婦道。", "一春常在樹，自覺身如鳥。", "歸來見小姑，新妝弄百草。"]'),
('1c3887e3-3028-4fbb-a233-2ff210636962','上馬歎','劉駕','唐','唐诗','tang','','[]','羸馬行遲遲，頑童去我遠。',84,'全唐诗/poet.tang.32000.json','["羸馬行遲遲，頑童去我遠。", "時時一回顧，不覺白日晚。", "路傍豪家宅，樓上紅妝滿。", "十月庭花開，花前吹玉管。", "君當未貴日，豈不常屯蹇。", "如何見布衣，忽若塵入眼。", "布衣豈常賤，世事車輪轉。"]'),
('0089d274-23b7-4a71-a726-ae49f69b8f9f','唐樂府十首 送征夫','劉駕','唐','唐诗','tang','','[]','昔送征夫苦，今送征夫樂。',36,'全唐诗/poet.tang.32000.json','["昔送征夫苦，今送征夫樂。", "寒衣縱攜去，應向歸時着。", "天子待功成，別造凌煙閣。"]'),
('7b63a225-2308-43dd-93ae-f056d80f2ff5','唐樂府十首 輪者謳','劉駕','唐','唐诗','tang','','[]','輓粟上高山，高山若平地。',60,'全唐诗/poet.tang.32000.json','["輓粟上高山，高山若平地。", "力盡心不怨，同我家私事。", "去者不遑寧，歸者唱歌行。", "相逢古城下，立語天未明。", "一身遠出塞，十口無稅征。"]'),
('6ccc1a01-4f06-4f88-adb1-0371a15a34a8','唐樂府十首 弔西人','劉駕','唐','唐诗','tang','','[]','河湟父老地，盡知歸明主。',36,'全唐诗/poet.tang.32000.json','["河湟父老地，盡知歸明主。", "將軍入空城，城下弔黃土。", "所願邊人耕，歲歲生禾黍。"]'),
('be05b79f-3303-406d-a678-a9763ae812b5','唐樂府十首 邊軍過','劉駕','唐','唐诗','tang','','[]','城前兵馬過，城裏人高臥。',72,'全唐诗/poet.tang.32000.json','["城前兵馬過，城裏人高臥。", "官家自供給，畏我田產破。", "健兒食肥肉，戰馬食新穀。", "食飽物有餘，所恨無兩腹。", "草青見軍過，草白見軍回。", "軍回人更多，盡繫西戎來。"]'),
('16447587-81e6-483c-93a1-35b82e434ffb','唐樂府十首 望歸馬','劉駕','唐','唐诗','tang','','[]','東人望歸馬，馬歸蓮峰下。',24,'全唐诗/poet.tang.32000.json','["東人望歸馬，馬歸蓮峰下。", "蓮峰與地平，亦不更徵兵。"]'),
('ed953411-b9ca-4f27-805b-cbd5e2f7e66a','唐樂府十首 祝河水','劉駕','唐','唐诗','tang','','[]','河水清瀰瀰，照見遠樹枝。',36,'全唐诗/poet.tang.32000.json','["河水清瀰瀰，照見遠樹枝。", "征人不飲馬，再拜祝馮夷。", "從今億萬歲，不見河濁時。"]'),
('dc3cca75-f9f7-432f-bd1a-0e2ac34e56ff','唐樂府十首 田西邊','劉駕','唐','唐诗','tang','','[]','刀劒作鋤犂，耕田古城下。',24,'全唐诗/poet.tang.32000.json','["刀劒作鋤犂，耕田古城下。", "高秋禾黍多，無地放羊馬。"]'),
('364236ad-83bb-4964-b861-ceaa54971cec','唐樂府十首 崑山','劉駕','唐','唐诗','tang','','[]','昔時玉爲寶，崑山過不得。',36,'全唐诗/poet.tang.32000.json','["昔時玉爲寶，崑山過不得。", "今時玉爲塵，崑山入中國。", "白玉尚如塵，誰肯愛金銀。"]'),
('b2ee4014-fbfd-4fff-a2ad-98cf6d1321fb','唐樂府十首 樂邊人','劉駕','唐','唐诗','tang','','[]','在鄉身亦勞，在邊腹亦飽。',24,'全唐诗/poet.tang.32000.json','["在鄉身亦勞，在邊腹亦飽。", "父兄若一處，任向邊頭老。"]'),
('bc248344-300a-490d-b356-9dffbb8ed849','唐樂府十首 獻賀觴','劉駕','唐','唐诗','tang','','[]','莫但取河湟，河湟非邊疆。',36,'全唐诗/poet.tang.32000.json','["莫但取河湟，河湟非邊疆。", "願今日入處，亦似天中央。", "天子壽萬歲，再拜獻此觴。"]'),
('0d01b612-00ec-4686-b8a2-7efa3794f537','且可憐行','劉駕','唐','唐诗','tang','','[]','園中花自早，不信外無花。',84,'全唐诗/poet.tang.32000.json','["園中花自早，不信外無花。", "良人未朝去，先出登香車。", "□□五□輪，滿城聞嘔啞。", "侍兒衣各別，頭上金雀多。", "祗是一家人，路人疑千家。", "過後香滿陌，直到春日斜。", "今朝且可憐，莫問久如何。"]'),
('ed2dd093-0504-4491-acb5-501395364dc6','築臺詞','劉駕','唐','唐诗','tang','','[]','前杵與後杵，築城聲不住。',24,'全唐诗/poet.tang.32000.json','["前杵與後杵，築城聲不住。", "我願築更高，得見秦皇墓。"]'),
('00416097-77a2-452f-ba7e-f91aaea0dc48','鄰女','劉駕','唐','唐诗','tang','','[]','君嫌鄰女醜，取婦他鄉縣。',36,'全唐诗/poet.tang.32000.json','["君嫌鄰女醜，取婦他鄉縣。", "料嫁與君人，亦爲鄰所賤。", "菖蒲花可貴，只爲人難見。"]'),
('8312c504-7643-4308-b0ce-c19f5d58acd9','山中夜坐','劉駕','唐','唐诗','tang','','[]','半夜山雨過，起來滿山月。',48,'全唐诗/poet.tang.32000.json','["半夜山雨過，起來滿山月。", "落盡醉處花，荒溝水決決。", "愴然惜春去，似與故人別。", "誰遣我多情，壯年無鬢髮。"]'),
('5ded5d1c-1c65-40fd-beec-40d42aa245d8','秦娥','劉駕','唐','唐诗','tang','','[]','秦娥十四五，面白於指爪。',24,'全唐诗/poet.tang.32000.json','["秦娥十四五，面白於指爪。", "羞人夜採桑，驚起戴勝鳥。"]'),
('abef521e-2091-4bca-a199-52e0f82e7d98','牧童','劉駕','唐','唐诗','tang','','[]','牧童見客拜，山果懷中落。',24,'全唐诗/poet.tang.32000.json','["牧童見客拜，山果懷中落。", "晝日驅牛歸，前溪風雨惡。"]'),
('e1fdbe86-813d-4601-9df0-bd7e13d755de','古出塞','劉駕','唐','唐诗','tang','','[]','胡風不開花，四氣多作雪。',72,'全唐诗/poet.tang.32000.json','["胡風不開花，四氣多作雪。", "北人尚凍死，況我本南越。", "古來犬羊地，巡狩無遺轍。", "九土耕不盡，武皇猶征伐。", "中天有高閣，圖畫何時歇？", "坐恐塞上山，低於沙中骨。"]'),
('076e612c-0bcc-49d5-9b98-d5a0e26eb291','寄遠','劉駕','唐','唐诗','tang','','[]','雪花豈結子，徒滿連理枝。',72,'全唐诗/poet.tang.32000.json','["雪花豈結子，徒滿連理枝。", "嫁作征人妻，不得長相隨。", "去年君點行，賤妾是新姬。", "別早見未熟，入夢無定姿。", "悄悄空閨中，蛩聲遶羅幃。", "得書喜猶甚，況復見君時。"]'),
('27b64d41-4d4f-4be8-8f3d-8b84398e9536','下第後屏居長安書懷寄太原從事','劉駕','唐','唐诗','tang','','[]','刖足豈更長，良工隔千里。',96,'全唐诗/poet.tang.32000.json','["刖足豈更長，良工隔千里。", "故山彭蠡上，歸夢向汾水。", "低摧神氣盡，僮僕心亦恥。", "未達誰不然，達者心思此。", "行年忽已壯，去老年更幾。", "功名生不彰，身歿豈爲鬼。", "纔看芳草歇，即歎涼風起。", "匹馬未來期，嘶聲尚在耳。"]'),
('843b886c-6f77-414f-8525-656bb69edb4d','早行','劉駕','唐','唐诗','tang','','[]','馬上續殘夢，馬嘶時復驚。',48,'全唐诗/poet.tang.32000.json','["馬上續殘夢，馬嘶時復驚。", "心孤多所虞，僮僕近我行。", "棲禽未分散，落月照古城。", "莫羨居者閑，冢邊人已耕。"]'),
('d75bf967-9c3d-49c2-a517-8635e8dabf6c','青門路','劉駕','唐','唐诗','tang','','[]','青門有歸路，坦坦高槐下。',72,'全唐诗/poet.tang.32000.json','["青門有歸路，坦坦高槐下。", "貧賤自恥歸，此地誰留我。", "門開送客去，落日嬾回馬。", "旅食帝城中，不如遠遊者。", "舟成於陸地，風水終相假。", "吾道諒如斯，立身無苟且。"]'),
('28af0461-760c-4a64-a79d-7f386cac8285','效古','劉駕','唐','唐诗','tang','','[]','融融芳景和，杳杳春日斜。',60,'全唐诗/poet.tang.32000.json','["融融芳景和，杳杳春日斜。", "嬌嬈不自持，清唱嚬雙蛾。", "終曲翻成泣，新人下香車。", "新人且莫喜，故人曾如此。", "燕趙猶生女，郎豈有終始。"]'),
('00b45f00-ba00-4cd8-99cc-ffe31d9109e4','戰城南','劉駕','唐','唐诗','tang','','[]','城南征戰多，城北無飢鴉。',48,'全唐诗/poet.tang.32000.json','["城南征戰多，城北無飢鴉。", "白骨馬蹄下，誰言皆有家。", "城前水聲苦，倏忽流萬古。", "莫爭城外城，城裏終閑土。"]'),
('cfdd5cad-a727-4f8c-a46c-fe3881ce075a','曲江春霽','劉駕','唐','唐诗','tang','','[]','宿雨洗秦樹，舊花如新開。',60,'全唐诗/poet.tang.32000.json','["宿雨洗秦樹，舊花如新開。", "池邊草未乾，日照人馬來。", "馬蹄踏流水，漸漸成塵埃。", "鴛鴦不敢下，飛繞岸東西。", "此地喧仍舊，歸人亦滿街。"]'),
('2bab027f-bda8-4df8-a30b-b7ff8fa33e96','贈先達','劉駕','唐','唐诗','tang','','[]','終南蒼翠好，未必如故山。',96,'全唐诗/poet.tang.32000.json','["終南蒼翠好，未必如故山。", "心期在榮名，三載居長安。", "昔蒙大雅匠，勉我工五言。", "業成時不重，辛苦只自憐。", "皎皎機上絲，盡作秦箏弦。", "貧女皆罷織，富人豈不寒。", "驚風起長波，浩浩何時還？", "待君當要路，一指王化源。"]'),
('25778403-ff66-475e-b638-951267d6bb28','有感','劉駕','唐','唐诗','tang','','[]','弓劒不自行，難引河湟思。',48,'全唐诗/poet.tang.32000.json','["弓劒不自行，難引河湟思。", "將軍半夜飲，十里聞歌飲。", "高門幾世宅，舞袖仍新賜。", "誰遣一書來，燈前問邊事。"]'),
('61b4737d-01db-4c85-a19c-0c6ed5169031','姑蘇臺','劉駕','唐','唐诗','tang','','[]','勾踐飲膽日，吳酒正滿杯。',84,'全唐诗/poet.tang.32000.json','["勾踐飲膽日，吳酒正滿杯。", "笙歌入海雲，聲自姑蘇來。", "西施舞初罷，侍兒整金釵。", "衆女不敢妒，自比泉下泥。", "越鼓聲騰騰，吳天隔塵埃。", "難將甬東地，更學會稽棲。", "霸跡一朝盡，草中棠梨開。"]'),
('521c2831-e1a0-4d81-93d4-1e878caf6a3d','豪家','劉駕','唐','唐诗','tang','','[]','九陌槐葉盡，青春在豪家。',48,'全唐诗/poet.tang.32000.json','["九陌槐葉盡，青春在豪家。", "嬌鶯不出城，長宿庭上花。", "高樓登夜半，已見南山多。", "恩深勢自然，不是愛驕奢。"]'),
('8bd746d9-90a9-4ab5-9947-494d7d9ea21b','山中有招','劉駕','唐','唐诗','tang','','[]','朗朗山月出，塵中事由生。',108,'全唐诗/poet.tang.32000.json','["朗朗山月出，塵中事由生。", "人心雖不閑，九陌夜無行。", "學古以求聞，有如石上耕。", "齊姜早作婦，豈識閨中情。", "何如此幽居，地僻人不爭。", "嘉樹自昔有，茅屋因我成。", "取薪不出門，采藥於前庭。", "春花雖無種，枕席芙蓉馨。", "君來食葵藿，天爵豈不榮。"]'),
('deccb9c2-e5a9-4905-91aa-698ed6fe419d','空城雀','劉駕','唐','唐诗','tang','','[]','飢啄空城上，莫近太倉粟。',48,'全唐诗/poet.tang.32000.json','["飢啄空城上，莫近太倉粟。", "一粒未充腸，却入公子腹。", "且弔城上骨，幾曾害爾族。", "不聞莊辛語，今日寒蕪綠。"]'),
('bad7b285-b722-49e7-9b21-0f3cd4f1375f','馮叟居','劉駕','唐','唐诗','tang','','[]','天作馮叟居，山僧尚嫌僻。',96,'全唐诗/poet.tang.32000.json','["天作馮叟居，山僧尚嫌僻。", "開門因兩樹，結宇倚翠壁。", "溪南有微徑，時遇採芝客。", "往往白雲生，對面千里隔。", "機忘若僮僕，常與猨鳥劇。", "曬藥上小峰，庭深無日色。", "自忘歸鄉里，不見新舊戚。", "纍纍子孫墓，秋風吹古柏。"]'),
('36790537-76ac-4af5-9395-2886e67ece02','醒後','劉駕','唐','唐诗','tang','','[]','醉臥芳草間，酒醒日落後。',36,'全唐诗/poet.tang.32000.json','["醉臥芳草間，酒醒日落後。", "壺觴半傾覆，客去應已久。", "不記折花時，何得花在手。"]'),
('305a88a0-311c-42b3-b51b-7617699d54a9','棄婦','劉駕','唐','唐诗','tang','','[]','回車在門前，欲上心更悲。',72,'全唐诗/poet.tang.32000.json','["回車在門前，欲上心更悲。", "路傍見花發，似妾初嫁時。", "養蠶已成繭，織素猶在機。", "新人應笑此，何如畫蛾眉。", "昨日惜紅顏，今日畏老遲。", "良媒去不遠，此恨今告誰。"]'),
('ad765a79-3c31-49ca-9e63-6bebc466ecd3','送李殷遊邊','劉駕','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','十年夢相識，一覯俄遠別。',120,'全唐诗/poet.tang.32000.json','["十年夢相識，一覯俄遠別。", "征駕在我傍，草草意難說。", "君居洞庭日，詩句滿魏闕。", "如何萬里來，青桂看人折。", "行裝不及備，西去偶然訣。", "孟夏出都門，紅塵客衣熱。", "荒城見羊馬，野館具薇蕨。", "邊境漸無虞，旅宿常待月。", "西園置酒地，日夕簪裾列。", "壯志安可留，槐花樽前發。"]'),
('3988b32b-df07-4052-b346-ea6d92828eda','江村','劉駕','唐','唐诗','tang','','[]','江水灌稻田，饑年稻亦熟。',72,'全唐诗/poet.tang.32000.json','["江水灌稻田，饑年稻亦熟。", "舟中愛桑麻，日午因成宿。", "相承幾十代，居止連茅屋。", "四鄰不相離，安肯去骨肉。", "書生說太苦，客路常在目。", "縱使富貴還，交親幾墳綠。"]'),
('5baaa588-8ec1-4b18-8dbd-efa7f18a4d88','出門','劉駕','唐','唐诗','tang','','[]','出門羨他人，奔走如得塗。',96,'全唐诗/poet.tang.32000.json','["出門羨他人，奔走如得塗。", "翻思他人意，與我或不殊。", "以茲聊自安，默默行九衢。", "生計逐羸馬，每出似移居。", "客從我鄉來，但得鄰里書。", "田園幾換主，夢歸猶荷鋤。", "進猶希萬一，退復何所如。", "況今闢公道，安得不躊躇。"]'),
('c392f188-f3c9-4464-b0c9-d3415f222f45','別道者','劉駕','唐','唐诗','tang','','[]','自君入城市，北邙無新墳。',48,'全唐诗/poet.tang.32000.json','["自君入城市，北邙無新墳。", "始信壺中藥，不落白楊根。", "如何忽告歸，蕣華還笑人。", "玉笙無遺音，悵望緱嶺雲。"]'),
('bb4c785a-b7c0-4e1a-9cdc-ca738ba95795','蘭昌宮','劉駕','唐','唐诗','tang','','[]','宮蘭非瑤草，安得春長在。',48,'全唐诗/poet.tang.32000.json','["宮蘭非瑤草，安得春長在。", "迴首春又歸，翠華不能待。", "悲風生輦路，山川寂已晦。", "邊恨在行人，行人無盡歲。"]'),
('ed79dc3e-b396-4b0c-8ce7-aaf690058093','送友人擢第東歸','劉駕','唐','唐诗','tang','','[]','同家楚天南，相識秦雲西。',96,'全唐诗/poet.tang.32000.json','["同家楚天南，相識秦雲西。", "古來懸弧義，豈顧子與妻。", "攜手踐名場，正遇公道開。", "君榮我雖黜，感恩同所懷。", "有馬不復羸，有奴不復飢。", "灞岸秋草綠，却是還家時。", "青門一瓢空，分手去遲遲。", "期君轍未平，我車繼東歸。"]'),
('00ddbd2f-b723-473a-9fce-8579256ee59a','久客','劉駕','唐','唐诗','tang','','[]','久客心易足，主人有餘力。',36,'全唐诗/poet.tang.32000.json','["久客心易足，主人有餘力。", "如何昨宵夢，到曉家山色。", "南音入誰耳，曲盡頭自白。"]'),
('32846028-5b49-405f-a951-2acd67709f3b','秋夕','劉駕','唐','唐诗','tang','','[]','促織燈下吟，燈光冷於水。',60,'全唐诗/poet.tang.32000.json','["促織燈下吟，燈光冷於水。", "鄉魂坐中去，倚壁身如死。", "求名爲骨肉，骨肉萬餘里。", "富貴在何時，離別今如此。", "出門長歎息，月白西風起。"]'),
('cfc36dd0-031e-46ed-bbe1-06645f7fcf58','效陶','劉駕','唐','唐诗','tang','','[]','兩曜無停馭，蓬壺應有墓。',96,'全唐诗/poet.tang.32000.json','["兩曜無停馭，蓬壺應有墓。", "何況北邙山，只近市朝路。", "大恢生死網，飛走無逃處。", "白髮忽已新，紅顏豈如故。", "我有杯中物，可以消萬慮。", "醉舞日婆娑，誰能記朝暮。", "如求神仙藥，階下亦種黍。", "但使長兀然，始見天地祖。"]'),
('b05c52b8-40ce-494b-b274-f807755a312f','長門怨','劉駕','唐','唐诗','tang','','[]','御泉長繞鳳皇[樓]，只是恩波別處流。',34,'全唐诗/poet.tang.32000.json','["御泉長繞鳳皇[樓]，只是恩波別處流。", "閑揲舞衣歸未得，夜來砧杵六宮秋。"]'),
('65f473e2-2545-4732-8a4a-56a784f93382','苦寒行','劉駕','唐','唐诗','tang','','[]','嚴寒動八荒，刺刺無休時。',60,'全唐诗/poet.tang.32000.json','["嚴寒動八荒，刺刺無休時。", "陽烏不自暖，雪壓扶桑枝。", "歲暮寒益壯，青春安得歸。", "朔鴈到南海，越禽何處飛。", "誰言貧士歎，不爲身無衣。"]'),
('d844560a-e0a4-4e09-8653-6de66366283d','琪樹下因吟六韻呈先達者','劉駕','唐','唐诗','tang','','[]','舉世愛嘉樹，此樹何人識。',72,'全唐诗/poet.tang.32000.json','["舉世愛嘉樹，此樹何人識。", "清秋遠山意，偶向亭際得。", "奇柯交若鬬，珍葉密如織。", "塵中尚青蔥，更想塵外色。", "所宜巢三鳥，影入瑤池碧。", "移根豈無時，一問紫煙客。"]'),
('b2a87e64-3c43-4b01-a56a-02241ec5526a','送人登第東歸','劉駕','唐','唐诗','tang','','[]','學古既到古，反求鑒者難。',156,'全唐诗/poet.tang.32000.json','["學古既到古，反求鑒者難。", "見詩未識君，疑生建安前。", "海畔豈無家，終難成故山。", "得失雖由命，世途多險艱。", "我皇追古風，文柄付大賢。", "此時如爲君，果在甲科間。", "晚達多早貴，舉世咸爲然。", "一夕顏却少，雖病心且安。", "所居似清明，冷竈起新煙。", "高情懶行樂，花盛僕馬前。", "歸程不淹留，指期到田園。", "香醪四鄰熟，霜橘千株繁。", "肯憶長安夜，論詩風雪寒。"]'),
('58b20ce9-14eb-44a2-b124-1ec78cd4302a','賈客詞','劉駕','唐','唐诗','tang','','[]','賈客燈下起，猶言發已遲。',72,'全唐诗/poet.tang.32000.json','["賈客燈下起，猶言發已遲。", "高山有疾路，暗行終不疑。", "寇盜伏其路，猛獸來相追。", "金玉四散去，空囊委路岐。", "揚州有大宅，白骨無地歸。", "少婦當此日，對鏡弄花枝。"]'),
('0416de29-dfaf-4909-8c21-db7ff37416ee','塞下曲','劉駕','唐','唐诗','tang','','[]','勒兵遼水邊，風急卷旌旃。',48,'全唐诗/poet.tang.32000.json','["勒兵遼水邊，風急卷旌旃。", "絕塞陰無草，平沙去盡天。", "下營看斗建，傳號信狼煙。", "聖代書青史，當時破虜年。"]'),
('b8ec33b3-10ec-4424-b073-88380cf5223b','春夜二首 一','劉駕','唐','唐诗','tang','','[]','一別杜陵歸未期，祗憑魂夢接親知。',32,'全唐诗/poet.tang.32000.json','["一別杜陵歸未期，祗憑魂夢接親知。", "近來欲睡兼難睡，夜夜夜深聞子規。"]'),
('21ede444-7994-4793-ad18-26d961b2c0ee','春夜二首 二','劉駕','唐','唐诗','tang','','[]','幾歲干戈阻路岐，憶山心切與心違。',32,'全唐诗/poet.tang.32000.json','["幾歲干戈阻路岐，憶山心切與心違。", "時難何處披衷抱，日日日斜空醉歸。"]'),
('4a198d72-ace4-4025-9d6d-88b1d069f4d0','郪中感懷','劉駕','唐','唐诗','tang','','[]','頃年曾住此中來，今日重遊事可哀。',32,'全唐诗/poet.tang.32000.json','["頃年曾住此中來，今日重遊事可哀。", "憶得幾家歡宴處，家家家業盡成灰。"]'),
('c2ad3d6f-9735-4c14-ad89-1b5bfd8a12d1','曉登迎春閣','劉駕','唐','唐诗','tang','','[]','未櫛凭欄眺錦城，煙籠萬井二江明。',32,'全唐诗/poet.tang.32000.json','["未櫛凭欄眺錦城，煙籠萬井二江明。", "香風滿閣花滿樹，樹樹樹梢啼曉鶯。"]'),
('d8bb4188-232d-49fc-9cc2-c201d4e8733b','白髭','劉駕','唐','唐诗','tang','','[]','到處逢人求至藥，幾回染了又成絲。',32,'全唐诗/poet.tang.32000.json','["到處逢人求至藥，幾回染了又成絲。", "素絲易染髭難染，墨翟當年合泣髭。"]'),
('16397e7d-cf17-436c-92fa-a006f1fc0f67','送盧使君赴夔州','劉駕','唐','唐诗','tang','','[]','鐃管隨征斾，高秋上遠巴。',48,'全唐诗/poet.tang.32000.json','["鐃管隨征斾，高秋上遠巴。", "白波連霧雨，青壁斷蒹葭。", "凭几雙瞳靜，登樓萬井斜。", "政成知俗變，當應畫輪車。"]'),
('c024508d-e680-411f-9b92-4c67ae03d540','望月','劉駕','唐','唐诗','tang','','[]','清秋新霽與君同，江上高樓倚碧空。',32,'全唐诗/poet.tang.32000.json','["清秋新霽與君同，江上高樓倚碧空。", "酒盡露零賓客散，更更更漏月明中。"]'),
('800a029c-f786-4810-b92e-93d23bab524b','古意','劉駕','唐','唐诗','tang','','[]','蒲帆出浦去，但見浦邊樹。',48,'全唐诗/poet.tang.32000.json','["蒲帆出浦去，但見浦邊樹。", "不如馬行郎，馬跡猶在路。", "大舟不相載，買宅令委住。", "莫道留金多，本非愛郎富。"]'),
('d95da435-feba-473a-946a-60375ca8d581','長洲懷古','劉滄','唐','唐诗','tang','','[]','野燒原空盡荻灰，吳王此地有樓臺。',64,'全唐诗/poet.tang.32000.json','["野燒原空盡荻灰，吳王此地有樓臺。", "千年事往人何在，半夜月明潮自來。", "白鳥影從江樹沒，清猨聲入楚雲哀。", "停車日晚薦蘋藻，風靜寒塘花正開。"]'),
('edb91824-6e13-4d57-b427-807cd4dda923','經煬帝行宮','劉滄','唐','唐诗','tang','','[]','此地曾經翠輦過，浮雲流水竟如何。',64,'全唐诗/poet.tang.32000.json','["此地曾經翠輦過，浮雲流水竟如何。", "香銷南國美人盡，怨入東風芳草多。", "殘柳宮前空露葉，夕陽川上浩煙波。", "行人遙起廣陵思，古渡月明聞棹歌。"]'),
('16637f37-8453-4a11-8bcf-035d20c838b0','春日遊嘉陵江','劉滄','唐','唐诗','tang','','[]','獨泛扁舟映綠楊，嘉陵江水色蒼蒼。',64,'全唐诗/poet.tang.32000.json','["獨泛扁舟映綠楊，嘉陵江水色蒼蒼。", "行看芳草故鄉遠，坐對落花春日長。", "曲岸危檣移渡影，暮天栖鳥入山光。", "今來誰識東歸意，把酒閑吟思洛陽。"]'),
('663a6285-6551-46c9-ad13-df3f5669e092','秋日山齋書懷','劉滄','唐','唐诗','tang','','[]','啓戶清風枕簟幽，蟲絲吹落挂簾鉤。',64,'全唐诗/poet.tang.32000.json','["啓戶清風枕簟幽，蟲絲吹落挂簾鉤。", "蟬吟高樹雨初霽，人憶故鄉山正秋。", "浩渺蒹葭連夕照，蕭疎楊柳隔沙洲。", "空將方寸荷知己，身寄煙蘿恩未酬。"]'),
('17b1eba6-0e49-4d50-9eb0-9bcafe5da674','晚秋洛陽客舍','劉滄','唐','唐诗','tang','','[]','清洛平分兩岸沙，沙邊水色近人家。',64,'全唐诗/poet.tang.32000.json','["清洛平分兩岸沙，沙邊水色近人家。", "隋朝古陌銅駝柳，石氏荒原金谷花。", "庭葉霜濃悲遠客，宮城日晚度寒鵶。", "未成歸計關河阻，空望白雲鄉路賒。"]'),
('5ea69288-0580-4068-8749-7197124700bc','深愁喜友人至','劉滄','唐','唐诗','tang','','[]','不避驅羸道路長，青山同喜惜年光。',64,'全唐诗/poet.tang.32000.json','["不避驅羸道路長，青山同喜惜年光。", "燈前話舊堦草夜，月下醉吟谿樹霜。", "落葉已經寒燒盡，衡門猶對古城荒。", "此身未遂歸休計，一半生涯寄岳陽。"]'),
('f059d478-99e8-47de-b28d-8f0630a3b33a','秋日望西陽','劉滄','唐','唐诗','tang','','["\u9ec4\u6cb3"]','古木蒼苔墜幾層，行人一望旅情增。',64,'全唐诗/poet.tang.32000.json','["古木蒼苔墜幾層，行人一望旅情增。", "太行山下黃河水，銅雀臺西武帝陵。", "風入蒹葭秋色動，雨餘楊柳暮煙凝。", "野花似泣紅妝淚，寒露滿枝枝不勝。"]'),
('8a84b261-440a-4fae-905d-42f970090fde','鄴都懷古','劉滄','唐','唐诗','tang','','[]','昔時霸業何蕭索，古木唯多鳥雀聲。',64,'全唐诗/poet.tang.32000.json','["昔時霸業何蕭索，古木唯多鳥雀聲。", "芳草自生宮殿處，牧童誰識帝王城。", "殘春楊柳長川迥，落日蒹葭遠水平。", "一望青山便惆悵，西陵無主月空明。"]'),
('e17dca08-9b9a-42b4-ba1c-5e1378a6bf8b','題龍門僧房','劉滄','唐','唐诗','tang','','[]','靜室遙臨伊水東，寂寥誰與此身同。',64,'全唐诗/poet.tang.32000.json','["靜室遙臨伊水東，寂寥誰與此身同。", "禹門山色度寒磬，蕭寺竹聲來晚風。", "僧宿石龕殘雪在，鴈歸沙渚夕陽空。", "偶將心地問高士，坐指浮生一夢中。"]'),
('8f9d7a4f-c1f5-44d4-8ee1-7c03a35d1602','秋夕山齋即事','劉滄','唐','唐诗','tang','','[]','衡門無事閉蒼苔，籬下蕭疎野菊開。',64,'全唐诗/poet.tang.32000.json','["衡門無事閉蒼苔，籬下蕭疎野菊開。", "半夜秋風江色動，滿山寒葉雨聲來。", "鴈飛關塞霜初落，書寄鄉閭人未迴。", "獨坐高窗此時節，一彈瑤瑟自成哀。"]'),
('6b115bf0-783b-4795-bd92-323f987a26c4','江行書事','劉滄','唐','唐诗','tang','','[]','遠渚蒹葭覆綠苔，姑蘇南望思裴徊。',64,'全唐诗/poet.tang.32000.json','["遠渚蒹葭覆綠苔，姑蘇南望思裴徊。", "空江獨樹楚山背，暮雨一舟吳苑來。", "人度深秋風葉落，鳥飛殘照水煙開。", "寒潮欲上泛萍藻，寄薦三閭情自哀。"]'),
('9007b412-5f1b-4f41-9c4b-6b4fa8653447','過鑄鼎原','劉滄','唐','唐诗','tang','','[]','黃帝修真萬國朝，鼎成龍駕上丹霄。',64,'全唐诗/poet.tang.32000.json','["黃帝修真萬國朝，鼎成龍駕上丹霄。", "天風乍起鶴聲遠，海霧漸深龍節遙。", "仙界日長青鳥度，御衣香散紫霞飄。", "唯留古跡寒原在，碧水蒼蒼空寂寥。"]'),
('895de138-a7aa-422f-bb58-e0ea4c8b2822','秋日寓懷','劉滄','唐','唐诗','tang','','[]','海上生涯一釣舟，偶因名利事淹留。',64,'全唐诗/poet.tang.32000.json','["海上生涯一釣舟，偶因名利事淹留。", "旅塗誰見客青眼，故國幾多人白頭。", "霽色滿川明水驛，蟬聲落日隱城樓。", "如何未盡此行役，西入潼關雲木秋。"]'),
('916788ba-8281-40c5-ab97-d738857f24fe','江城晚望','劉滄','唐','唐诗','tang','','[]','一望江城思有餘，遙分野逕入樵漁。',64,'全唐诗/poet.tang.32000.json','["一望江城思有餘，遙分野逕入樵漁。", "青山經雨菊花盡，白鳥下灘蘆葉疎。", "靜聽潮聲寒木杪，遠看風色暮帆舒。", "秋期又涉潼關路，不得年年向此居。"]'),
('d9c217d8-518d-47bb-b6c5-85a0875312e3','宿蒼谿館','劉滄','唐','唐诗','tang','','[]','孤館門開對碧岑，竹窗燈下聽猨吟。',64,'全唐诗/poet.tang.32000.json','["孤館門開對碧岑，竹窗燈下聽猨吟。", "巴山夜雨別離夢，秦塞舊山迢遰心。", "滿地莓苔生近水，幾株楊柳自成陰。", "空思知己隔雲嶺，鄉路獨歸春草深。"]'),
('886c363d-9afd-4be4-9fc3-d33348dd98a2','題王母廟','劉滄','唐','唐诗','tang','','[]','寂寥珠翠想遺聲，門掩煙微水殿清。',64,'全唐诗/poet.tang.32000.json','["寂寥珠翠想遺聲，門掩煙微水殿清。", "拂曙紫霞生古壁，何年絳節下層城。", "鶴歸遼海春光晚，花落閑堦夕雨晴。", "武帝無名在仙籍，玉壇星月夜空明。"]'),
('b49902b2-4f1f-49cb-86df-deb575a3cf6a','留別復本修古二上人','劉滄','唐','唐诗','tang','','[]','二遠相知是昔年，此身長寄禮香煙。',64,'全唐诗/poet.tang.32000.json','["二遠相知是昔年，此身長寄禮香煙。", "綠蕪風晚水邊寺，清磬月高林下禪。", "臺殿虛窗山翠入，梧桐疎葉露光懸。", "西峰話別又須去，終日關山在馬前。"]'),
('48d27ed5-36bd-4a1b-aef6-6f71469a3d20','邊思','劉滄','唐','唐诗','tang','','["\u9ec4\u6cb3"]','漢將邊方背轆轤，受降城北是單于。',64,'全唐诗/poet.tang.32000.json','["漢將邊方背轆轤，受降城北是單于。", "黃河晚凍雪風急，野火遠燒山木枯。", "偷號甲兵衝塞色，銜枚戰馬踏寒蕪。", "蛾眉一沒空留怨，青塚月明啼夜烏。"]'),
('c7cf0c86-b7c0-4158-9ccb-86949f401661','登龍門敬善寺閣','劉滄','唐','唐诗','tang','','[]','獨步危梯入杳冥，天風瀟灑拂簷楹。',64,'全唐诗/poet.tang.32000.json','["獨步危梯入杳冥，天風瀟灑拂簷楹。", "禹門煙樹正春色，少室雲屏向晚晴。", "花落院深清禁閉，水分川闊綠蕪平。", "瑣窗朱檻同仙界，半夜緱山有鶴聲。"]'),
('a72b51f2-6bbf-493d-881f-9c1e3fe72638','題王校書山齋','劉滄','唐','唐诗','tang','','[]','猨鳥無聲晝掩扉，寒原隔水到人稀。',64,'全唐诗/poet.tang.32000.json','["猨鳥無聲晝掩扉，寒原隔水到人稀。", "雲晴古木月初上，雪滿空庭鶴未歸。", "藥囿地連山色近，樵家路入樹煙微。", "栖遲慣得滄浪思，雲閣還應夢釣磯。"]'),
('75cc1819-60f3-4570-aa63-2eccd4250d72','浙江晚渡懷古','劉滄','唐','唐诗','tang','','[]','蟬噪秋風滿古隄，荻花寒渡思萋萋。',64,'全唐诗/poet.tang.32000.json','["蟬噪秋風滿古隄，荻花寒渡思萋萋。", "潮聲歸海鳥初下，草色連江人自迷。", "碧落晴分平楚外，青山晚出穆陵西。", "此來一見垂綸者，卻憶舊居明月溪。"]'),
('58209009-f49f-4511-baad-0ead7cfa8e94','及第後宴曲江','劉滄','唐','唐诗','tang','','[]','及第新春選勝遊，杏園初宴曲江頭。',64,'全唐诗/poet.tang.32000.json','["及第新春選勝遊，杏園初宴曲江頭。", "紫毫粉壁題仙籍，柳色簫聲拂御樓。", "霽景露光明遠岸，晚空山翠墜芳洲。", "歸時不省花間醉，綺陌香車似水流。"]'),
('e4919cee-b309-43f0-a6fc-7be936c8f532','秋日山寺懷友人','劉滄','唐','唐诗','tang','','[]','蕭寺樓臺對夕陰，淡煙疎磬散空林。',64,'全唐诗/poet.tang.32000.json','["蕭寺樓臺對夕陰，淡煙疎磬散空林。", "風生寒渚白蘋動，霜落秋山黃葉深。", "雲盡獨看晴塞鴈，月明遙聽遠村砧。", "相思不見又經歲，坐向松窗彈玉琴。"]'),
('637deb68-191b-4899-89ff-8c229c0bb9b8','八月十五日夜玩月','劉滄','唐','唐诗','tang','','[]','中秋朗月靜天河，烏鵲南飛客恨多。',64,'全唐诗/poet.tang.32000.json','["中秋朗月靜天河，烏鵲南飛客恨多。", "寒色滿窗明枕簟，清光凝露拂煙蘿。", "桂枝斜漢流靈魄，蘋葉微風動細波。", "此夜空亭聞木落，蒹葭霜磧鴈初過。"]'),
('5cf0bbbe-bf85-4faa-8513-b7b8481b8d8a','晚春宿僧院','劉滄','唐','唐诗','tang','','[]','蕭寺春風正落花，淹留數宿惠休家。',64,'全唐诗/poet.tang.32000.json','["蕭寺春風正落花，淹留數宿惠休家。", "碧空雲盡磬聲遠，清夜月高窗影斜。", "白日閑吟爲道侶，青山遙指是生涯。", "微微一點寒燈在，鄉夢不成聞曙鵶。"]'),
('0d855ec3-c8f5-489e-a562-1047a415e3b9','懷汶陽兄弟','劉滄','唐','唐诗','tang','','[]','回看雲嶺思茫茫，幾處關河隔汶陽。',64,'全唐诗/poet.tang.32000.json','["回看雲嶺思茫茫，幾處關河隔汶陽。", "書信經年鄉國遠，弟兄無力海田荒。", "天高霜月砧聲苦，風滿寒林木葉黃。", "終日路岐歸未得，秋來空羨鴈成行。"]'),
('c679c442-919c-43b0-91c7-025fdbc5c189','題天宮寺閣','劉滄','唐','唐诗','tang','','[]','丹闕侵霄壯復危，排空霞影動簷扉。',64,'全唐诗/poet.tang.32000.json','["丹闕侵霄壯復危，排空霞影動簷扉。", "城連伊水禹門近，煙隔上陽宮樹微。", "天歛暮雲殘雨歇，路穿春草一僧歸。", "此來閑望更何有，無限清風生客衣。"]'),
('9609f167-73e7-4c6a-94b2-d73c6e90f919','遊上方石窟寺','劉滄','唐','唐诗','tang','','[]','苔徑縈迴景漸分，翛然空界靜埃氛。',64,'全唐诗/poet.tang.32000.json','["苔徑縈迴景漸分，翛然空界靜埃氛。", "一聲疎磬過寒水，半壁危樓隱白雲。", "雪下石龕僧在定，日西山木鳥成羣。", "幾來吟嘯立朱檻，風起天香處處聞。"]'),
('0c2deaec-0853-40d9-9183-bd2556facb38','懷江南友人','劉滄','唐','唐诗','tang','','[]','久絕音書隔塞塵，路岐誰與子相親。',64,'全唐诗/poet.tang.32000.json','["久絕音書隔塞塵，路岐誰與子相親。", "愁中獨坐秦城夜，別後幾經吳苑春。", "湘岸風來吹綠綺，海門潮上沒青蘋。", "空勞兩地望明月，多感斷蓬千里身。"]'),
('538bb982-362a-4714-a1ed-acd5e5f6d8e9','題敬亭山廟','劉滄','唐','唐诗','tang','','[]','森森古木列巖隈，迥壓寒原霽色開。',64,'全唐诗/poet.tang.32000.json','["森森古木列巖隈，迥壓寒原霽色開。", "雲雨只從山上起，風雷多向廟中來。", "三江入海聲長在，雙鶴啼天影未迴。", "花落空庭春晝晚，石牀松殿滿青苔。"]'),
('5b5bb571-59a6-4af0-96a6-fbde62938f02','經麻姑山','劉滄','唐','唐诗','tang','','[]','麻姑此地鍊神丹，寂寞煙霞古竈殘。',64,'全唐诗/poet.tang.32000.json','["麻姑此地鍊神丹，寂寞煙霞古竈殘。", "一自仙娥歸碧落，幾年春雨洗紅蘭。", "帆飛震澤秋江遠，雨過陵陽晚樹寒。", "山頂白雲千萬片，時聞鸞鶴下仙壇。"]'),
('ee292b05-f9de-4ade-bce9-48cffb729015','對殘春','劉滄','唐','唐诗','tang','','[]','楊花漠漠暗長隄，春盡人愁鳥又啼。',64,'全唐诗/poet.tang.32000.json','["楊花漠漠暗長隄，春盡人愁鳥又啼。", "鬢髪近來生處白，家園幾向夢中迷。", "霏微遠樹荒郊外，牢落空城夕照西。", "唯有年光堪自惜，不勝煙草日萋萋。"]'),
('88981c0f-7080-4470-a582-20b3e4c85cc5','過滄浪峽','劉滄','唐','唐诗','tang','','[]','山疊雲重一徑幽，蒼苔古石瀨清流。',64,'全唐诗/poet.tang.32000.json','["山疊雲重一徑幽，蒼苔古石瀨清流。", "出巖樹色見來靜，落澗泉聲長自秋。", "遠入虛明思白帝，寒生浩景想滄洲。", "如何地近東西路，馬足車輪不暫留。"]'),
('084b2a05-68f6-427e-9b76-cea456694c6b','經過建業','劉滄','唐','唐诗','tang','','[]','六代興衰曾此地，西風露泣白蘋花。',64,'全唐诗/poet.tang.32000.json','["六代興衰曾此地，西風露泣白蘋花。", "煙波浩渺空亡國，楊柳蕭條有幾家。", "楚塞秋光晴入樹，浙江殘雨晚生霞。", "淒涼處處漁樵路，鳥去人歸山影斜。"]'),
('bcdfb30a-59fe-4ea0-8bcb-40f14425007a','贈道者','劉滄','唐','唐诗','tang','','[]','真趣淡然居物外，忘機多是隱天台。',64,'全唐诗/poet.tang.32000.json','["真趣淡然居物外，忘機多是隱天台。", "停燈深夜看仙籙，拂石高秋坐釣臺。", "賣藥故人湘水別，入簷栖鳥舊山來。", "無因朝市知名姓，地僻衡門對嶽開。"]'),
('7c3de870-4a08-4259-a0f0-8a4b393b112e','題馬太尉華山莊','劉滄','唐','唐诗','tang','','[]','別開池館背山陰，近得幽奇物外心。',64,'全唐诗/poet.tang.32000.json','["別開池館背山陰，近得幽奇物外心。", "竹色拂雲連嶽寺，泉聲帶雨出谿林。", "一庭楊柳春光暖，三逕煙蘿晚翠深。", "自是功成閑劒履，西齋長臥對瑤琴。"]'),
('61c10046-5c6e-4655-8338-f9802d9700ef','秋日夜懷','劉滄','唐','唐诗','tang','','[]','砧杵寥寥秋色長，遶枝寒鵲客情傷。',64,'全唐诗/poet.tang.32000.json','["砧杵寥寥秋色長，遶枝寒鵲客情傷。", "關山雲盡九秋月，門柳葉凋三徑霜。", "近日每思歸少室，故人遙憶隔瀟湘。", "如何節候變容髪，明鏡一看愁異常。"]'),
('85926f2d-6a22-4850-8ef7-b3f4e4739f5f','題巫山廟','劉滄','唐','唐诗','tang','','[]','十二嵐峯挂夕暉，廟門深閉霧煙微。',64,'全唐诗/poet.tang.32000.json','["十二嵐峯挂夕暉，廟門深閉霧煙微。", "天高木落楚人思，山迥月殘神女歸。", "觸石晴雲凝翠鬢，度江寒雨濕羅衣。", "嬋娟似恨襄王夢，猨呌斷岩秋蘚稀。"]'),
('4ed023a1-51d2-4005-b56a-7f03c6d8fbf8','題吳宮苑','劉滄','唐','唐诗','tang','','[]','吳苑荒涼故國名，吳山月上照江明。',64,'全唐诗/poet.tang.32000.json','["吳苑荒涼故國名，吳山月上照江明。", "殘春碧樹自留影，半夜子規何處聲。", "蘆葉長侵洲渚暗，蘋花開盡水煙平。", "經過此地千年恨，荏苒東風露色清。"]'),
('0d95041f-98b9-4f24-bdf1-83ee361a3c0a','旅館書懷','劉滄','唐','唐诗','tang','','[]','秋看庭樹換風煙，兄弟飄零寄海邊。',64,'全唐诗/poet.tang.32000.json','["秋看庭樹換風煙，兄弟飄零寄海邊。", "客計倦行分陝路，家貧休種汶陽田。", "雲低遠塞鳴寒鴈，雨歇空山噪暮蟬。", "落葉蟲絲滿窗戶，秋堂獨坐思悠然。"]'),
('a1f09741-40df-4fe9-861c-1334238e791d','贈天台隱者','劉滄','唐','唐诗','tang','','[]','靜者多依猨鳥叢，衡門野色四郊通。',64,'全唐诗/poet.tang.32000.json','["靜者多依猨鳥叢，衡門野色四郊通。", "天開宿霧海生日，水泛落花山有風。", "迴望一巢懸木末，獨尋危石坐巖中。", "看書飲酒餘無事，自樂樵漁狎釣翁。"]'),
('3d0f2059-8fe4-40e9-9a50-5d098b82f449','洛陽月夜書懷','劉滄','唐','唐诗','tang','','[]','疎柳高槐古巷通，月明西照上陽宮。',64,'全唐诗/poet.tang.32000.json','["疎柳高槐古巷通，月明西照上陽宮。", "一聲邊鴈塞門雪，幾處遠砧河漢風。", "獨榻閑眠移嶽影，寒窗幽思度煙空。", "孤吟此夕驚秋晚，落葉殘花樹色中。"]'),
('b9b17191-0309-4b6b-ac99-e19b55b1facb','江行夜泊','劉滄','唐','唐诗','tang','','[]','白浪連空極渺漫，孤舟此夜泊中灘。',64,'全唐诗/poet.tang.32000.json','["白浪連空極渺漫，孤舟此夜泊中灘。", "岳陽秋霽寺鐘遠，渡口月明漁火殘。", "綠綺韵高湘女怨，青葭色映水禽寒。", "鄉遙楚國生歸思，欲曙山光上木蘭。"]'),
('b56c1b5c-e2c6-4afc-8a38-682213b77b27','贈顓頊山人','劉滄','唐','唐诗','tang','','[]','浩氣含真玉片輝，著書精義入玄微。',64,'全唐诗/poet.tang.32000.json','["浩氣含真玉片輝，著書精義入玄微。", "洛陽紫陌幾曾醉，少室白雲時一歸。", "松雪月高唯鶴宿，煙嵐秋霽到人稀。", "知君濟世有長策，莫問滄浪隱釣磯。"]'),
('8b669ace-ad1c-47fe-8293-be7fb630a044','長安冬夜書情','劉滄','唐','唐诗','tang','','[]','上國棲遲歲欲終，此情多寄寂寥中。',64,'全唐诗/poet.tang.32000.json','["上國棲遲歲欲終，此情多寄寂寥中。", "鐘傳半夜旅人館，鵶呌一聲疎樹風。", "古巷月高山色靜，寒蕪霜落灞原空。", "今來唯問心期事，獨望青雲路未通。"]'),
('898dc273-91c0-44ea-bb89-ba1505e6bdc9','經古行宮','劉滄','唐','唐诗','tang','','[]','玉輦西歸已至今，古原風景自沈沈。',64,'全唐诗/poet.tang.32000.json','["玉輦西歸已至今，古原風景自沈沈。", "御溝流水長芳草，宮樹落花空夕陰。", "胡蝶翅翻殘露滴，子規聲盡野煙深。", "路人不記當年事，臺殿寂寥山影侵。"]'),
('95a9bf12-0c1e-45b3-8387-ea9c4918ca31','秋日登醴泉縣樓','劉滄','唐','唐诗','tang','','[]','閑上高樓時一望，綠蕪寒野靜中分。',64,'全唐诗/poet.tang.32000.json','["閑上高樓時一望，綠蕪寒野靜中分。", "人行直路入秦樹，鴈截斜陽背塞雲。", "渭水自流汀島色，漢陵空長石苔紋。", "秋風高柳出危葉，獨聽蟬聲日欲曛。"]'),
('a4111405-815a-4142-ac0d-233452564c5a','春日旅遊','劉滄','唐','唐诗','tang','','[]','玄髪辭家事遠遊，春風歸鴈一聲愁。',64,'全唐诗/poet.tang.32000.json','["玄髪辭家事遠遊，春風歸鴈一聲愁。", "花開忽憶故山樹，月上自登臨水樓。", "浩浩晴原人獨去，依依春草水分流。", "秦川楚塞煙波隔，怨別路岐何日休。"]'),
('665ed260-133e-4dc8-a221-b20b6b2e4649','送友人下第歸吳','劉滄','唐','唐诗','tang','','[]','共惜年華未立名，路岐終日軫羈情。',64,'全唐诗/poet.tang.32000.json','["共惜年華未立名，路岐終日軫羈情。", "青春半是往來盡，白髮多因離別生。", "楚岸帆開雲樹映，吳門月上水煙清。", "東歸自有故山約，花落石牀苔蘚平。"]'),
('1398615a-7dff-4349-bbed-1b8d5e878838','訪友人郊居','劉滄','唐','唐诗','tang','','[]','登原過水訪相如，竹塢莎庭似故居。',64,'全唐诗/poet.tang.32000.json','["登原過水訪相如，竹塢莎庭似故居。", "空塞山當清晝晚，古槐人繼綠陰餘。", "休彈瑟韻傷離思，已有蟬聲報夏初。", "醉唱勞歌翻自歎，釣船漁浦夢難疎。"]'),
('7207a46c-d68a-4d68-86a2-53ac50240c13','匡城尋薛閔秀才不遇','劉滄','唐','唐诗','tang','','[]','音容一別近三年，往事空思意浩然。',64,'全唐诗/poet.tang.32000.json','["音容一別近三年，往事空思意浩然。", "匹馬東西何處客，孤城楊柳晚來蟬。", "路長草色秋山綠，川闊晴光遠水連。", "不見故人勞夢寐，獨吟風月過南燕。"]'),
('79f76c9d-00ae-47f6-8cd3-634f3381a1ac','與僧話舊','劉滄','唐','唐诗','tang','','[]','巾舃同時下翠微，舊遊因話事多違。',64,'全唐诗/poet.tang.32000.json','["巾舃同時下翠微，舊遊因話事多違。", "南朝古寺幾僧在，西嶺空林唯鳥歸。", "莎徑晚煙凝竹塢，石池春色染苔衣。", "此時相見又相別，即是關河朔鴈飛。"]'),
('3ce81977-0e77-4ae7-8659-037eea137ce5','寄遠','劉滄','唐','唐诗','tang','','[]','西園楊柳暗驚秋，寶瑟朱弦結遠愁。',64,'全唐诗/poet.tang.32000.json','["西園楊柳暗驚秋，寶瑟朱弦結遠愁。", "霜落鴈聲來紫塞，月明人夢在青樓。", "蕙心迢遰湘雲暮，蘭思縈迴楚水流。", "錦字織成添別恨，關河萬里路悠悠。"]'),
('494cfc5f-f5f4-4ca7-8542-b7cc557fe58a','長安逢友人','劉滄','唐','唐诗','tang','','[]','上國相逢塵滿襟，傾杯一話昔年心。',64,'全唐诗/poet.tang.32000.json','["上國相逢塵滿襟，傾杯一話昔年心。", "荒臺共望秋山立，古寺多同雪夜吟。", "風度重城宮漏盡，月明高柳禁煙深。", "終期白日青雲路，休感鬢毛霜雪侵。"]'),
('4cea7b6f-c0e3-4df2-8b86-ce4778e87e1c','下第東歸途中書事','劉滄','唐','唐诗','tang','','[]','峽路誰知倦此情，往來多是半年程。',64,'全唐诗/poet.tang.32000.json','["峽路誰知倦此情，往來多是半年程。", "孤吟洛苑逢春盡，幾向秦城見月明。", "高柳斷煙侵嶽影，古隄斜日背灘聲。", "東歸海上有餘業，牢落田園荒草平。"]'),
('b1f4e0d8-2b67-4b9d-b3f2-58616a3c0758','經龍門廢寺','劉滄','唐','唐诗','tang','','[]','因思人事事無窮，幾度經過感此中。',64,'全唐诗/poet.tang.32000.json','["因思人事事無窮，幾度經過感此中。", "山色不移樓殿盡，石臺依舊水雲空。", "唯餘芳草滴春露，時有殘花落晚風。", "楊柳覆灘清瀨響，暮天沙鳥自西東。"]'),
('4204559c-c474-431e-b737-3fea237e3ef2','下第後懷舊居','劉滄','唐','唐诗','tang','','[]','幾到青門未立名，芳時多負故鄉情。',64,'全唐诗/poet.tang.32000.json','["幾到青門未立名，芳時多負故鄉情。", "雨餘秦苑綠蕪合，春盡灞原白髮生。", "每見山泉長屬意，終期身事在歸耕。", "蘋花覆水曲谿暮，獨坐釣舟歌月明。"]'),
('39e69984-b494-433a-9f79-46ad3bf9c2aa','經無可舊居兼傷賈島','劉滄','唐','唐诗','tang','','["\u957f\u6c5f"]','塵室寒窗我獨看，別來人事幾凋殘。',64,'全唐诗/poet.tang.32000.json','["塵室寒窗我獨看，別來人事幾凋殘。", "晝空蕭寺一僧去，雪滿巴山孤客寒。", "落葉墮巢禽自出，蒼苔封砌竹成竿。", "碧雲迢遰長江遠，向夕苦吟歸思難。"]'),
('04ff9a51-19f8-452f-ac7a-fd5d32aec8a4','贈隱者','劉滄','唐','唐诗','tang','','[]','何時止此幽棲處，獨掩衡門長綠苔。',64,'全唐诗/poet.tang.32000.json','["何時止此幽棲處，獨掩衡門長綠苔。", "臨水靜聞靈鶴語，隔原時有至人來。", "五湖仙島幾年別，九轉藥爐深夜開。", "誰識無機養真性，醉眠松石枕空杯。"]'),
('b7e5aa4f-2e88-4348-85cf-b3a9d7fa989f','題書齋','劉滄','唐','唐诗','tang','','[]','一日不曾離此處，風吹疎牖夕雲晴。',64,'全唐诗/poet.tang.32000.json','["一日不曾離此處，風吹疎牖夕雲晴。", "氣凌霜色劒光動，吟對雪華詩韻清。", "高木宿禽來遠嶽，古原殘雨隔重城。", "西齋瑤瑟自爲侶，門掩半春苔蘚生。"]'),
('b336e5f6-4a05-491b-b65d-c19ba6edabcc','題秦女樓','劉滄','唐','唐诗','tang','','[]','珠翠香銷鴛瓦墮，神仙曾向此中遊。',64,'全唐诗/poet.tang.32000.json','["珠翠香銷鴛瓦墮，神仙曾向此中遊。", "青樓月色桂花冷，碧落簫聲雲葉愁。", "杳杳蓬萊人不見，蒼蒼苔蘚路空留。", "一從鳳去千年後，迢遰岐山水石秋。"]'),
('34825610-0702-4650-88fc-342f3e5f6e61','題桃源處士山居留寄','劉滄','唐','唐诗','tang','','[]','白雲深處葺茅廬，退隱衡門與俗疎。',64,'全唐诗/poet.tang.32000.json','["白雲深處葺茅廬，退隱衡門與俗疎。", "一洞曉煙留水上，滿庭春露落花初。", "閑看竹嶼吟新月，特酌山醪讀古書。", "窮達盡爲身外事，浩然元氣樂樵漁。"]'),
('b5773b54-5774-4eef-9805-2676268a4c9f','宿題天壇觀','劉滄','唐','唐诗','tang','','[]','沐髪清齋宿洞宮，桂花松韻滿巖風。',64,'全唐诗/poet.tang.32000.json','["沐髪清齋宿洞宮，桂花松韻滿巖風。", "紫霞曉色秋山霽，碧落寒光霜月空。", "華表鶴聲天外迥，蓬萊仙界海門通。", "冥心一悟虛無理，寂寞玄珠象罔中。"]'),
('a4f40e7c-829d-4c6c-ba00-58e65119b8b4','洛神怨','劉滄','唐','唐诗','tang','','[]','子建東歸恨思長，飄颻神女步池塘。',64,'全唐诗/poet.tang.32000.json','["子建東歸恨思長，飄颻神女步池塘。", "雲鬟高動水宮影，珠翠乍搖沙露光。", "心寄碧沈空婉戀，夢殘春色自悠揚。", "停車綺陌傍楊柳，片月青樓落未央。"]'),
('aead4684-9422-4a53-ad7a-0a38396be3ff','龍門留別道友','劉滄','唐','唐诗','tang','','[]','一顧恩深荷道安，獨垂雙淚下層巒。',64,'全唐诗/poet.tang.32000.json','["一顧恩深荷道安，獨垂雙淚下層巒。", "飛鳴北鴈塞雲暮，搖落西風關樹寒。", "春谷終期吹羽翼，萍身不定逐波瀾。", "裴徊偏起舊枝戀，半夜獨吟孤燭殘。"]'),
('163af2c9-5dda-4fbe-896d-555e25b1dcf8','題四皓廟','劉滄','唐','唐诗','tang','','[]','石壁蒼苔翠靄濃，驅車商洛想遺踪。',64,'全唐诗/poet.tang.32000.json','["石壁蒼苔翠靄濃，驅車商洛想遺踪。", "天高猨呌向山月，露下鶴聲來廟松。", "葉墮陰巖疎薜荔，池經秋雨老芙蓉。", "雪髯仙侶何深隱，千古寂寥雲水重。"]'),
('f5543119-58a6-4428-abbe-44f98c9c67cb','望未央宮','劉滄','唐','唐诗','tang','','[]','西上秦原見未央，山嵐川色晚蒼蒼。',64,'全唐诗/poet.tang.32000.json','["西上秦原見未央，山嵐川色晚蒼蒼。", "雲樓欲動入清渭，鴛瓦如飛出綠楊。", "舞席歌塵空歲月，宮花春草滿池塘。", "香風吹落天人語，綵鳳五雲朝漢皇。"]'),
('09537476-48f1-40e8-9f16-833c6e1a70ec','秋日過昭陵','劉滄','唐','唐诗','tang','','[]','寢廟徒悲劒與冠，翠華龍馭杳漫漫。',64,'全唐诗/poet.tang.32000.json','["寢廟徒悲劒與冠，翠華龍馭杳漫漫。", "原分山勢入空塞，地匝松陰出晚寒。", "上界鼎成雲縹緲，西陵舞罷淚闌干。", "那堪獨立斜陽裏，碧落秋光煙樹殘。"]'),
('c59a047f-2ea1-4b49-94c1-3e1dcf264ae9','夏日登慈恩寺','劉滄','唐','唐诗','tang','','[]','金界時來一訪僧，天香飄翠瑣窗凝。',64,'全唐诗/poet.tang.32000.json','["金界時來一訪僧，天香飄翠瑣窗凝。", "碧池靜照寒松影，清晝深懸古殿燈。", "晚景風蟬催節候，高空雲鳥度軒層。", "塵機消盡話玄理，暮磬出林疎韻澄。"]'),
('998d04e8-1ada-4bd5-88a8-b50a88f6de8c','宿題金山寺','劉滄','唐','唐诗','tang','','[]','一點青山翠色危，雲岩不掩與星期。',64,'全唐诗/poet.tang.32000.json','["一點青山翠色危，雲岩不掩與星期。", "海門煙樹潮歸後，江面山樓月照時。", "獨鶴唳空秋露下，高僧入定夜猨知。", "蕭疎水木清鐘梵，顥氣寒光動石池。"]'),
('6600f7c6-0427-48fe-98d2-00c36cb5896e','送友人遊蜀','劉滄','唐','唐诗','tang','','[]','北去西遊春未半，蜀山雲雪入詩情。',64,'全唐诗/poet.tang.32000.json','["北去西遊春未半，蜀山雲雪入詩情。", "青蘿拂水花流影，翠靄隔巖猨有聲。", "日出空江分遠浪，鳥歸高木認孤城。", "心期萬里無勞倦，古石蒼苔峽路清。"]'),
('6c531003-97bb-4399-b548-67583cae0daa','題鄭中丞東溪','劉滄','唐','唐诗','tang','','[]','一境新開雉堞西，綠苔微徑露淒淒。',64,'全唐诗/poet.tang.32000.json','["一境新開雉堞西，綠苔微徑露淒淒。", "高軒夜靜竹聲遠，曲岸春深楊柳低。", "山霽月明常此醉，草芳花暗省曾迷。", "即隨鳳詔歸清列，幾憶風花夢小溪。"]'),
('51511e2d-c8da-4892-82a1-c98c70bcb78e','代友人悼姬','劉滄','唐','唐诗','tang','','[]','羅帳香微冷錦裀，歌聲永絕想梁塵。',64,'全唐诗/poet.tang.32000.json','["羅帳香微冷錦裀，歌聲永絕想梁塵。", "蕭郎獨宿落花夜，謝女不歸明月春。", "青鳥罷傳相寄字，碧江無復採蓮人。", "滿庭芳草坐成恨，迢遰蓬萊入夢頻。"]'),
('0d27db0e-2c51-4b39-a9f1-94c9235388ea','夏日登西林白上人樓','劉滄','唐','唐诗','tang','','[]','幾到西林清淨境，層臺高視有無間。',64,'全唐诗/poet.tang.32000.json','["幾到西林清淨境，層臺高視有無間。", "寒光遠動天邊水，碧影出空煙外山。", "苔點落花微萼在，葉藏幽鳥碎聲閑。", "曠然多慊登樓意，永日重門深掩關。"]'),
('bc639bfd-b8ab-4fd6-8dd3-8b0c838187b6','江樓月夜聞笛','劉滄','唐','唐诗','tang','','[]','南浦蒹葭疎雨後，寂寥橫笛怨江樓。',64,'全唐诗/poet.tang.32000.json','["南浦蒹葭疎雨後，寂寥橫笛怨江樓。", "思飄明月浪花白，聲入碧雲楓葉秋。", "河漢夜闌孤鴈度，瀟湘水闊二妃愁。", "髪寒衣濕曲初罷，露色河光生釣舟。"]'),
('cfca5cb4-24f2-464d-8d60-b60a5a46a27d','送友人下第東歸','劉滄','唐','唐诗','tang','','[]','漠漠楊花灞岸飛，幾迴傾酒話東歸。',64,'全唐诗/poet.tang.32000.json','["漠漠楊花灞岸飛，幾迴傾酒話東歸。", "九衢春盡生鄉夢，千里塵多滿客衣。", "流水雨餘芳草合，空山月晚白雲微。", "金門自有西來約，莫待螢光照竹扉。"]'),
('b5372dae-746b-411b-b3c5-2aa051e056ef','從鄭郎中高州遊東潭','劉滄','唐','唐诗','tang','','[]','煙嵐晚入濕旌旗，高檻風清醉未歸。',64,'全唐诗/poet.tang.32000.json','["煙嵐晚入濕旌旗，高檻風清醉未歸。", "夾路野花迎馬首，出林山鳥向人飛。", "一谿寒水涵清淺，幾處晴雲度翠微。", "自是謝公心近得，登樓望月思依依。"]'),
('121e3c69-0905-4115-b2fa-31800bd25a8a','罷華原尉上座主尚書','劉滄','唐','唐诗','tang','','[]','自憐生計事悠悠，浩渺滄浪一釣舟。',64,'全唐诗/poet.tang.32000.json','["自憐生計事悠悠，浩渺滄浪一釣舟。", "千里夢歸清洛近，三年官罷杜陵秋。", "山連絕塞渾無色，水到平沙幾處流。", "白露黃花歲時晚，不堪霜鬢鏡前愁。"]'),
('3ff92816-b977-4868-98d3-7cd7155303d6','雨後遊南門寺','劉滄','唐','唐诗','tang','','[]','郭南山寺雨初晴，上界尋僧竹裏行。',64,'全唐诗/poet.tang.32000.json','["郭南山寺雨初晴，上界尋僧竹裏行。", "半壁樓臺秋月過，一川煙水夕陽平。", "苔封石室雲含潤，露滴松枝鶴有聲。", "木葉蕭蕭動歸思，西風畫角漢東城。"]'),
('81005274-f922-4b13-b433-0def4cff5683','題古寺','劉滄','唐','唐诗','tang','','[]','古寺蕭條偶宿期，更深霜壓竹枝低。',64,'全唐诗/poet.tang.32000.json','["古寺蕭條偶宿期，更深霜壓竹枝低。", "長天月影高窗過，疎樹寒鵶半夜啼。", "池水竭來龍已去，老松枯處鶴猶棲。", "傷心可惜從前事，寥落朱廊墮粉泥。"]'),
('f7268a30-87c5-438f-bf5f-82e3b4398a58','晚秋野望','劉滄','唐','唐诗','tang','','[]','秋盡郊原情自哀，菊花寂寞晚仍開。',64,'全唐诗/poet.tang.32000.json','["秋盡郊原情自哀，菊花寂寞晚仍開。", "高風疎葉帶霜落，一鴈寒聲背水來。", "荒壘幾年經戰後，故山終日望書回。", "歸途休問從前事，獨唱勞歌醉數杯。"]'),
('4ba120c3-a9c0-4044-a0fc-cb319764ebc5','秋月望上陽宮','劉滄','唐','唐诗','tang','','[]','苔色輕塵鎖洞房，亂鴉羣鴿集殘陽。',64,'全唐诗/poet.tang.32000.json','["苔色輕塵鎖洞房，亂鴉羣鴿集殘陽。", "青山空出禁城日，黃葉自飛宮樹霜。", "御路幾年香輦去，天津終日水聲長。", "此時獨立意難盡，正值西風砧杵涼。"]'),
('88904708-e986-43e3-95b1-1b291fa17576','入關留別主人','劉滄','唐','唐诗','tang','','[]','此來多愧食魚心，東閣將辭強一吟。',64,'全唐诗/poet.tang.32000.json','["此來多愧食魚心，東閣將辭強一吟。", "羸馬客程秋草合，晚蟬關樹古槐深。", "風生野渡河聲急，鴈過寒原嶽勢侵。", "對酒相看自無語，幾多離思入瑤琴。"]'),
('aeae8a38-837d-458a-8e8a-8f9018f6e4cb','留別山中友人','劉滄','唐','唐诗','tang','','[]','欲辭松月戀知音，去住多同羈鳥心。',64,'全唐诗/poet.tang.32000.json','["欲辭松月戀知音，去住多同羈鳥心。", "秋盡書窗驚白髮，晚衝霜葉下青岑。", "大河風急寒聲遠，高嶺雲開夕影深。", "別後寂寥無限意，野花門路草蟲吟。"]'),
('57186daf-df8b-40c3-b3c1-6b2205e92a2a','春晚旅次有懷','劉滄','唐','唐诗','tang','','[]','晚出關河綠野平，依依雲樹動鄉情。',64,'全唐诗/poet.tang.32000.json','["晚出關河綠野平，依依雲樹動鄉情。", "殘春花盡黃鶯語，遠客愁多白髮生。", "野水亂流臨古驛，斷煙凝處近孤城。", "東西未遂歸田計，海上青山久廢耕。"]'),
('1117acb4-7846-488b-a201-38ca471d2fad','與重幽上人話舊','劉滄','唐','唐诗','tang','','[]','雲飛天末水空流，省與師同別異州。',64,'全唐诗/poet.tang.32000.json','["雲飛天末水空流，省與師同別異州。", "庭樹蟬聲初入夏，石牀苔色幾經秋。", "燈微靜室生鄉思，月上嚴城話旅遊。", "自喜他年接巾舃，滄浪地近虎溪頭。"]'),
('f99648a9-f80a-4b31-b900-e0b9c43a5613','月夜聞鶴唳','劉滄','唐','唐诗','tang','','[]','碧落風微月正明，霜毛似怨有離情。',64,'全唐诗/poet.tang.32000.json','["碧落風微月正明，霜毛似怨有離情。", "莓苔石冷想孤立，楊柳葉疎聞轉清。", "空夜露殘驚墮羽，遼天秋晚憶歸程。", "鳳凰樓閣知猶戀，終逐煙霞上玉京。"]'),
('249a5e40-ec0e-491f-af74-c6de16382e0f','過北邙山','劉滄','唐','唐诗','tang','','[]','散漫黃埃滿北原，折碑橫路碾苔痕。',64,'全唐诗/poet.tang.32000.json','["散漫黃埃滿北原，折碑橫路碾苔痕。", "空山夜月來松影，荒塚春風變木根。", "漠漠兔絲羅古廟，翩翩丹旐過孤村。", "白楊落日悲風起，蕭索寒巢鳥獨奔。"]'),
('f9b25131-75e4-4f7e-9209-8ca5b63ef5ab','咸陽懷古','劉滄','唐','唐诗','tang','','[]','經過此地無窮事，一望淒然感廢興。',64,'全唐诗/poet.tang.32000.json','["經過此地無窮事，一望淒然感廢興。", "渭水故都秦二世，咸原秋草漢諸陵。", "天空絕塞聞邊鴈，葉盡孤村見夜燈。", "風景蒼蒼多少恨，寒山半出白雲層。"]'),
('103eece3-d83c-4a1c-a630-e8b916f0e1ab','送友人罷舉赴薊門從事','劉滄','唐','唐诗','tang','','[]','人生行止在知己，遠佐諸侯重所依。',64,'全唐诗/poet.tang.32000.json','["人生行止在知己，遠佐諸侯重所依。", "綠綬便當身是貴，青霄休怨志相違。", "晚雲遼水疎殘雨，寒角邊城怨落暉。", "此去黃金臺上客，相思應羨鴈南歸。"]'),
('25de53a4-270d-47e9-ac8f-805ee7fc637c','看牓日','劉滄','唐','唐诗','tang','','[]','禁漏初停蘭省開，列仙名目上清來。',64,'全唐诗/poet.tang.32000.json','["禁漏初停蘭省開，列仙名目上清來。", "飛鳴曉日鶯聲遠，變化春風鶴影回。", "廣陌萬人生喜色，曲江千樹發寒梅。", "青雲已是酬恩處，莫惜芳時醉酒杯。"]'),
('8171fc9a-76cb-4661-af55-f70b20420d73','送李休秀才歸嶺中','劉滄','唐','唐诗','tang','','[]','南泛孤舟景自饒，蒹葭汀浦晚蕭蕭。',64,'全唐诗/poet.tang.32000.json','["南泛孤舟景自饒，蒹葭汀浦晚蕭蕭。", "秋風漢水旅愁起，寒木楚山歸思遙。", "獨夜猨聲和落葉，晴江月色帶回潮。", "故園新過重陽節，黃菊滿籬應未凋。"]'),
('40da7dc5-52b1-4987-9844-5573281b0b01','寓居寄友人','劉滄','唐','唐诗','tang','','[]','雨餘虛館竹陰清，獨坐書窗軫旅情。',64,'全唐诗/poet.tang.32000.json','["雨餘虛館竹陰清，獨坐書窗軫旅情。", "芳草衡門無馬跡，古槐深巷有蟬聲。", "夕陽雲盡嵩峰出，遠岸煙消洛水平。", "今夜南原賞佳景，月高風定苦吟生。"]'),
('58446644-2460-4083-bc83-aa75de4acc4f','經曲阜城','劉滄','唐','唐诗','tang','','[]','行經闕里自堪傷，曾歎東流逝水長。',64,'全唐诗/poet.tang.32000.json','["行經闕里自堪傷，曾歎東流逝水長。", "蘿蔓幾凋荒隴樹，莓苔多處古宮牆。", "三千弟子標青史，萬代先生號素王。", "蕭索風高洙泗上，秋山明月夜蒼蒼。"]'),
('42369471-2c85-4478-bd4b-f5dc3b8ad7ed','汶陽客舍','劉滄','唐','唐诗','tang','','[]','年光自感益蹉跎，岐路東西竟若何。',64,'全唐诗/poet.tang.32000.json','["年光自感益蹉跎，岐路東西竟若何。", "窗外雨來山色近，海邊秋至鴈聲多。", "思鄉每讀登樓賦，對月空吟叩角歌。", "迢遰舊山伊水畔，破齋荒徑閉煙蘿。"]'),
('38fb89ea-cc8c-4de7-9767-fc353f9ca121','留別崔澣秀才昆仲','劉滄','唐','唐诗','tang','','[]','汶陽離思水無窮，去住情深夢寐中。',64,'全唐诗/poet.tang.32000.json','["汶陽離思水無窮，去住情深夢寐中。", "歲晚蟲鳴寒露草，日西蟬噪古槐風。", "川分遠岳秋光靜，雲盡遙天霽色空。", "對酒不能傷此別，尺書憑鴈往來通。"]'),
('e12693a4-5d53-4192-9184-6df4a81f82a8','和友人憶洞庭舊居','劉滄','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','客舍經時益苦吟，洞庭猶憶在前林。',64,'全唐诗/poet.tang.32000.json','["客舍經時益苦吟，洞庭猶憶在前林。", "青山殘月有歸夢，碧落片雲生遠心。", "谿路煙開江月出，草堂門掩海濤深。", "因君話舊起愁思，隔水數聲何處砧。"]'),
('720d3b21-625c-4afc-a1e2-0c562d710854','晚歸山居','劉滄','唐','唐诗','tang','','[]','寥落霜空木葉稀，初行郊野思依依。',64,'全唐诗/poet.tang.32000.json','["寥落霜空木葉稀，初行郊野思依依。", "秋深頻憶故鄉事，日暮獨尋荒徑歸。", "山影暗隨雲水動，鐘聲潛入遠煙微。", "娟娟唯有西林月，不惜清光照竹扉。"]'),
('ed0d2f36-a9ab-4c52-8e29-9683e928980b','送元敘上人歸上黨','劉滄','唐','唐诗','tang','','[]','太行關路戰塵收，白日思鄉別沃州。',64,'全唐诗/poet.tang.32000.json','["太行關路戰塵收，白日思鄉別沃州。", "薄暮焚香臨野燒，清晨漱齒涉寒流。", "谿邊殘壘空雲木，山上孤城對驛樓。", "此去寂寥尋舊跡，蒼苔滿徑竹齋秋。"]'),
('0d2c1fd7-dc84-4917-9635-ab4db4e69925','秋日旅途即事','劉滄','唐','唐诗','tang','','[]','驅羸多自感，煙草遠郊平。',48,'全唐诗/poet.tang.32000.json','["驅羸多自感，煙草遠郊平。", "鄉路幾時盡，旅人終日行。", "渡邊寒水驛，山下夕陽城。", "蕭索更何有，秋風兩鬢生。"]'),
('56af8c09-9fa9-472c-a0a3-7ba139c6f41f','早行','劉滄','唐','唐诗','tang','','[]','旅途乘早景，策馬獨淒淒。',48,'全唐诗/poet.tang.32000.json','["旅途乘早景，策馬獨淒淒。", "殘影郡樓月，一聲關樹雞。", "聽鐘煙柳外，問渡水雲西。", "當自勉行役，終期功業齊。"]'),
('c9c843c3-038b-4067-94f7-f3a4762b06c7','句','劉滄','唐','唐诗','tang','','[]','海曙雲浮日，江遙水合天。',12,'全唐诗/poet.tang.32000.json','["海曙雲浮日，江遙水合天。"]'),
('04bd7671-1369-41bc-be49-19218e7875c1','湘口送友人','李頻','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','中流欲暮見湘煙，葦岸無窮接楚田。',64,'全唐诗/poet.tang.32000.json','["中流欲暮見湘煙，葦岸無窮接楚田。", "去雁遠衝雲夢雪，離人獨上洞庭船。", "風波盡日依山轉，星漢通霄向水連。", "零落梅花過殘臘，故園歸醉及新年。"]'),
('24338aa9-e2dd-4f66-88c7-a428b439f972','鄂州頭陀寺上方','李頻','唐','唐诗','tang','','[]','高寺上方無不見，天涯行客思迢迢。',64,'全唐诗/poet.tang.32000.json','["高寺上方無不見，天涯行客思迢迢。", "西江帆挂東風急，夏口城銜楚塞遙。", "沙渚漁歸多濕網，桑林蠶後盡空條。", "感時歎物尋僧話，惟向禪心得寂寥。"]'),
('efe9c2e2-8557-4eb4-921d-09fa4a85b844','寄遠','李頻','唐','唐诗','tang','','[]','槐欲成陰分袂時，君期十日復金扉。',64,'全唐诗/poet.tang.32000.json','["槐欲成陰分袂時，君期十日復金扉。", "槐今落葉已將盡，君向遠鄉猶未歸。", "化石早曾聞節婦，沈湘何必獨靈妃。", "須知此意同生死，不學他人空寄衣。"]'),
('e3264e30-132f-4092-9865-ed5b41177101','題張司馬別墅','李頻','唐','唐诗','tang','','[]','庭前樹盡手中栽，先後花分幾番開。',64,'全唐诗/poet.tang.32000.json','["庭前樹盡手中栽，先後花分幾番開。", "巢鳥戀雛驚不起，野人思酒去還來。", "自拋官與青山近，誰訝身爲白髮催。", "門外尋常行樂處，重重履跡在莓苔。"]'),
('d79017c4-a642-4a8c-9530-f5154251f186','長安即事','李頻','唐','唐诗','tang','','[]','長遇豪家不敢過，此身誰與取高科。',64,'全唐诗/poet.tang.32000.json','["長遇豪家不敢過，此身誰與取高科。", "故園久絕書來後，南國空看雁去多。", "中夜永懷聽疊漏，先秋歸夢涉層波。", "愁人白髮自生早，我獨少年能幾何。"]'),
('ee4652d3-11ae-4259-a197-3c067c6ea45d','漢上逢同年崔八','李頻','唐','唐诗','tang','','[]','去歲曾遊帝里春，杏花開過各離秦。',64,'全唐诗/poet.tang.32000.json','["去歲曾遊帝里春，杏花開過各離秦。", "偶先託質逢知己，獨未還家作旅人。", "世上路岐何繚繞，空中光景自逡巡。", "一回相見一回別，能得幾時年少身。"]'),
('d62506eb-9ad7-459b-8530-d67e98c4ec6f','五月一日蒙替本官不得隨例入關感懷獻送相公','李頻','唐','唐诗','tang','','[]','五月傾朝謁紫宸，一朝無分在清塵。',64,'全唐诗/poet.tang.32000.json','["五月傾朝謁紫宸，一朝無分在清塵。", "含香已去星郎位，衣錦惟思婺女隣。", "折獄也曾爲俗吏，勸農元本是耕人。", "知將何事酬公道，只養生靈似養身。"]'),
('67525be2-4a58-43e0-89f7-82233e656e0d','春閨怨','李頻','唐','唐诗','tang','','[]','紅妝女兒燈下羞，畫眉夫壻隴西頭。',32,'全唐诗/poet.tang.32000.json','["紅妝女兒燈下羞，畫眉夫壻隴西頭。", "自怨愁容長照鏡，悔教征戍覓封侯。"]'),
('fadacf88-90f0-4646-9fe1-24a5375b4695','送邊將','李頻','唐','唐诗','tang','','[]','防秋戎馬恐來奔，詔發將軍出雁門。',64,'全唐诗/poet.tang.32000.json','["防秋戎馬恐來奔，詔發將軍出雁門。", "遙領短兵登隴首，獨橫長劒向河源。", "悠揚落日黃雲動，蒼莽陰風白草翻。", "若縱干戈更深入，應聞收得到崑崙。"]'),
('05e62bae-2725-4214-b748-0c1d2a95b35a','太和公主還宮','李頻','唐','唐诗','tang','','[]','天驕發使犯邊塵，漢將推功遂奪親。',64,'全唐诗/poet.tang.32000.json','["天驕發使犯邊塵，漢將推功遂奪親。", "離亂應無初去貌，死生難有却回身。", "禁花半老曾攀樹，宮女多非舊識人。", "重上鳳樓追故事，幾多愁思向青春。"]'),
('213d56b8-731e-457b-86a0-8028e4b5b296','將赴黔州先寄本府中丞','李頻','唐','唐诗','tang','','[]','八月瞿塘到底翻，孤舟上得已銷魂。',64,'全唐诗/poet.tang.32000.json','["八月瞿塘到底翻，孤舟上得已銷魂。", "幕中職罷猶趨府，闕下官成未謝恩。", "丹嶂聳空無過鳥，青林覆水有垂猿。", "感知肺腑終難說，從此辭歸便掃門。"]'),
('728a6ee3-4675-4f41-9241-869bab7b7378','和友人下第北遊感懷','李頻','唐','唐诗','tang','','[]','聖代爲儒可致身，誰知又別五陵春。',64,'全唐诗/poet.tang.32000.json','["聖代爲儒可致身，誰知又別五陵春。", "青門獨出空歸鳥，紫陌相逢盡醉人。", "江島去尋垂釣遠，塞山來見舉頭頻。", "且須共漉邊城酒，何必陶家有白綸。"]'),
('855d07f6-c3dd-4db9-8826-8f4c52ae78ae','樂遊原春望','李頻','唐','唐诗','tang','','[]','五陵佳氣晚氛氳，霸業雄圖勢自分。',64,'全唐诗/poet.tang.32000.json','["五陵佳氣晚氛氳，霸業雄圖勢自分。", "秦地山河連楚塞，漢家宮殿入青雲。", "未央樹色春中見，長樂鐘聲月下聞。", "無那楊華起愁思，滿天飄落雪紛紛。"]'),
('36b9a0b2-efa7-4f59-9fb8-d1eb9a6ac491','黃雀行','李頻','唐','唐诗','tang','','[]','欲竊高倉集御河，翩翩疑渡畏秋波。',64,'全唐诗/poet.tang.32000.json','["欲竊高倉集御河，翩翩疑渡畏秋波。", "朱宮晚樹侵鶯語，畫閣香簾奪燕窠。", "疎影暗棲寒露重，空城飢噪暮煙多。", "誰令不解高飛去，破宅荒庭有網羅。"]'),
('18e362f7-6a68-4246-973c-5a42917ce8a6','長安寓居寄柏侍郎','李頻','唐','唐诗','tang','','[]','霜輕兩鬢欲相侵，愁緒無端不可尋。',64,'全唐诗/poet.tang.32000.json','["霜輕兩鬢欲相侵，愁緒無端不可尋。", "秦女紅妝空覓伴，郢郎白雪少知音。", "長亭古木春光老，太華青煙晚更深。", "獨向灞陵東北望，一封書寄萬重心。"]'),
('1365c1c9-e864-4920-ba10-d3815a59f6b7','春日思歸','李頻','唐','唐诗','tang','','[]','春情不斷若連環，一夕思歸鬢欲斑。',64,'全唐诗/poet.tang.32000.json','["春情不斷若連環，一夕思歸鬢欲斑。", "壯志未酬三尺劒，故鄉空隔萬重山。", "音書斷絕干戈後，親友相逢夢寐間。", "却羨浮雲與飛鳥，因風吹去又吹還。"]'),
('d811f847-2b34-492a-bcd5-4c7fce32d655','朔中即事','李頻','唐','唐诗','tang','','[]','關門南北雜戎夷，草木秋來即出師。',64,'全唐诗/poet.tang.32000.json','["關門南北雜戎夷，草木秋來即出師。", "落日風沙長暝早，窮冬雨雪轉春遲。", "山頭堠火孤明後，星外行人四絕時。", "自古邊功何不立，漢家中外自相疑。"]'),
('cfcd053a-1279-4ec4-a5f0-660acdc4be20','感懷獻門下相公','李頻','唐','唐诗','tang','','[]','誰云郎選不由詩，上相憐才積有時。',64,'全唐诗/poet.tang.32000.json','["誰云郎選不由詩，上相憐才積有時。", "却是龍鍾到門晚，終非稽古致身遲。", "謀將郡印歸難遂，讀著家書坐欲癡。", "日望南宮看列宿，迢迢婺女與鄉比。"]'),
('d00b15a6-0ff1-41f2-9809-d3e0d5f169ab','贈長城庾將軍','李頻','唐','唐诗','tang','','[]','初年三十拜將軍，近代英雄獨未聞。',64,'全唐诗/poet.tang.32000.json','["初年三十拜將軍，近代英雄獨未聞。", "向國報恩心比石，辭天作鎮氣凌雲。", "逆風走馬貂裘卷，望塞懸弧雁陣分。", "定擁節麾從此去，安西大破犬戎羣。"]'),
('7faa7ba0-8ac0-4161-a239-1ea27a742bf1','浙東獻鄭大夫','李頻','唐','唐诗','tang','','[]','聖主東憂漲海濱，思移副相倚陶鈞。',64,'全唐诗/poet.tang.32000.json','["聖主東憂漲海濱，思移副相倚陶鈞。", "樓臺獨坐江山月，舟楫先行澤國春。", "遙想萬家開戶外，近聞羣盜竄諸鄰。", "幾時入去調元化，天下同爲堯舜人。"]'),
('dd0ed4a4-35c3-4073-a035-9de286a41877','鏡湖夜泊有懷','李頻','唐','唐诗','tang','','[]','廣水遙隄利物功，因思太守惠無窮。',64,'全唐诗/poet.tang.32000.json','["廣水遙隄利物功，因思太守惠無窮。", "自從版築興農隙，長與耕耘致歲豐。", "漲接星津流蕩漾，寬浮雲岫動虛空。", "想當戰國開時有，范蠡扁舟祗此中。"]'),
('1d9b7ddd-99dd-48aa-8a4f-4cc1453f868f','宣州獻從叔大夫','李頻','唐','唐诗','tang','','[]','清時選地任賢明，從此觀風輟尹京。',64,'全唐诗/poet.tang.32000.json','["清時選地任賢明，從此觀風輟尹京。", "日月天中辭洛邑，雲山江上領宣城。", "萬家閭井俱安寢，千里農桑竟起耕。", "聞說聖朝同漢代，已愁徵入拜公卿。"]'),
('509dffc1-7403-4bd8-832c-0c2c5dc0ba73','賀同年翰林從叔舍人知制誥','李頻','唐','唐诗','tang','','[]','仙禁何人躡近蹤，孔門先選得真龍。',64,'全唐诗/poet.tang.32000.json','["仙禁何人躡近蹤，孔門先選得真龍。", "別居雲路拋三省，專掌天書在九重。", "五色毫揮成渙汗，百寮班下獨從容。", "芳年貴盛誰爲比，鬱鬱青青嶽頂松。"]'),
('cf7b90af-99c1-45ea-a310-6427dbc01346','吳門別主人','李頻','唐','唐诗','tang','','[]','早晚更看吳苑月，小齋長憶落西窗。',32,'全唐诗/poet.tang.32000.json','["早晚更看吳苑月，小齋長憶落西窗。", "不知明夜誰家見，應照離人隔楚江。"]'),
('b9c15c44-c312-4f62-8b94-8b29728d2bd7','自黔中歸新安','李頻','唐','唐诗','tang','','[]','朝過春關辭北闕，暮參戎幕向南巴。',32,'全唐诗/poet.tang.32000.json','["朝過春關辭北闕，暮參戎幕向南巴。", "却將仙桂東歸去，江月相隨直到家。"]'),
('9bf0ebcf-f51c-4992-9fc2-da994b1709f0','奉和鄭薰相公','李頻','唐','唐诗','tang','','[]','三四株松匝草亭，便成彭澤柳爲名。',32,'全唐诗/poet.tang.32000.json','["三四株松匝草亭，便成彭澤柳爲名。", "蓮峰隱去難辭闕，滻水朝回與出城。"]'),
('af3d8be3-6769-4323-a143-2cf1abd75a5a','及第後還家過峴嶺','李頻','唐','唐诗','tang','','[]','魏馱山前一朵花，嶺西更有幾千家。',32,'全唐诗/poet.tang.32000.json','["魏馱山前一朵花，嶺西更有幾千家。", "石斑魚鮓香衝鼻，淺水沙田飯遶牙。"]'),
('32fe510a-b564-44ec-a96c-bb030d00dc26','春日旅舍','李頻','唐','唐诗','tang','','[]','未識東西南北路，青春白日坐銷難。',32,'全唐诗/poet.tang.32000.json','["未識東西南北路，青春白日坐銷難。", "如何一別故園後，五度花開五處看。"]'),
('bf08652f-2676-4b32-aa0b-06e2e2598360','過長江傷賈島','李頻','唐','唐诗','tang','','["\u957f\u6c5f"]','忽從一宦遠流離，無罪無人子細知。',32,'全唐诗/poet.tang.32000.json','["忽從一宦遠流離，無罪無人子細知。", "到得長江聞杜宇，想君魂魄也相隨。"]'),
('2d1b277a-e957-4239-a463-48f51006ce9e','自遣','李頻','唐','唐诗','tang','','[]','永擬東歸把釣絲，將行忽起半心疑。',32,'全唐诗/poet.tang.32000.json','["永擬東歸把釣絲，將行忽起半心疑。", "青雲道是不平地，還有平人上得時。"]'),
('242b5624-6d24-4343-a9c9-c454ab4ccea1','寄曹鄴','李頻','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','終南山是枕前雲，禁鼓無因曉夜聞。',32,'全唐诗/poet.tang.32000.json','["終南山是枕前雲，禁鼓無因曉夜聞。", "朝客秋來不朝日，曲江西岸去尋君。"]'),
('2c13d4be-6e7b-479c-acef-bc6bf9bc3152','述懷','李頻','唐','唐诗','tang','','[]','望月疑無得桂緣，春天又待到秋天。',32,'全唐诗/poet.tang.32000.json','["望月疑無得桂緣，春天又待到秋天。", "杏花開與槐花落，愁去愁來過幾年。"]'),
('a464a5e1-e2de-4983-a0b8-15959fcd5918','客洛酬劉駕','李頻','唐','唐诗','tang','','[]','浮世總應相送老，共君偏更遠行多。',32,'全唐诗/poet.tang.32000.json','["浮世總應相送老，共君偏更遠行多。", "此回不似前回別，聽盡離歌逐櫂歌。"]'),
('587da2a0-98fd-4e9d-8aa7-0997e703e274','題釣臺障子','李頻','唐','唐诗','tang','','[]','君家盡是我家山，嚴子前臺枕古灣。',32,'全唐诗/poet.tang.32000.json','["君家盡是我家山，嚴子前臺枕古灣。", "却把釣竿終不可，幾時入海得魚還。"]'),
('f44ae051-cd72-4228-ab45-387873ef7048','題陽山顧煉師草堂','李頻','唐','唐诗','tang','','[]','若到當時上升處，長生何事後無人。',32,'全唐诗/poet.tang.32000.json','["若到當時上升處，長生何事後無人。", "前峰自去種松子，坐見年來取茯神。"]'),
('b39d401d-2b24-4334-8dbc-6f9b900a1ad9','聞金吾妓唱梁州','李頻','唐','唐诗','tang','','[]','聞君一曲古梁州，驚起黃雲塞上愁。',32,'全唐诗/poet.tang.32000.json','["聞君一曲古梁州，驚起黃雲塞上愁。", "秦女樹前花正發，北風吹落滿城秋。"]'),
('59b65da7-9042-46ab-900c-208887bd5d77','游蜀回簡友人','李頻','唐','唐诗','tang','','[]','別來十二月，去到漏天邊。',24,'全唐诗/poet.tang.32000.json','["別來十二月，去到漏天邊。", "不是因逢閏，還應是隔年。"]'),
('ac8b41f2-0397-4224-acf8-aad23eafbaf7','贈涇州王侍御','李頻','唐','唐诗','tang','','[]','一旦天書下紫微，三年旌斾隴雲飛。',32,'全唐诗/poet.tang.32000.json','["一旦天書下紫微，三年旌斾隴雲飛。", "塞門無事春空到，邊草青青戰馬肥。"]'),
('f461e230-d7d0-4ca4-affc-0c04e1f023c1','夏日宿秘書姚監宅','李頻','唐','唐诗','tang','','[]','貴宅多嘉樹，先秋有好風。',48,'全唐诗/poet.tang.32000.json','["貴宅多嘉樹，先秋有好風。", "情閑離闕下，夢野在山中。", "露色浮寒瓦，螢光墮暗叢。", "聽吟麗句盡，河漢任西東。"]'),
('445828e8-03de-470d-9d49-058d069224cf','過嵩陰隱者','李頻','唐','唐诗','tang','','[]','當門看少室，倚杖復披衣。',48,'全唐诗/poet.tang.32000.json','["當門看少室，倚杖復披衣。", "每日醒還醉，無人是與非。", "架書抽讀亂，庭果摘嘗稀。", "獨有江南客，思家未得歸。"]'),
('781eb8bd-dd5f-41a6-b861-e5dcd64ceb4f','留別山家','李頻','唐','唐诗','tang','','[]','閑門不易求，半月在林丘。',48,'全唐诗/poet.tang.32000.json','["閑門不易求，半月在林丘。", "已與山水別，難爲花木留。", "孤懷歸靜夜，遠會隔高秋。", "莫道無言去，冥心在重遊。"]'),
('95842962-291c-4806-a919-d6a1f724fe76','送人遊吳','李頻','唐','唐诗','tang','','[]','楚田開雪後，草色與君看。',48,'全唐诗/poet.tang.32000.json','["楚田開雪後，草色與君看。", "積水浮春氣，深山滯雨寒。", "毗陵孤月出，建業一鍾殘。", "爲把鄉書去，因收別淚難。"]'),
('a2288d47-90d0-45f9-b234-7be5b71baa06','東渭橋晚眺','李頻','唐','唐诗','tang','','[]','秦地有吳洲，千檣渭曲頭。',48,'全唐诗/poet.tang.32000.json','["秦地有吳洲，千檣渭曲頭。", "人當返照立，水徹故鄉流。", "落第春難過，窮途日易愁。", "誰知橋上思，萬里在江樓。"]'),
('a32b1d71-503b-40fe-815f-34f57634b1fd','送延陵韋少府','李頻','唐','唐诗','tang','','[]','延陵稱貴邑，季子有高蹤。',48,'全唐诗/poet.tang.32000.json','["延陵稱貴邑，季子有高蹤。", "古跡傳多代，仙山管幾峰。", "微泉聲小雨，異木色深冬。", "去畢三年秩，新詩篋不容。"]'),
('32eb0c05-87d7-4ae6-93c9-9591053781d1','淮南送友人歸滄州','李頻','唐','唐诗','tang','','[]','風色忽西轉，坐爲千里分。',48,'全唐诗/poet.tang.32000.json','["風色忽西轉，坐爲千里分。", "高帆背楚落，寒日逆淮曛。", "斷燒緣喬木，盤鵰隱片雲。", "鄉關百戰地，歸去始休軍。"]'),
('90a8ce29-80e0-4b64-816c-e08bed5fcdc5','夏日題盩厔友人書齋','李頻','唐','唐诗','tang','','[]','脩竹齊高樹，書齋竹樹中。',48,'全唐诗/poet.tang.32000.json','["脩竹齊高樹，書齋竹樹中。", "四時無夏氣，三伏有秋風。", "黑處巢幽鳥，陰來呌候蟲。", "牕西太白雪，萬仞在遙空。"]'),
('fe92f8bf-6625-4176-9181-87b6daefff0f','尋山','李頻','唐','唐诗','tang','','[]','一逕入雙崖，初疑有幾家。',48,'全唐诗/poet.tang.32000.json','["一逕入雙崖，初疑有幾家。", "行窮人不見，坐久日空斜。", "石上生靈草，泉中落異花。", "終須結茅屋，向此學餐霞。"]'),
('976867e2-eff6-4564-aedd-e18746e40412','送元遂上人歸錢唐','李頻','唐','唐诗','tang','','[]','白衣遊帝鄉，已得事空王。',48,'全唐诗/poet.tang.32000.json','["白衣遊帝鄉，已得事空王。", "却返湖山寺，高禪水月房。", "雨中過嶽黑，秋後宿船涼。", "回顧秦人語，他生會別方。"]'),
('1654f5f8-7d7a-4f77-ac54-547190adb31b','貽友人喻坦之','李頻','唐','唐诗','tang','','[]','從容心自切，飲水勝銜杯。',48,'全唐诗/poet.tang.32000.json','["從容心自切，飲水勝銜杯。", "共在山中長，相隨闕下來。", "脩身空有道，取事各無媒。", "不信昇平代，終遺草澤才。"]'),
('98f136cd-d526-494e-9e12-4e8d214c1050','送友人往振武','李頻','唐','唐诗','tang','','[]','風沙遙見說，道路替君愁。',48,'全唐诗/poet.tang.32000.json','["風沙遙見說，道路替君愁。", "磧夜星垂地，雲明火上樓。", "征鴻辭塞雪，戰馬識邊秋。", "不共將軍語，何因有去留。"]'),
('a5bab627-dacc-490a-9ef4-f8bd1e531aed','賦得長城斑竹杖','李頻','唐','唐诗','tang','','[]','秦興版築時，翦伐不知誰。',48,'全唐诗/poet.tang.32000.json','["秦興版築時，翦伐不知誰。", "異代餘根在，幽人得手持。", "細看生古意，閑倚動邊思。", "莫作鳩形並，空將鶴髪期。"]'),
('d6877c51-bc71-43cb-862c-44bcd0aefe71','送德清喻明府','李頻','唐','唐诗','tang','','[]','棹返霅溪雲，仍參舊使君。',48,'全唐诗/poet.tang.32000.json','["棹返霅溪雲，仍參舊使君。", "州傳多古跡，縣記是新文。", "水柵橫舟閉，湖田立木分。", "但如詩思苦，爲政即超羣。"]'),
('d290779b-b471-47cc-a54d-c0a273a0fb71','送薛能少府任盩厔','李頻','唐','唐诗','tang','','[]','不才甘下第，君子蹇何重。',48,'全唐诗/poet.tang.32000.json','["不才甘下第，君子蹇何重。", "相送昆明岸，同看太白峰。", "數瓢留頃刻，殘照迫從容。", "好去煙霞縣，仙人有舊蹤。"]'),
('bd4113da-c577-4737-9506-2c4e6216e973','送許壽下第歸東山','李頻','唐','唐诗','tang','','[]','吾君設禮闈，誰合學忘機。',48,'全唐诗/poet.tang.32000.json','["吾君設禮闈，誰合學忘機。", "却是高人起，難爲下第歸。", "出關心縱野，避世事終稀。", "莫更今秋夕，相思望少微。"]'),
('e7ebd106-c322-4bd9-8bd2-5882ecb5be8c','冬夜酬范秘書','李頻','唐','唐诗','tang','','[]','九衢行一匝，不敢入他門。',48,'全唐诗/poet.tang.32000.json','["九衢行一匝，不敢入他門。", "累日無餘事，通宵得至言。", "命嗟清世蹇，春覺閏冬暄。", "翻覆吟佳句，何酬國士恩。"]'),
('40a6b1bd-cca2-481e-80a5-a4bd4e123674','送陸肱尉江夏','李頻','唐','唐诗','tang','','[]','如何執簡去，便作挂帆期。',48,'全唐诗/poet.tang.32000.json','["如何執簡去，便作挂帆期。", "澤國三春早，江天落日遲。", "縣人齊候處，洲鳥欲飛時。", "免褐方三十，青雲豈白髭。"]'),
('e4a0932d-af0b-45a3-bb19-1f9a805e893d','漢上送人西歸','李頻','唐','唐诗','tang','','[]','幾作西歸夢，因爲愴別心。',48,'全唐诗/poet.tang.32000.json','["幾作西歸夢，因爲愴別心。", "野銜天去盡，山夾漢來深。", "疊浪翻殘照，高帆引片陰。", "空留相贈句，畢我白頭吟。"]'),
('a6a0cb5e-d8f1-4990-82ce-a7a2db1463c5','蜀中逢友人','李頻','唐','唐诗','tang','','[]','自古有行役，誰人免別家。',48,'全唐诗/poet.tang.32000.json','["自古有行役，誰人免別家。", "相歡猶陌上，一醉任天涯。", "積疊山藏蜀，潺湲水遶巴。", "他年復何處，共說海棠花。"]'),
('cde2d1ee-925d-47d6-b2c4-d91f61567233','寄范評事','李頻','唐','唐诗','tang','','[]','行坐不相遺，轅門載筆時。',48,'全唐诗/poet.tang.32000.json','["行坐不相遺，轅門載筆時。", "雅知難更遇，舊分合長思。", "夢即重尋熟，書常轉達遲。", "山齋終擬到，何日遂心期。"]'),
('475cd9a9-a45e-4373-8751-c912c34b8ecc','南遊過湘漢即事寄友人','李頻','唐','唐诗','tang','','[]','南去遠駈逐，三湘五月行。',48,'全唐诗/poet.tang.32000.json','["南去遠駈逐，三湘五月行。", "巴山雪水下，楚澤火雲生。", "向野聊中飯，乘涼探暮程。", "離懷不可說，已迫峽猿聲。"]'),
('2903b681-6554-43e0-aca0-c47ff4d92b5d','送許渾侍御赴潤州','李頻','唐','唐诗','tang','','[]','家山近石頭，遂意恣東遊。',48,'全唐诗/poet.tang.32000.json','["家山近石頭，遂意恣東遊。", "祖席離烏府，歸帆轉蜃樓。", "陰氛出海散，落月向潮流。", "別有爲霖日，孤雲未自由。"]'),
('2670d667-46e7-4c1e-ba5c-66545ca5ea78','喜友人厲圖南及第','李頻','唐','唐诗','tang','','[]','相憂過己切，相賀似身榮。',48,'全唐诗/poet.tang.32000.json','["相憂過己切，相賀似身榮。", "心達無前後，神交共死生。", "承家吾子事，登第世人情。", "未有通儒術，明時道不行。"]'),
('38f89f90-993d-42f2-929b-86f13c94cc0b','送友人下第歸越','李頻','唐','唐诗','tang','','[]','歸意隨流水，江湖共在東。',48,'全唐诗/poet.tang.32000.json','["歸意隨流水，江湖共在東。", "山陰何處去，草際片帆通。", "雨色春愁裏，潮聲曉夢中。", "雖爲半年客，便是往來鴻。"]'),
('9391df0b-42e8-4911-a908-611f0bd2cb81','寄友人','李頻','唐','唐诗','tang','','[]','一別一相見，須臾老此生。',48,'全唐诗/poet.tang.32000.json','["一別一相見，須臾老此生。", "客衣寒後薄，山思夜深清。", "詩近吟何句，髭新白幾莖。", "路岐如昨日，來往夢分明。"]'),
('db446d59-91e0-41d2-bd74-08d1cccc9875','送友人下第歸宛陵','李頻','唐','唐诗','tang','','[]','天涯長戀親，闕下獨傷春。',48,'全唐诗/poet.tang.32000.json','["天涯長戀親，闕下獨傷春。", "擬住還求己，須歸不爲身。", "臨岐仍犯雪，挂席始離塵。", "共泣東風別，同爲滄海人。"]'),
('efad0020-1e72-4b9c-8188-3c837774eb00','秋夜對月寄鳯翔范書記','李頻','唐','唐诗','tang','','[]','月過秋霖後，光應夜夜清。',48,'全唐诗/poet.tang.32000.json','["月過秋霖後，光應夜夜清。", "一回相憶起，幾度獨吟行。", "河漢東西直，山川遠近明。", "寸心遙往處，新有雁來聲。"]'),
('83abed08-d69f-4875-97b5-29655761f6e5','送孫明秀才往潘州訪韋卿','李頻','唐','唐诗','tang','','[]','北鳥飛不到，北人今去遊。',48,'全唐诗/poet.tang.32000.json','["北鳥飛不到，北人今去遊。", "天涯浮瘴水，嶺外問潘州。", "草木春冬茂，猿猱日夜愁。", "定知遷客淚，應只對君流。"]'),
('8aefb57b-9047-481e-bcdb-8f90539babd4','八月十五夜對月','李頻','唐','唐诗','tang','','[]','陰盛此宵中，多爲雨與風。',48,'全唐诗/poet.tang.32000.json','["陰盛此宵中，多爲雨與風。", "坐無雲雨至，看與雪霜同。", "抱濕離遙海，傾寒向逈空。", "年年不可值，還似命難通。"]'),
('2ce0030b-36a3-4228-a89e-dd2e6f249d44','及第後歸','李頻','唐','唐诗','tang','','[]','家臨浙水傍，岸對買臣鄉。',48,'全唐诗/poet.tang.32000.json','["家臨浙水傍，岸對買臣鄉。", "縱棹隨歸鳥，乘潮向夕陽。", "苦吟身得雪，甘意鬢成霜。", "況此年猶少，酬知足自強。"]'),
('00c9e09d-924f-4a1d-958f-e2520e17fce5','過巫峽','李頻','唐','唐诗','tang','','[]','擁棹向驚湍，巫峰直上看。',48,'全唐诗/poet.tang.32000.json','["擁棹向驚湍，巫峰直上看。", "削成從水底，聳出在雲端。", "暮雨晴時少，啼猿渴下難。", "一聞神女去，風竹掃空壇。"]'),
('59a87e11-d975-40e1-bbd8-b8455f77d776','送友人往太原','李頻','唐','唐诗','tang','','[]','離亭聊把酒，此路徹邊頭。',48,'全唐诗/poet.tang.32000.json','["離亭聊把酒，此路徹邊頭。", "草白雁來盡，時清人去遊。", "汾河流晉地，塞雪滿幷州。", "別後相思夜，空看北斗愁。"]'),
('aa179ade-0b77-45de-a022-f51385e5b914','旅懷','李頻','唐','唐诗','tang','','[]','萬里共心論，徒言吾道存。',48,'全唐诗/poet.tang.32000.json','["萬里共心論，徒言吾道存。", "奉親無別業，謁帝有何門。", "水宿驚濤浦，山行落葉村。", "長安長夢去，欹枕即聞猿。"]'),
('649279b6-2a63-4a6c-9605-c2a7bd348908','送裴御史赴湖南','李頻','唐','唐诗','tang','','[]','關門鳥道中，飛傳復乘驄。',48,'全唐诗/poet.tang.32000.json','["關門鳥道中，飛傳復乘驄。", "暮雪離秦甸，春雲入楚宮。", "平蕪天共闊，積水地多空。", "使府懸帆去，能消幾日風。"]'),
('ad80de49-e92f-42af-825a-d4ddf3be6b4f','送姚郜先輩赴汝州辟','李頻','唐','唐诗','tang','','[]','行李事寒天，東來聘禮全。',48,'全唐诗/poet.tang.32000.json','["行李事寒天，東來聘禮全。", "州當定鼎處，人去偃戈年。", "雷雨依嵩嶺，桑麻接楚田。", "遙知清夜作，不是借戎篇。"]'),
('c1d38741-4714-4c25-b6d1-414368e2848e','初離黔中泊江上','李頻','唐','唐诗','tang','','[]','去去把青桂，平生心不違。',48,'全唐诗/poet.tang.32000.json','["去去把青桂，平生心不違。", "更蒙蓮府辟，兼脫布衣歸。", "霽岳明殘雪，清波漾落暉。", "無窮幽鳥戲，時向棹前飛。"]'),
('e301fea5-a1b2-42dd-a30a-6b846812d452','黔中酬同院韋判官','李頻','唐','唐诗','tang','','[]','平生同所爲，相遇偶然遲。',48,'全唐诗/poet.tang.32000.json','["平生同所爲，相遇偶然遲。", "各著青袍後，無歸白社期。", "江流來絕域，府地管諸夷。", "聖代都無事，從公且賦詩。"]'),
('2dc27cfb-5770-4d67-a100-9e63ced8edac','和范秘書襄陽舊遊','李頻','唐','唐诗','tang','','[]','聽話揚帆興，初從峴首還。',48,'全唐诗/poet.tang.32000.json','["聽話揚帆興，初從峴首還。", "高吟入白浪，遙坐看青山。", "枯木猿啼爽，寒汀鶴步閑。", "秋來關去夢，幾夜度商顏。"]'),
('d0b8b184-515c-4b9f-b283-cfcf8e93f3b4','秋夜山中思歸送友人','李頻','唐','唐诗','tang','','[]','蕭條對秋色，相憶在雲泉。',48,'全唐诗/poet.tang.32000.json','["蕭條對秋色，相憶在雲泉。", "木落病身起，潮平歸思懸。", "涼鐘山頂寺，暝火渡頭船。", "此地非吾土，淹留又一年。"]'),
('4c4f2514-1c28-41b6-961f-d708e69a5190','自黔中東歸旅次淮上','李頻','唐','唐诗','tang','','[]','行旅本同愁，黔吳復阻脩。',48,'全唐诗/poet.tang.32000.json','["行旅本同愁，黔吳復阻脩。", "半年方中路，窮節到孤舟。", "夕靄垂陰野，晨光動積流。", "家山一夜夢，便是昔年遊。"]'),
('7cee4a0d-c06c-4664-aaee-2ed49aa28720','江夏春感舊','李頻','唐','唐诗','tang','','[]','東風出海門，處處動林園。',48,'全唐诗/poet.tang.32000.json','["東風出海門，處處動林園。", "澤國雪霜少，沙汀花木繁。", "暖魚依水淺，晴雁入空翻。", "何處陽和力，生萍不駐根。"]'),
('c10beffc-d1cc-4d38-a5dd-55ac9af9d5fb','眉州別李使君','李頻','唐','唐诗','tang','','[]','回首雪峰前，朱門心杳然。',48,'全唐诗/poet.tang.32000.json','["回首雪峰前，朱門心杳然。", "離人自嗚咽，流水莫潺湲。", "毒草通蠻徼，秋林近漏天。", "一生從此去，五字有誰憐。"]'),
('b6e8492a-1ade-4dee-b3c8-44a9114b9ee2','送許棠及第歸宣州','李頻','唐','唐诗','tang','','[]','高科終自致，志業信如神。',48,'全唐诗/poet.tang.32000.json','["高科終自致，志業信如神。", "待得逢公道，由來合貴身。", "秋歸方覺好，舊夢始知真。", "更想青山宅，誰爲後主人。"]'),
('8ed9f6c6-1475-4773-85bd-895af11dc8e3','黔中罷職將泛江東','李頻','唐','唐诗','tang','','[]','黔中初罷職，薄俸亦無殘。',48,'全唐诗/poet.tang.32000.json','["黔中初罷職，薄俸亦無殘。", "舉目鄉關遠，攜家旅食難。", "野梅將雪競，江月與沙寒。", "兩鬢愁應白，何勞把鏡看。"]'),
('7745765e-daac-4ed7-95b3-09aee2dc42d1','長安書事寄所知','李頻','唐','唐诗','tang','','[]','帝里本無名，端居有道情。',48,'全唐诗/poet.tang.32000.json','["帝里本無名，端居有道情。", "睡魂春夢斷，書興晚窗明。", "老擬歸何處，閑應過此生。", "江湖終一日，拜別便東行。"]'),
('fbb6b8b3-643b-466d-b2d1-0a1484d5b440','酬姚覃','李頻','唐','唐诗','tang','','[]','不見又相招，何曾訴寂寥。',48,'全唐诗/poet.tang.32000.json','["不見又相招，何曾訴寂寥。", "醉眠春草長，吟坐夜燈銷。", "淚墮思山切，身歸轉路遙。", "年年送別處，楊柳少垂條。"]'),
('811610ae-4a7b-4a67-bb42-96bcc99201ec','春日鄜州贈裴居言','李頻','唐','唐诗','tang','','[]','雖將身佐幕，出入似閑居。',48,'全唐诗/poet.tang.32000.json','["雖將身佐幕，出入似閑居。", "草色長相待，山情信不疎。", "燈前春睡足，酒後夜寒餘。", "筆硯時時近，終非署簿書。"]'),
('04cd2cb2-f710-4a3f-9cc3-20bc0c800eed','送于生入蜀','李頻','唐','唐诗','tang','','[]','家吳聞入蜀，道路頗乖離。',48,'全唐诗/poet.tang.32000.json','["家吳聞入蜀，道路頗乖離。", "一第何多難，都城可少知。", "江山非久適，命數未終奇。", "況又將冤抱，經春杜魄隨。"]'),
('8f2a358f-88a2-4052-a813-55e5133d48ca','送許棠歸涇縣作尉','李頻','唐','唐诗','tang','','[]','青桂復青袍，一歸榮一高。',48,'全唐诗/poet.tang.32000.json','["青桂復青袍，一歸榮一高。", "縣人齊下拜，邑宰共分曹。", "遶郭看秧插，尋街聽繭繅。", "封侯萬里者，燕頷乃徒勞。"]'),
('65b6ee5f-c4e4-44a0-b547-fd1acc791f53','友人話別','李頻','唐','唐诗','tang','','[]','論交雖不蚤，話別且相親。',48,'全唐诗/poet.tang.32000.json','["論交雖不蚤，話別且相親。", "除却棲禪客，誰非南陌人。", "半生都返性，終老擬安貧。", "願入白雲社，高眠自致身。"]'),
('afff0c17-0fe4-45af-85f8-5ff090244a25','山居','李頻','唐','唐诗','tang','','[]','欲出窮吾道，東西自未能。',48,'全唐诗/poet.tang.32000.json','["欲出窮吾道，東西自未能。", "捲書唯對鶴，開畫獨留僧。", "落葉和雲掃，秋山共月登。", "何年石上水，夜夜滴高層。"]'),
('c58e9000-e311-4750-9924-625c1616b78d','寄范郎中','李頻','唐','唐诗','tang','','[]','蔾杖山中出，吟詩對范家。',48,'全唐诗/poet.tang.32000.json','["蔾杖山中出，吟詩對范家。", "相知從海嶠，寄食向京華。", "名宦成何報，清眸未縱賒。", "臨邛夢來往，雨雪滿襃斜。"]'),
('6e426816-c58c-409c-914f-a9e167197c50','書懷','李頻','唐','唐诗','tang','','[]','宦途從不問，身事覺無差。',48,'全唐诗/poet.tang.32000.json','["宦途從不問，身事覺無差。", "華髪初生女，滄洲未有家。", "却閑思洞穴，終老曠桑麻。", "別訪棲禪侶，相期語劫沙。"]'),
('0b54225c-1204-42ba-a6a7-2d1d3377d78c','越中行','李頻','唐','唐诗','tang','','[]','越國臨滄海，芳洲復暮晴。',48,'全唐诗/poet.tang.32000.json','["越國臨滄海，芳洲復暮晴。", "湖通諸浦白，日隱亂峰明。", "野宿多無定，閑遊免有情。", "天台聞不遠，終到石橋行。"]'),
('f59fb2b1-46e1-4303-8e3b-25d3ab8c5b9c','春日南遊寄浙東許同年','李頻','唐','唐诗','tang','','[]','孤帆處處宿，不問是誰家。',48,'全唐诗/poet.tang.32000.json','["孤帆處處宿，不問是誰家。", "南國平蕪遠，東風細雨斜。", "旅懷多寄酒，寒意欲留花。", "更想前途去，茫茫滄海涯。"]'),
('d9732635-cd42-42c9-b073-32062a46b175','明州江亭夜別段秀才','李頻','唐','唐诗','tang','','[]','離亭向水開，時候復蒸梅。',48,'全唐诗/poet.tang.32000.json','["離亭向水開，時候復蒸梅。", "霹靂燈燭滅，蒹葭風雨來。", "京關雖共語，海嶠不同回。", "莫爲蓴鱸美，天涯滯爾才。"]'),
('c9d08e81-f134-4c5a-ae77-2140ab264fdc','臨岐留別相知','李頻','唐','唐诗','tang','','[]','百歲竟何事，一身長遠遊。',48,'全唐诗/poet.tang.32000.json','["百歲竟何事，一身長遠遊。", "行行將近老，處處不離愁。", "世路多相取，權門不自投。", "難爲此時別，欲別願人留。"]'),
('ed2cb24f-c40e-4b8e-8800-35535a728cd6','鄂渚湖上即事','李頻','唐','唐诗','tang','','[]','杜門聊自適，湖水在窗間。',48,'全唐诗/poet.tang.32000.json','["杜門聊自適，湖水在窗間。", "縱得滄洲去，無過白日閑。", "多慵空好道，少賤早凋顏。", "獨有東山月，依依自往還。"]'),
('35a92d34-aa42-45c5-a873-df372c6fe9a6','辭夏口崔尚書','李頻','唐','唐诗','tang','','[]','一飯仍難受，依仁況一年。',48,'全唐诗/poet.tang.32000.json','["一飯仍難受，依仁況一年。", "終期身可報，不擬骨空鐫。", "城晚風高角，江春浪起船。", "同來棲止地，獨去塞鴻前。"]'),
('ceac9e2b-a485-4fc0-aa13-b8688eab8e83','秦原早望','李頻','唐','唐诗','tang','','[]','一忝鄉書薦，長安未得回。',48,'全唐诗/poet.tang.32000.json','["一忝鄉書薦，長安未得回。", "年光逐渭水，春色上秦臺。", "燕掠平蕪去，人衝細雨來。", "東風生故里，又過幾花開。"]'),
('5621e8e9-0952-4551-87a6-80c77c8e0d86','送友人之揚州','李頻','唐','唐诗','tang','','[]','一別長安後，晨征便信雞。',48,'全唐诗/poet.tang.32000.json','["一別長安後，晨征便信雞。", "河聲入峽急，地勢出關低。", "綠樹叢垓下，青蕪闊楚西。", "路長知不惡，隨處得詩題。"]'),
('a7d8618e-edb9-40c7-93dd-c8bfdd1f4758','過四皓廟','李頻','唐','唐诗','tang','','[]','東西南北人，高跡自相親。',48,'全唐诗/poet.tang.32000.json','["東西南北人，高跡自相親。", "天下已歸漢，山中猶避秦。", "龍樓曾作客，鶴氅不爲臣。", "獨有千年後，青青廟木春。"]'),
('cb327c73-d247-444d-b4e1-57d96fa2b7a6','陝下懷歸','李頻','唐','唐诗','tang','','[]','故園何處在，零落五湖東。',48,'全唐诗/poet.tang.32000.json','["故園何處在，零落五湖東。", "日暮無來客，天寒有去鴻。", "大河冰徹塞，高嶽雪連空。", "獨夜懸歸思，迢迢永漏中。"]'),
('54d6ff00-d8c7-4a05-aca2-996635c0a6f1','送徐處士歸江南','李頻','唐','唐诗','tang','','[]','行行野雪薄，寒氣日通春。',48,'全唐诗/poet.tang.32000.json','["行行野雪薄，寒氣日通春。", "故國又芳草，滄江終白身。", "遊歸花落滿，睡起鳥啼新。", "莫惜閑書札，西來問旅人。"]'),
('61149c4d-2fc3-41db-8cb6-e4cca4cb1c8b','鄜州留別王從事','李頻','唐','唐诗','tang','','[]','相識未十日，相知如十年。',48,'全唐诗/poet.tang.32000.json','["相識未十日，相知如十年。", "從來易離別，此去忽留連。", "路險行衝雨，山高度隔天。", "難終清夜坐，更聽說安邊。"]'),
('7ac401fd-f53b-4f75-9d30-c6728cc7928e','長安夜懷','李頻','唐','唐诗','tang','','[]','匹馬西遊日，從吳又轉荆。',48,'全唐诗/poet.tang.32000.json','["匹馬西遊日，從吳又轉荆。", "風雷幾夜坐，山水半年行。", "夢永秋燈滅，吟餘曉露明。", "良時不我與，白髮向秦生。"]'),
('95d8500e-923d-4703-a6f2-e987a0520195','冬夜山中尋友','李頻','唐','唐诗','tang','','[]','何人山雪夜，相訪不相思。',48,'全唐诗/poet.tang.32000.json','["何人山雪夜，相訪不相思。", "若得長閑日，應無暫到時。", "葉寒凋欲盡，泉凍落還遲。", "即此天明去，重來未有期。"]'),
('92dc105b-1564-4ab7-9104-330b603e5a70','送劉山人歸洞庭','李頻','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','君逐雲山去，人間又絕蹤。',48,'全唐诗/poet.tang.32000.json','["君逐雲山去，人間又絕蹤。", "半湖乘早月，中路入疎鐘。", "秋盡草蟲急，夜深山雨重。", "平生心未已，豈得更相從。"]'),
('c84a5bc0-e95d-4857-86d6-fcc7a4490ced','古意','李頻','唐','唐诗','tang','','[]','白馬遊何處，青樓日正長。',48,'全唐诗/poet.tang.32000.json','["白馬遊何處，青樓日正長。", "鳳簫拋舊曲，鸞鏡嬾新妝。", "玄鳥深巢靜，飛花入戶香。", "雖非竇滔婦，錦字已成章。"]'),
('4d4e7603-41a1-416a-80e7-d0e7101feb17','避暑','李頻','唐','唐诗','tang','','[]','當暑憶歸林，陶家借柳陰。',48,'全唐诗/poet.tang.32000.json','["當暑憶歸林，陶家借柳陰。", "蟬從初伏噪，客向晚涼吟。", "白日欺玄鬢，滄江負素心。", "神仙倘有術，引我出幽岑。"]'),
('1c44a4a5-9419-4643-ae9c-ccb56fce9c7c','送吳秘書歸杭州','李頻','唐','唐诗','tang','','[]','爲客得從容，官清料復重。',48,'全唐诗/poet.tang.32000.json','["爲客得從容，官清料復重。", "海崖歸有業，天目近何峰。", "是處通春棹，無村不夜舂。", "馬卿夸貴達，還說返臨邛。"]'),
('38b6af91-b486-40b1-951e-97324e1346e1','中秋對月','李頻','唐','唐诗','tang','','[]','秋分一夜停，陰魄最晶熒。',48,'全唐诗/poet.tang.32000.json','["秋分一夜停，陰魄最晶熒。", "好是生滄海，徐看歷杳冥。", "層空疑洗色，萬怪想潛形。", "他夕無相類，晨雞不可聽。"]'),
('49ae4d35-35dd-4ea2-bf0d-57f599678643','八月上峽','李頻','唐','唐诗','tang','','[]','萬里巴江水，秋來滿峽流。',48,'全唐诗/poet.tang.32000.json','["萬里巴江水，秋來滿峽流。", "亂山無陸路，行客在孤舟。", "洶洶灘聲急，冥冥樹色愁。", "免爲三不弔，已白一生頭。"]'),
('d6a99bd7-88ad-4758-9a6b-8d0b1453e003','送狄明府赴九江','李頻','唐','唐诗','tang','','[]','字人修祖德，清白定聞傳。',48,'全唐诗/poet.tang.32000.json','["字人修祖德，清白定聞傳。", "匹馬從秦去，孤帆入楚懸。", "關中寒食雨，湖上暑衣天。", "四考兼重請，相知住幾年。"]'),
('475bd683-f6f5-4bde-9553-13feb6cccde9','陝下投姚諫議','李頻','唐','唐诗','tang','','[]','舊業在東鄙，西遊從楚荆。',48,'全唐诗/poet.tang.32000.json','["舊業在東鄙，西遊從楚荆。", "風雷幾夜坐，山水半年行。", "夢永秋燈滅，吟孤曉露明。", "前心若不遂，有耻却歸耕。"]'),
('ca375d52-f2f0-492a-ba97-9d79bc7f01c1','關東逢薛能','李頻','唐','唐诗','tang','','[]','何處不相思，相逢還有時。',48,'全唐诗/poet.tang.32000.json','["何處不相思，相逢還有時。", "交心如到老，會面未爲遲。", "苦學緣明代，勞生欲白髭。", "唯君一度別，便似見無期。"]'),
('5675e35e-2fcd-48a9-9f1a-6e5c5e1fa586','富春贈孫璐','李頻','唐','唐诗','tang','','[]','天柱與天目，曾棲絕頂房。',48,'全唐诗/poet.tang.32000.json','["天柱與天目，曾棲絕頂房。", "青雲求祿晚，白日坐家長。", "井氣通潮信，牕風引海涼。", "平生詩稱在，老達亦何妨。"]'),
('9014fcd2-6744-4d85-9d43-eee13952dc3c','送友人遊蜀','李頻','唐','唐诗','tang','','[]','東堂雖不捷，西去復何愁。',48,'全唐诗/poet.tang.32000.json','["東堂雖不捷，西去復何愁。", "蜀馬知歸路，巴山似舊遊。", "星臨劒閣動，花落錦江流。", "鼓吹青林下，時聞祭武侯。"]'),
('7163e631-cc74-4ee0-9a16-d4ec2f587e08','夏日盩厔郊居寄姚少府','李頻','唐','唐诗','tang','','[]','古木有清陰，寒泉有下深。',48,'全唐诗/poet.tang.32000.json','["古木有清陰，寒泉有下深。", "蟬從初伏噪，客向晚涼吟。", "白日欺玄鬢，滄江負素心。", "甚思中夜話，何路許相尋。"]'),
('de4a29bf-da79-485d-8e9f-ab9fb9ef5b0f','送胡休處士歸湘江','李頻','唐','唐诗','tang','','[]','見說湘江切，長愁有去時。',48,'全唐诗/poet.tang.32000.json','["見說湘江切，長愁有去時。", "江湖秋涉遠，雷雨夜眠遲。", "舊業多歸興，空山盡老期。", "天寒一瓢酒，落日醉留誰。"]'),
('f15d94a9-d748-4057-838c-9a625c32e4bc','峽州送清徹上人歸浙西','李頻','唐','唐诗','tang','','[]','風濤幾千里，歸路半乘舟。',48,'全唐诗/poet.tang.32000.json','["風濤幾千里，歸路半乘舟。", "此地難相遇，何人更共遊。", "坐經嵩頂夏，行值洛陽秋。", "到寺安禪夕，江雲滿石樓。"]'),
('21dd6cc6-2ce5-4f63-93f9-94c6a15d851c','送僧入天台','李頻','唐','唐诗','tang','','[]','一錫隨緣赴，天台又去登。',48,'全唐诗/poet.tang.32000.json','["一錫隨緣赴，天台又去登。", "長亭舊別路，落日獨行僧。", "夜燒山何處，秋帆浪幾層。", "他時授巾拂，莫爲老無能。"]'),
('888f73cd-938c-4cae-813c-c80573a32ae5','回山後寄范酇先輩','李頻','唐','唐诗','tang','','[]','高樓會月夜，北雁向南分。',48,'全唐诗/poet.tang.32000.json','["高樓會月夜，北雁向南分。", "留住經春雪，辭來見夏雲。", "遙空江不極，絕頂日難曛。", "一與山僧坐，無因得議文。"]'),
('5166c587-ee47-47dd-a475-e2c8136a54fa','長安送友人東歸','李頻','唐','唐诗','tang','','[]','白社思歸處，青門見去人。',48,'全唐诗/poet.tang.32000.json','["白社思歸處，青門見去人。", "鄉遙茂苑樹，路入廣陵塵。", "海日潮浮曉，湖山雪露春。", "猶期來帝里，未是得閑人。"]'),
('d812c37a-fa93-445b-8fff-dd0ee1a464d7','深秋過源宗上人房','李頻','唐','唐诗','tang','','[]','到日值搖落，相留山舍空。',48,'全唐诗/poet.tang.32000.json','["到日值搖落，相留山舍空。", "微寒生夜半，積雨向秋終。", "度講多來雁，經禪少候蟲。", "方從聽話後，不省在愁中。"]'),
('9abf4c9f-f569-41be-94c8-1e6e825157ec','秋日登山閣','李頻','唐','唐诗','tang','','[]','蒼蒼山閣晚，杳杳隙塵秋。',48,'全唐诗/poet.tang.32000.json','["蒼蒼山閣晚，杳杳隙塵秋。", "偶上多時立，翻成盡日愁。", "草平連邑動，河滿逐江流。", "下視窮邊路，行人在隴頭。"]'),
('93adb863-7d10-4b40-b0e4-e64bd4223706','秋宿慈恩寺遂上人院','李頻','唐','唐诗','tang','','[]','滿閣終南色，清宵獨倚欄。',48,'全唐诗/poet.tang.32000.json','["滿閣終南色，清宵獨倚欄。", "風高斜漢動，葉下曲江寒。", "帝里求名老，空門見性難。", "吾師無一事，不似在長安。"]'),
('8656a575-0e2c-4077-8214-70f202c4980c','題棲霞寺慶上人院','李頻','唐','唐诗','tang','','[]','居與鳥巢鄰，日將巢鳥親。',48,'全唐诗/poet.tang.32000.json','["居與鳥巢鄰，日將巢鳥親。", "多生從此性，久集得無身。", "樹老風終夜，山寒雪見春。", "不知諸祖後，傳印是何人。"]'),
('7345bc9d-6b0c-41c1-be11-002f858ce90e','送友人入蜀','李頻','唐','唐诗','tang','','[]','天際蜀門開，西看舉別杯。',48,'全唐诗/poet.tang.32000.json','["天際蜀門開，西看舉別杯。", "何人不異禮，上客自懷才。", "夜澗青林發，秋江淥水來。", "臨邛行樂處，莫到白頭回。"]'),
('51dc310b-cb62-44f5-9091-62a29fc8e131','贈同官蘇明府','李頻','唐','唐诗','tang','','[]','山中畿內邑，別覺大夫清。',48,'全唐诗/poet.tang.32000.json','["山中畿內邑，別覺大夫清。", "簿領分王事，官資寄野情。", "閑齋無獄訟，隱几向泉聲。", "從此朝天路，門前是去程。"]'),
('7781d087-9a13-461f-9c49-eb72b0689176','送厲圖南往荆州覲伯','李頻','唐','唐诗','tang','','[]','雲水入荆湘，古來魚鳥鄉。',48,'全唐诗/poet.tang.32000.json','["雲水入荆湘，古來魚鳥鄉。", "故關重隔遠，春日獨行長。", "山溜含清韻，江雷吐夜光。", "郡中詞客會，遊子更升堂。"]'),
('52f625a8-cfc1-430b-a9db-0c09a9171b2f','山中夜坐','李頻','唐','唐诗','tang','','[]','歸家來幾夜，倏忽覺秋殘。',48,'全唐诗/poet.tang.32000.json','["歸家來幾夜，倏忽覺秋殘。", "月滿方塘白，風依老樹寒。", "戲魚重躍定，驚鳥却棲難。", "爲有門前路，吾生不得安。"]'),
('7572df3b-441e-44cd-b6ab-f7a886228f88','送台州唐興陳明府','李頻','唐','唐诗','tang','','[]','見說海西隅，山川與俗殊。',48,'全唐诗/poet.tang.32000.json','["見說海西隅，山川與俗殊。", "宦遊如不到，仙分即應無。", "瀑布當公署，天台是縣圖。", "遙知爲吏去，有術字惸孤。"]'),
('b4a70e91-a8f5-41a1-8f75-6409c9ac30d0','夏日過友人檀溪別業','李頻','唐','唐诗','tang','','[]','暑天宜野宅，林籟爽泠泠。',48,'全唐诗/poet.tang.32000.json','["暑天宜野宅，林籟爽泠泠。", "沙月邀開戶，巖風助掃庭。", "鷺棲依綠篠，魚躍出清萍。", "客抱方如醉，因來得暫醒。"]'),
('e330be48-ffc2-4fce-9eb8-247807f4f71a','自江上入關','李頻','唐','唐诗','tang','','[]','盡室寄滄洲，孤帆獨泝流。',36,'全唐诗/poet.tang.32000.json','["盡室寄滄洲，孤帆獨泝流。", "天涯心似夢，江上雨兼秋。", "文字爲人棄，田園被債收。"]'),
('411796cc-6950-4267-8025-53ea725553c0','冬夜和范秘書宿秘省中作','李頻','唐','唐诗','tang','','[]','每日得閑吟，清曹闕下深。',48,'全唐诗/poet.tang.32000.json','["每日得閑吟，清曹闕下深。", "因知遙夜坐，別有遠山心。", "芸細書中氣，松疎雪後陰。", "歸時高興足，還復插朝簪。"]'),
('fa2cdb39-1eae-4fce-83d3-c73d24227aaa','送友人遊太原','李頻','唐','唐诗','tang','','[]','孤帆幾日懸，楚客思飄然。',48,'全唐诗/poet.tang.32000.json','["孤帆幾日懸，楚客思飄然。", "水宿南湖夜，山離舊國年。", "秋風高送雁，寒雨入停蟬。", "此去勤書札，時常中路傳。"]'),
('4dc64afc-9d79-4924-a40e-313469970770','江上居寄山中客','李頻','唐','唐诗','tang','','[]','山後與山前，相思隔呌猿。',48,'全唐诗/poet.tang.32000.json','["山後與山前，相思隔呌猿。", "殘雲收樹末，返照落江源。", "苦雨秋濤漲，狂風野火翻。", "朝來賣藥客，遇我達無言。"]'),
('cb7414e5-fd3e-46eb-99b2-3bad97e2b620','送張郎中赴睦州','李頻','唐','唐诗','tang','','[]','青山復淥水，想入富春西。',48,'全唐诗/poet.tang.32000.json','["青山復淥水，想入富春西。", "夾岸清猿去，中流白日低。", "美兼華省出，榮共故鄉齊。", "賤子遙攀送，歸心逐馬蹄。"]'),
('6f66b613-c6ad-4ffe-807e-4f8a06edc638','送鄂渚韋尚書赴鎮','李頻','唐','唐诗','tang','','[]','夏口本吳頭，重城據上遊。',48,'全唐诗/poet.tang.32000.json','["夏口本吳頭，重城據上遊。", "戈船轉江漢，風月宿汀洲。", "執憲傾民望，銜恩赴主憂。", "誰知舊寮屬，攀餞淚仍流。"]'),
('04022602-65ef-40e1-bc6a-ec75bee4e148','送崔侍御書記赴山北座主尚書招辟','李頻','唐','唐诗','tang','','[]','書記向丘門，旌幢夾谷尊。',48,'全唐诗/poet.tang.32000.json','["書記向丘門，旌幢夾谷尊。", "從來遊幕意，此去幷酬恩。", "雁呌嫌冰合，驄嘶喜雪繁。", "同爲入室士，不覺別銷魂。"]'),
('4bc6d24c-3f64-4a74-9f07-bcd8e5bfa574','入朝遇雪','李頻','唐','唐诗','tang','','[]','霜鬢持霜簡，朝天向雪天。',48,'全唐诗/poet.tang.32000.json','["霜鬢持霜簡，朝天向雪天。", "玉階初辨色，瓊樹乍相鮮。", "密翳空難曙，盈徴瑞不愆。", "誰爲洛陽客，是日更高眠。"]'),
('47a5c3f2-7f63-4863-b660-650c8e417c56','勉力','李頻','唐','唐诗','tang','','[]','日月不並照，升沈俱有時。',48,'全唐诗/poet.tang.32000.json','["日月不並照，升沈俱有時。", "自媒徒欲速，孤立却宜遲。", "盡力唯求己，公心任遇誰。", "人間不得意，半是鬢先衰。"]'),
('345f04ea-f77a-4c46-be30-55caa4dd5a79','郊居寄友人','李頻','唐','唐诗','tang','','[]','林色樹還曛，何時得見君。',48,'全唐诗/poet.tang.32000.json','["林色樹還曛，何時得見君。", "獨居度永日，相去遠浮雲。", "故疾隨秋至，離懷覺夜分。", "蛩聲非自苦，偏是旅人聞。"]'),
('7bc34511-ad8e-4dee-8155-8153d9688989','送陸肱歸吳興','李頻','唐','唐诗','tang','','[]','雪後江上去，風光故國新。',48,'全唐诗/poet.tang.32000.json','["雪後江上去，風光故國新。", "清渾天氣曉，綠動浪花春。", "勸酒提壺鳥，乘舟震澤人。", "誰知滄海月，取桂却來秦。"]'),
('a21c126f-edf4-4dcf-92a6-6ca34b2e06ca','暮秋重過山僧院','李頻','唐','唐诗','tang','','[]','却接良宵坐，明河幾轉流。',48,'全唐诗/poet.tang.32000.json','["却接良宵坐，明河幾轉流。", "安禪逢小暑，抱疾入高秋。", "靜室聞玄理，深山可白頭。", "朝朝獻林果，亦欲學獼猴。"]'),
('bfc5e0de-3e4f-4695-9ec7-7332bde9b938','送新安少府','李頻','唐','唐诗','tang','','[]','南浮雖六月，風水已秋涼。',48,'全唐诗/poet.tang.32000.json','["南浮雖六月，風水已秋涼。", "日亂看江樹，身飛逐楚檣。", "後期誰可定，臨別語空長。", "遠宦須清苦，幽蘭貴獨芳。"]'),
('2fa7aa13-ae74-44bb-891a-6face034eeb9','送人歸吳','李頻','唐','唐诗','tang','','[]','何人不歸去，君去是閑人。',48,'全唐诗/poet.tang.32000.json','["何人不歸去，君去是閑人。", "帝里求相識，山家即近鄰。", "交情吾道可，離思柳條新。", "未飲青門酒，先如醉夢身。"]'),
('2fb3be4a-f521-4de0-a820-7799bdaaeaac','送姚評事','李頻','唐','唐诗','tang','','[]','儒服從戎去，須知勝事全。',48,'全唐诗/poet.tang.32000.json','["儒服從戎去，須知勝事全。", "使君開幕日，天子偃戈年。", "風雨依嵩嶺，桑麻接楚田。", "新詩隨過客，旋滿洛陽傳。"]'),
('f1a16a64-7822-4b90-8b88-31e9bf7eb59f','題棲雲寺立上人院','李頻','唐','唐诗','tang','','[]','是法從生有，脩持歷劫塵。',48,'全唐诗/poet.tang.32000.json','["是法從生有，脩持歷劫塵。", "獨居巖下室，長似定中身。", "樹老風終夜，山寒雪見春。", "不知諸祖後，傳印是何人。"]'),
('14494be6-98f2-4f3b-8089-e490ce77c3a0','黔中罷職過峽州題田使君北樓','李頻','唐','唐诗','tang','','[]','巴中初去日，已遇使君留。',48,'全唐诗/poet.tang.32000.json','["巴中初去日，已遇使君留。", "及得尋東道，還陪上北樓。", "江衝巫峽出，檣過洛宮收。", "好是從戎罷，看山覺自由。"]'),
('23e0c989-f402-4fea-84b9-c8e121b3e70b','江上送從兄羣玉校書東遊','李頻','唐','唐诗','tang','','[]','逍遙蓬閣吏，才子復詩流。',48,'全唐诗/poet.tang.32000.json','["逍遙蓬閣吏，才子復詩流。", "墳籍因窮覽，江湖却縱遊。", "眠波聽戍鼓，飯浦約魚舟。", "處處迎高密，先應掃郡樓。"]'),
('1cffea41-be7b-45b2-9e94-5c11ba3e7e88','宛陵東峰亭與友人話別','李頻','唐','唐诗','tang','','[]','坐舉天涯目，停杯語日晡。',36,'全唐诗/poet.tang.32000.json','["坐舉天涯目，停杯語日晡。", "脩篁齊逈檻，列岫限平蕪。", "亂水通三楚，歸帆挂五湖。"]'),
('da08ae1e-81dd-440c-9c69-96e79e6c6950','華山尋隱者','李頻','唐','唐诗','tang','','[]','自入華山居，關東相見疎。',48,'全唐诗/poet.tang.32000.json','["自入華山居，關東相見疎。", "瓢中誰寄酒，葉上我留書。", "巢鳥寒棲盡，潭泉暮凍餘。", "長聞得藥力，此說又何如。"]'),
('884a7c90-4d31-429b-866f-29fa86e0c2cd','題薦福寺僧棲白上人院','李頻','唐','唐诗','tang','','[]','空門有才子，得道亦吟詩。',48,'全唐诗/poet.tang.32000.json','["空門有才子，得道亦吟詩。", "內殿頻徴入，孤峰久作期。", "高名何代比，密行幾生持。", "長愛喬松院，清涼坐夏時。"]'),
('1a9d595d-c789-446b-a974-952a6718e992','遊四明山劉樊二真人祠題山下孫氏居','李頻','唐','唐诗','tang','','[]','久在仙壇下，全家是地仙。',48,'全唐诗/poet.tang.32000.json','["久在仙壇下，全家是地仙。", "池塘來乳洞，禾黍接芝田。", "起看青山足，還傾白酒眠。", "不知塵世事，雙鬢逐流年。"]'),
('81c1987e-e61d-4028-b52a-8c021c200e92','和太學趙鴻博士歸蔡中','李頻','唐','唐诗','tang','','[]','得祿從高第，還鄉見後生。',48,'全唐诗/poet.tang.32000.json','["得祿從高第，還鄉見後生。", "田園休問主，詞賦已垂名。", "掃壁前題出，開窗舊景清。", "遙知賢太守，致席日邀迎。"]'),
('4b0dddab-70d1-4514-a7a7-a80eb2def195','送壽昌曹明府','李頻','唐','唐诗','tang','','[]','惠人須宰邑，爲政貴通經。',48,'全唐诗/poet.tang.32000.json','["惠人須宰邑，爲政貴通經。", "却用清琴理，猶嫌薄俗聽。", "漲江晴漸淥，春嶠燒還青。", "若宿嚴陵瀨，誰當是客星。"]'),
('b5a3e1f9-e399-4fd4-b2b5-af14402068c4','哭賈島','李頻','唐','唐诗','tang','','[]','秦樓吟苦夜，南望只悲君。',48,'全唐诗/poet.tang.32000.json','["秦樓吟苦夜，南望只悲君。", "一宦終遐徼，千山隔旅墳。", "恨聲流蜀魄，冤氣入湘雲。", "無限風騷句，時來日夜聞。"]'),
('7f920b77-d950-40ae-9398-36b75cff38a6','送薛能赴鎮徐方','李頻','唐','唐诗','tang','','[]','列土人間盛，彭門屬九州。',48,'全唐诗/poet.tang.32000.json','["列土人間盛，彭門屬九州。", "山河天設險，禮樂牧分憂。", "皎日爲明信，清風占早秋。", "雖同郤縠舉，郤縠不封侯。"]'),
('6f7db208-afbd-4e1f-ba1e-7ea7eb61052c','送鳯翔范書記','李頻','唐','唐诗','tang','','[]','西京無暑氣，夏景似清秋。',48,'全唐诗/poet.tang.32000.json','["西京無暑氣，夏景似清秋。", "天府來相辟，高人去自由。", "江山通蜀國，日月近神州。", "若共將軍語，河蘭地未收。"]'),
('d7c2239b-3160-4324-bb97-daec992f0414','岐山逢陝下故人','李頻','唐','唐诗','tang','','["\u9ec4\u6cb3"]','三秦一會面，二陝久分攜。',48,'全唐诗/poet.tang.32000.json','["三秦一會面，二陝久分攜。", "共憶黃河北，相留白日西。", "寄來書少達，別後夢多迷。", "早晚期于此，看花聽鳥啼。"]'),
('2ebc7b30-bb7a-4194-a32e-debf531e335f','送友人陸肱往太原','李頻','唐','唐诗','tang','','[]','幷州非故國，君去復尋誰。',48,'全唐诗/poet.tang.32000.json','["幷州非故國，君去復尋誰。", "獫狁方爲寇，嫖姚正用師。", "戍煙來自號，邊雪下無時。", "更想經綿上，應逢禁火期。"]'),
('db716d68-91c5-428f-9a1b-078f554eafac','贈李將軍','李頻','唐','唐诗','tang','','[]','吾宗偏好武，漢代將家流。',48,'全唐诗/poet.tang.32000.json','["吾宗偏好武，漢代將家流。", "走馬辭中禁，屯軍向渭州。", "天心待破虜，陣面許封侯。", "却得河源水，方應洗國讐。"]'),
('c97ba93a-285c-4182-bf9d-96663e102d5e','送友人喻坦之歸睦州','李頻','唐','唐诗','tang','','[]','歸心常共知，歸路不相隨。',48,'全唐诗/poet.tang.32000.json','["歸心常共知，歸路不相隨。", "彼此無依倚，東西又別離。", "山花含雨濕，江樹近潮欹。", "莫戀漁樵興，生涯各有爲。"]'),
('9836f9fe-8999-4293-bc12-aefa289abdad','尋華陽隱者','李頻','唐','唐诗','tang','','[]','閑却白雲居，行蹤出去初。',48,'全唐诗/poet.tang.32000.json','["閑却白雲居，行蹤出去初。", "窗中聊取筆，架上獨留書。", "日背林光冷，潭澄嶽影虛。", "長聞得藥力，此說復何如。"]'),
('8837a315-30cd-44b9-b861-8c3e1807a06a','長安即事','李頻','唐','唐诗','tang','','[]','豈得有書名，徒爲老帝京。',48,'全唐诗/poet.tang.32000.json','["豈得有書名，徒爲老帝京。", "關中秋氣早，雨後夜涼生。", "滄海身終泛，青門夢已行。", "秦人縱相識，多少別離情。"]'),
('0b11d202-ac0d-448c-ac9d-7c78925db617','送友人遊塞北','李頻','唐','唐诗','tang','','[]','朔野正秋風，前程見磧鴻。',48,'全唐诗/poet.tang.32000.json','["朔野正秋風，前程見磧鴻。", "日西身獨遠，山轉路無窮。", "樹隔高關斷，沙連大漠空。", "君看河外將，早晚擬平戎。"]'),
('7f8047e7-b2b4-42b9-b711-6e75b37009b2','陝府上姚中丞','李頻','唐','唐诗','tang','','[]','關東領藩鎮，[闕]下授旌旄。',50,'全唐诗/poet.tang.32000.json','["關東領藩鎮，[闕]下授旌旄。", "覓句秋吟苦，酬恩夜坐勞。", "天開吹角出，木落上樓高。", "閑話錢塘郡，半年聽海潮。"]'),
('796791e6-77e6-4ddc-90ae-f48a3fd4b0f5','送供奉喻鍊師歸天目山','李頻','唐','唐诗','tang','','[]','承恩雖內殿，得道本深山。',48,'全唐诗/poet.tang.32000.json','["承恩雖內殿，得道本深山。", "舉世相看老，孤峰獨自還。", "溪來青壁裏，路在白雲間。", "絕頂無人住，雙峰是舊關。"]'),
('f91a2347-7f92-4b09-92e5-a28032e2e614','之任建安淥溪亭偶作二首 一','李頻','唐','唐诗','tang','','[]','入境當春務，農蠶事正殷。',48,'全唐诗/poet.tang.32000.json','["入境當春務，農蠶事正殷。", "逢溪難飲馬，度嶺更勞人。", "想取烝黎泰，無過賦歛均。", "不知成政後，誰是得爲鄰。"]'),
('4d0930d4-7acc-4907-bd89-ed143dffdd95','之任建安淥溪亭偶作二首 二','李頻','唐','唐诗','tang','','[]','維舟綠溪岸，繞郡白雲峰。',48,'全唐诗/poet.tang.32000.json','["維舟綠溪岸，繞郡白雲峰。", "將幕連山起，人家向水重。", "短才無獨見，長策未相逢。", "所幸分堯理，烝民悉可封。"]'),
('a371a06f-071f-4c0f-a01b-4c6fd1e77147','送侯郎中任新定二首 一','李頻','唐','唐诗','tang','','[]','爲郎非白頭，作牧授滄洲。',48,'全唐诗/poet.tang.32000.json','["爲郎非白頭，作牧授滄洲。", "江界乘潮入，山川值勝遊。", "暑氣隨轉扇，涼月傍開樓。", "便欲歸田里，拋官逐隱侯。"]'),
('53bfce48-8e9b-430d-b274-ec311fbec21d','送侯郎中任新定二首 二','李頻','唐','唐诗','tang','','[]','罷郎東出守，半路得浮舟。',48,'全唐诗/poet.tang.32000.json','["罷郎東出守，半路得浮舟。", "大斾行當夏，桐江到未秋。", "雲閑分島寺，濤靜見沙鷗。", "誰伴臨清景，吟詩上郡樓。"]'),
('7c9af664-38c8-46fb-b0f7-0adb6a0db138','送太學吳康仁及第南歸','李頻','唐','唐诗','tang','','[]','因爲太學選，志業徹春闈。',72,'全唐诗/poet.tang.32000.json','["因爲太學選，志業徹春闈。", "首領諸生出，先登上第歸。", "一榮猶未已，具慶且應稀。", "縱馬行青草，臨岐脫白衣。", "家遙楚國寄，帆對漢山飛。", "知己盈華省，看君再發機。"]'),
('fde02478-7088-4b6b-ab09-fa091b1c6d1c','陝州題河上亭','李頻','唐','唐诗','tang','','[]','岸擁洪流急，亭開清興長。',72,'全唐诗/poet.tang.32000.json','["岸擁洪流急，亭開清興長。", "當軒河草晚，入坐水風涼。", "獨鳥驚來客，孤雲觸去檣。", "秋聲和遠雨，暮色帶微陽。", "浪靜澄牕影，沙陰發簟光。", "逍遙每盡日，誰識愛滄浪。"]'),
('119764a3-8f77-49f7-a47f-4c0104636f22','留題姚氏山齋','李頻','唐','唐诗','tang','','[]','未厭棲林趣，猶懷濟世才。',72,'全唐诗/poet.tang.32000.json','["未厭棲林趣，猶懷濟世才。", "閑眠知道在，高步會時來。", "露滴從添硯，蟬吟便送杯。", "亂書離縹帙，迸筍出苔莓。", "異果因僧摘，幽窗爲燕開。", "春遊何處盡，欲別幾遲回。"]'),
('90925448-0a88-4f27-86dc-eff3920430c3','長安書懷投知己','李頻','唐','唐诗','tang','','[]','所學近雕蟲，知難謁至公。',144,'全唐诗/poet.tang.32000.json','["所學近雕蟲，知難謁至公。", "徒隨衆人後，擬老一生中。", "間歲家書到，經荒世業空。", "心懸滄海斷，夢與白雲通。", "玉漏聲連北，銀河氣極東。", "關門迢遞月，禁苑寂寥鴻。", "地廣身難束，時平道獨窮。", "蕭條苔長雨，淅瀝葉危風。", "久媿干朝客，多慚別釣翁。", "因依非不忝，延薦況曾蒙。", "與善應無替，垂恩本有終。", "霜天搖落日，莫使逐孤蓬。"]'),
('df2d0ae0-7193-4124-afb4-9493ade54718','送姚侍御充渭北掌書記','李頻','唐','唐诗','tang','','[]','北境烽煙急，南山戰伐頻。',120,'全唐诗/poet.tang.32000.json','["北境烽煙急，南山戰伐頻。", "撫綏初易帥，參畫盡須人。", "書記才偏稱，朝廷意更親。", "繡衣行李日，綺陌別離塵。", "報國將臨虜，之藩不離秦。", "豸冠嚴在首，雄筆健隨身。", "飲馬河聲暮，休兵塞色春。", "敗亡仍暴骨，冤哭可傷神。", "上策何當用，邊情此是真。", "雕陰曾久客，拜送欲霑巾。"]'),
('e24e9ae8-798d-4760-9676-b3e6f8d1db6c','長安書情投知己','李頻','唐','唐诗','tang','','[]','陝服因詩句，從容已半年。',288,'全唐诗/poet.tang.32000.json','["陝服因詩句，從容已半年。", "一從歸闕下，罕得到門前。", "每候朝軒出，常看列宿懸。", "重投期見獎，數首果蒙傳。", "轉覺功宜倍，兼令住更堅。", "都忘春暫醉，少省夜曾眠。", "煩暑燈誰讀，孤雲業自專。", "精華搜未竭，騷雅琢須全。", "此事勤雖過，他謀拙莫先。", "槐街勞白日，桂路在青天。", "取第殊無序，還鄉可有緣。", "旅情長越鳥，秋思幾秦蟬。", "月色千樓滿，砧聲萬井連。", "江山阻迢遞，時節暗推遷。", "道即窮通守，才應始末憐。", "書紳相戒語，藏篋贈行篇。", "致主當齊聖，爲郎本是仙。", "人心期際會，鳳翼許遷延。", "畢竟良圖在，何妨逸性便。", "幽齋中寢覺，珍木正陰圓。", "隱几閑瞻夜，臨雲興渺然。", "五陵供麗景，六義動花牋。", "倘與潛生翼，寧非助化權。", "免教垂素髪，歸種海隅田。"]'),
('4135975e-abe0-4512-aa8f-2a2deafb0c9e','府試丹浦非樂戰','李頻','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','自古爲君道，垂衣致理難。',72,'全唐诗/poet.tang.32000.json','["自古爲君道，垂衣致理難。", "懷仁須去殺，用武即勝殘。", "毒幟誅方及，兵臨釁可觀。", "居來彭蠡固，戰罷洞庭寬。", "雪國知天遠，霜林是血丹。", "吾皇則堯典，薄伐至桑亁。"]'),
('9dc22683-6954-493a-af61-8770d66cc7c5','府試風雨聞雞','李頻','唐','唐诗','tang','','[]','不爲風雨變，雞德一何貞。',72,'全唐诗/poet.tang.32000.json','["不爲風雨變，雞德一何貞。", "在暗長先覺，臨晨即自鳴。", "陰霾方見信，頃刻詎移聲。", "向晦如相警，知時似獨清。", "蕭蕭和斷漏，喔喔報重城。", "欲識詩人興，中含君子情。"]'),
('19c1b125-f6b3-4a9d-9c67-be39388e5d54','府試觀蘭亭圖','李頻','唐','唐诗','tang','','[]','往會人何處，遺蹤事可觀。',72,'全唐诗/poet.tang.32000.json','["往會人何處，遺蹤事可觀。", "林亭今日在，草木古春殘。", "筆想吟中駐，杯疑飲後乾。", "向青穿峻嶺，當白認回湍。", "月影窗間夜，湖光枕上寒。", "不知詩酒客，誰更慕前歡。"]'),
('829b29d0-1caf-4416-83de-141271b04ee4','府試老人星見','李頻','唐','唐诗','tang','','[]','良宵出戶庭，極目向青冥。',72,'全唐诗/poet.tang.32000.json','["良宵出戶庭，極目向青冥。", "海內逢康日，天邊見壽星。", "臨空遙的的，竟曉獨熒熒。", "春後先依景，秋來忽近丁。", "垂休臨有道，作瑞掩前經。", "豈比周王夢，徒言得九齡。"]'),
('f0abfb71-c78e-4401-9c92-2b761693f2f8','省試振鷺','李頻','唐','唐诗','tang','','[]','有鳥生江浦，霜華作羽翰。',72,'全唐诗/poet.tang.32000.json','["有鳥生江浦，霜華作羽翰。", "君臣將比潔，朝野共相歡。", "月影林梢下，冰光水際殘。", "翻飛時共樂，飲啄道皆安。", "逈翥宜高詠，羣棲入靜看。", "由來鴛鷺侶，濟濟列千官。"]'),
('de17960a-cbb1-4d67-a3d1-184dd2c8fe47','寄辛明府','李頻','唐','唐诗','tang','','[]','何處無苛政，東南有子男。',72,'全唐诗/poet.tang.32000.json','["何處無苛政，東南有子男。", "細將朝客說，須是邑人諳。", "別業空經稔，歸田獨未甘。", "目凝煙積樹，心貯月明潭。", "曉鼓愁方亂，春山睡正酣。", "不任啼鳥思，鄉社欲桑蠶。"]'),
('b28557f4-6ffe-4102-b993-81513aca309c','苑中題友人林亭','李頻','唐','唐诗','tang','','[]','井邑藏嵓穴，幽棲趣若何。',72,'全唐诗/poet.tang.32000.json','["井邑藏嵓穴，幽棲趣若何。", "春篁抽筍密，夏鳥雜雛多。", "坐有清風至，林無暑氣過。", "亂書還就葉，真飲不聽歌。", "片影明紅蘚，斜陰映綠蘿。", "雄文終可惜，莫更棄高科。"]'),
('fce6e119-a8ea-4bfe-93fe-6a4252d2fb6a','投京兆府試官任文學先輩','李頻','唐','唐诗','tang','','[]','高興每論詩，非才獨見推。',96,'全唐诗/poet.tang.32000.json','["高興每論詩，非才獨見推。", "應當明試日，不比暗投時。", "出口人皆信，操心自可知。", "孤單雖有託，際會別無期。", "取舍知由己，窮通斷在茲。", "賤身何足數，公道自難欺。", "澤國違甘旨，漁舟積夢思。", "長安未歸去，爲倚鑒妍媸。"]'),
('ca567bee-ce66-429e-810b-f2c0bf420750','宋少府東溪泛舟','李頻','唐','唐诗','tang','','[]','登岸還入舟，水禽驚笑語。',36,'全唐诗/poet.tang.32000.json','["登岸還入舟，水禽驚笑語。", "晚葉低衆色，濕雲帶繁暑。", "落日乘醉歸，溪流復幾許。"]'),
('fcb48b29-ad6c-475f-a489-8b0e493a3ca1','聞北虜入靈州二首 一','李頻','唐','唐诗','tang','','[]','河冰一夜合，虜騎入靈州。',24,'全唐诗/poet.tang.32000.json','["河冰一夜合，虜騎入靈州。", "歲歲徴兵去，難防塞草秋。"]'),
('8fc1a9ed-4053-4c88-9c57-2144e58e34b5','聞北虜入靈州二首 二','李頻','唐','唐诗','tang','','[]','見說靈州戰，沙中血未乾。',24,'全唐诗/poet.tang.32000.json','["見說靈州戰，沙中血未乾。", "將軍日告急，走馬向長安。"]'),
('9442dc86-6661-43b8-87b9-31df50b0a05a','送友人下第歸感懷','李頻','唐','唐诗','tang','','[]','帝里春無意，歸山對物華。',24,'全唐诗/poet.tang.32000.json','["帝里春無意，歸山對物華。", "即應來日去，九陌踏槐花。"]'),
('72133e79-bc65-4686-bb38-1abc76457e3f','贈桂林友人','李頻','唐','唐诗','tang','','[]','君家桂林住，日伐桂枝炊。',24,'全唐诗/poet.tang.32000.json','["君家桂林住，日伐桂枝炊。", "何事東堂樹，年年待一枝。"]'),
('04971c17-5c15-4e04-b2a5-f8cdfc63f1a2','長安感懷','李頻','唐','唐诗','tang','','[]','一第知何日，全家待此身。',24,'全唐诗/poet.tang.32000.json','["一第知何日，全家待此身。", "空將灞陵酒，酌送向東人。"]'),
('c2652529-6311-4778-b342-f292fb420889','題長孫桐樹','李頻','唐','唐诗','tang','','[]','一去龍門側，千年鳳影移。',24,'全唐诗/poet.tang.32000.json','["一去龍門側，千年鳳影移。", "空餘剪圭處，無復在孫枝。"]'),
('a6144ae0-3bcf-4503-b58d-9abf24d6608c','渡漢江','李頻','唐','唐诗','tang','','["\u4e94\u8a00\u7edd\u53e5", "\u601d\u4e61", "\u5510\u8bd7\u4e09\u767e\u9996", "\u6e21\u6c5f"]','嶺外音書絕，經年復歷春。',24,'全唐诗/poet.tang.32000.json','["嶺外音書絕，經年復歷春。", "近鄉情更怯，不敢問來人。"]'),
('73ce85e2-72a1-4042-a809-172177db3da4','嵩山夜還','李頻','唐','唐诗','tang','','[]','家住東臯去，好採舊山薇。',24,'全唐诗/poet.tang.32000.json','["家住東臯去，好採舊山薇。", "自省遊泉石，何曾不夜歸。"]'),
('31187640-bb91-4ac9-85cc-7115be6c4e5b','暮秋宿清源上人院','李頻','唐','唐诗','tang','','[]','野客愁來日，山房木落中。',48,'全唐诗/poet.tang.32000.json','["野客愁來日，山房木落中。", "微風生夜半，積雨向秋終。", "證道方離法，安禪不住空。", "迷途將覺路，語默見西東。"]'),
('f5eca67c-e1db-40f9-bd4b-920f21734996','秋夜宿重本上人院','李頻','唐','唐诗','tang','','[]','却憶涼堂坐，明河幾度流。',48,'全唐诗/poet.tang.32000.json','["却憶涼堂坐，明河幾度流。", "安禪逢小暑，抱疾入高秋。", "水國曾重講，雲林半舊遊。", "此來看月落，還似道相求。"]'),
('c5e02e3f-9588-4beb-8278-411eddeb2662','贈立規上人','李頻','唐','唐诗','tang','','[]','竹向空齋合，無僧在四鄰。',48,'全唐诗/poet.tang.32000.json','["竹向空齋合，無僧在四鄰。", "去雲離坐石，斜月到禪身。", "樹老風終夜，山寒雪見春。", "不知諸祖後，傳印是何人。"]'),
('4051ba4e-bf73-46d1-9ed6-5bd0a31a849e','蘇州寒食日送人歸覲','李頻','唐','唐诗','tang','','[]','江城寒食下，花木慘離魂。',48,'全唐诗/poet.tang.32000.json','["江城寒食下，花木慘離魂。", "幾宿投山寺，孤帆過海門。", "□聲潑火雨，柳色禁煙村。", "定看堂高後，斑衣滅淚痕。"]'),
('801df974-5d29-4119-aa6a-6a638ef67544','即席送許□之曹南省兄','李頻','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','梅爛荷圓六月天，歸帆高背虎丘煙。',64,'全唐诗/poet.tang.32000.json','["梅爛荷圓六月天，歸帆高背虎丘煙。", "到時自見成行雁，別處休聽滿樹蟬。", "賣劒爲賒吳市酒，攜家猶借洞庭船。", "待看春榜來江外，名占蓬萊第幾仙。"]'),
('25c0a253-706f-4ab8-94af-cbaacceffd38','送羅著作兩浙按獄','李頻','唐','唐诗','tang','','[]','使印星車適舊遊，陶潛今日在瀛洲。',64,'全唐诗/poet.tang.32000.json','["使印星車適舊遊，陶潛今日在瀛洲。", "科條盡曉三千罪，囹圄應空十二州。", "舊綬有香籠驛馬，皇華無暇狎沙鷗。", "歸來重過姑蘇郡，莫忘題名在虎丘。"]'),
('3c2610bf-d41b-46b3-ba0b-925ddf294ae8','下第後屏居書懷寄張侍御','李頻','唐','唐诗','tang','','[]','刖足豈一生，良工隔千里。',96,'全唐诗/poet.tang.32000.json','["刖足豈一生，良工隔千里。", "故山彭澤上，歸夢向汾水。", "低催神氣盡，僮僕心亦耻。", "未達誰不知，達者多忘此。", "行年忽已壯，去老年更幾。", "功名如不彰，身歿豈爲鬼。", "纔看芳草歇，即歎涼風起。", "驄馬未來朝，嘶聲尚在耳。"]'),
('52c11e55-22fa-4efd-93c6-d7669a98196d','荅韓中丞容不飲酒','李頻','唐','唐诗','tang','','[]','老大成名仍足病，強聽絲竹亦無歡。',32,'全唐诗/poet.tang.32000.json','["老大成名仍足病，強聽絲竹亦無歡。", "高情太守容閑坐，借與青山盡日看。"]'),
('616014db-3d2e-465e-81bf-cef3aa2cf32a','句','李頻','唐','唐诗','tang','','[]','只將五字句，用破一生心。',36,'全唐诗/poet.tang.32000.json','["只將五字句，用破一生心。", "楚里八千里，槃槃此都會。", "巍峩數里城，遠水相映帶。"]'),
('07e12fb9-a0f7-4cba-81a3-65b03dbf4639','冬至後西湖泛舟看斷冰偶成長句','李郢','唐','唐诗','tang','','["\u9ec4\u6cb3", "\u897f\u6e56"]','一陽生後陰飆竭，湖上層冰看折時。',96,'全唐诗/poet.tang.32000.json','["一陽生後陰飆竭，湖上層冰看折時。", "雲母扇搖當殿色，珊瑚樹碎滿盤枝。", "斜汀藻動魚應覺，極浦波生鴈未知。", "山影淺中留瓦礫，日光寒外送漣漪。", "崖崩葦岸縱橫散，篙蹙蘭舟片段隨。", "曾向黃河望衝激，大鵬飛起雪風吹。"]'),
('817c933e-49a2-40eb-acd7-4565e8246a15','陽羨春歌','李郢','唐','唐诗','tang','','[]','石亭梅花落如積，玉蘚斕班竹姑赤。',130,'全唐诗/poet.tang.32000.json','["石亭梅花落如積，玉蘚斕班竹姑赤。", "祝陵有酒清若空，煮稬蒸魚作寒食。", "長橋新晴好天氣，兩市兒郎[櫂]船戲。", "溪頭鐃鼓狂殺儂，青蓋紅裙偶相值。", "風光何處最可憐，邵家高樓白日邊。", "樓下遊人顏色喜，溪南黃帽應羞死。", "三月未有二月殘，靈龜可信渰水乾。", "葑草青青促歸去，短簫橫笛說明年。"]'),
('9cc39a4f-2d24-4fde-aef0-7b7c6840c604','茶山貢焙歌','李郢','唐','唐诗','tang','','[]','使君愛客情無已，客在金臺價無比。',296,'全唐诗/poet.tang.32000.json','["使君愛客情無已，客在金臺價無比。", "春風三月貢茶時，盡逐紅旌到山裏。", "焙中清曉朱門開，筐箱漸見新芽來。", "陵煙觸露不停探，官家赤印連帖催。", "朝飢暮匐誰興哀，喧闐競納不盈掬。", "一時一餉還成堆，蒸之馥之香勝梅，研膏架動轟如雷。", "茶成拜表貢天子，萬人爭噉春山摧。", "驛騎鞭聲砉流電，半夜驅夫誰復見。", "十日王程路四千，到時須及清明宴。", "吾君可謂納諫君，諫官不諫何由聞。", "九重城裏雖玉食，天涯吏役長紛紛。", "使君憂民慘容色，就焙嘗茶坐諸客。", "幾回到口重咨嗟，嫩綠鮮芳出何力。", "山中有酒亦有歌，樂營房戶皆仙家。", "仙家十隊酒百斛，金絲宴饌隨經過。", "使君是日憂思多，客亦無言徵綺羅。", "殷勤繞焙復長歎，官府例成期如何。", "吳民吳民莫憔悴，使君作相期蘇爾。"]'),
('fd17641b-9782-4779-8ddd-7d52cebeedf4','夏日登信州北樓','李郢','唐','唐诗','tang','','[]','高樓上長望，百里見靈山。',48,'全唐诗/poet.tang.32000.json','["高樓上長望，百里見靈山。", "雨歇河珠定，雲開谷鳥還。", "田苗映林合，牛犢傍村閑。", "始得消憂處，蟬聲催入關。"]'),
('28efa2ac-79b8-4230-ae11-e5b97a066d6c','遊天柱觀','李郢','唐','唐诗','tang','','[]','聽鐘到靈觀，仙子喜相尋。',48,'全唐诗/poet.tang.32000.json','["聽鐘到靈觀，仙子喜相尋。", "茅洞幾千載，水聲寒至今。", "讀碑丹井上，坐石澗亭陰。", "清興未云盡，煙霞生夕林。"]'),
('c61bbd58-ee62-4786-a541-38fb136aecbf','酬劉谷除夜見寄','李郢','唐','唐诗','tang','','[]','坐恐三更至，流年此夜分。',48,'全唐诗/poet.tang.32000.json','["坐恐三更至，流年此夜分。", "客心無限事，愁雨不堪聞。", "灞上家殊遠，爐前酒暫醺。", "劉郎亦多恨，詩憶故山雲。"]'),
('ae3ee4a1-bd33-4e68-923f-564673f318bf','元日作','李郢','唐','唐诗','tang','','[]','鏘鏘華駟客，門館賀新正。',48,'全唐诗/poet.tang.32000.json','["鏘鏘華駟客，門館賀新正。", "野雪江山霽，微風竹樹清。", "蕪庭春意曉，殘枿燼煙生。", "忽憶王孫草，前年在帝京。"]'),
('fb114637-7666-49a6-a6e5-5f12718a1fdd','酬劉谷立春日吏隱亭見寄','李郢','唐','唐诗','tang','','[]','孤亭遙帶寺，靜者獨登臨。',48,'全唐诗/poet.tang.32000.json','["孤亭遙帶寺，靜者獨登臨。", "楚霽江流慢，春歸澤氣陰。", "野田青牧馬，幽竹暖鳴禽。", "日日年光盡，何堪故國心。"]'),
('54732191-7d84-438e-8abe-3a219ec8f642','宿憐上人房','李郢','唐','唐诗','tang','','[]','重公舊相識，一夕話勞生。',48,'全唐诗/poet.tang.32000.json','["重公舊相識，一夕話勞生。", "藥裹關身病，經函寄道情。", "嶽寒當寺色，灘夜入樓聲。", "不待移文誚，三年別赤城。"]'),
('a3e04892-3305-4692-85bb-550117d07d68','園居','李郢','唐','唐诗','tang','','[]','暮雨楊雄宅，秋風向秀園。',48,'全唐诗/poet.tang.32000.json','["暮雨楊雄宅，秋風向秀園。", "不聞砧杵動，時看桔槔翻。", "釣下魚初食，船移鴨蹔喧。", "橘寒才弄色，須帶早霜繁。"]'),
('d4af9edd-641f-4773-8d9f-d1f9c9480321','中元夜','李郢','唐','唐诗','tang','','[]','江南水寺中元夜，金粟欄邊見月娥。',64,'全唐诗/poet.tang.32000.json','["江南水寺中元夜，金粟欄邊見月娥。", "紅燭影迴仙態近，翠鬟光動看人多。", "香飄彩殿凝蘭麝，露繞輕衣雜綺羅。", "湘水夜空巫峽遠，不知歸路欲如何。"]'),
('346f418b-b2ef-45a1-8178-2cdb2ee12d6c','贈羽林將軍','李郢','唐','唐诗','tang','','[]','虬鬚憔悴羽林郎，曾入甘泉侍武皇。',64,'全唐诗/poet.tang.32000.json','["虬鬚憔悴羽林郎，曾入甘泉侍武皇。", "鵰沒夜雲知御苑，馬隨仙仗識天香。", "五湖歸去孤舟月，六國平來兩鬢霜。", "唯有桓伊江上笛，臥吹三弄送殘陽。"]'),
('3d32635e-a4dd-42b2-b01d-953467116556','送人之嶺南','李郢','唐','唐诗','tang','','[]','關山迢遰古交州，歲[晏]憐君走馬遊。',66,'全唐诗/poet.tang.32000.json','["關山迢遰古交州，歲[晏]憐君走馬遊。", "謝氏海邊逢素女，越王潭上見青牛。", "嵩臺月照啼猨曙，石室煙含古桂秋。", "迴望長安五千里，刺桐花下莫淹留。"]'),
('1e6edac4-29e5-4b04-8cef-99434afa9df0','晚泊松江驛','李郢','唐','唐诗','tang','','[]','片帆孤客晚夷猶，紅蓼花前水驛秋。',64,'全唐诗/poet.tang.32000.json','["片帆孤客晚夷猶，紅蓼花前水驛秋。", "歲月方驚離別盡，煙波仍駐古今愁。", "雲陰故國山川暮，潮落空江網罟收。", "還有吳娃舊歌曲，櫂聲遙散採菱舟。"]'),
('76d6f0f4-302e-4bec-8fd7-44a713f15a38','江亭春霽','李郢','唐','唐诗','tang','','[]','江蘺漠漠荇田田，江上雲亭霽景鮮。',64,'全唐诗/poet.tang.32000.json','["江蘺漠漠荇田田，江上雲亭霽景鮮。", "蜀客帆檣背歸燕，楚山花木怨啼鵑。", "春風掩映千門柳，曉色淒涼萬井煙。", "金磬泠泠水南寺，上方僧室翠微連。"]'),
('875f8ffa-ebb3-47e1-acba-48f498ac629e','早秋書懷','李郢','唐','唐诗','tang','','[]','高梧一葉墜涼天，宋玉悲秋淚灑然。',64,'全唐诗/poet.tang.32000.json','["高梧一葉墜涼天，宋玉悲秋淚灑然。", "霜拂楚山頻見菊，雨零溪樹忽無蟬。", "虛村暮角催殘日，近寺歸僧寄野泉。", "青鬢已緣多病鑷，可堪風景促流年。"]'),
('08227cbe-b546-4554-9d3a-3bc77b2a1b8a','爲妻作生日寄意','李郢','唐','唐诗','tang','','[]','謝家生日好風煙，柳暖花春二月天。',64,'全唐诗/poet.tang.32000.json','["謝家生日好風煙，柳暖花春二月天。", "金鳳對翹雙翡翠，蜀琴初上七絲弦。", "鴛鴦交頸期千歲，琴瑟諧和願百年。", "應恨客程歸未得，綠窗江淚冷涓涓。"]'),
('369c801b-1e0a-4ecd-b02c-9c7e1f6aa0df','重陽日寄浙東諸從事','李郢','唐','唐诗','tang','','[]','野人多病門長掩，荒圃重陽菊自開。',64,'全唐诗/poet.tang.32000.json','["野人多病門長掩，荒圃重陽菊自開。", "愁裏又聞清笛怨，望中難見白衣來。", "元瑜正及從軍樂，甯戚誰憐叩角哀。", "紅斾紛紛碧江暮，知君醉下望鄉臺。"]'),
('7ca95409-b8b5-4ca5-a635-3e83b7dcd220','和湖州杜員外冬至日白蘋洲見憶','李郢','唐','唐诗','tang','','[]','白蘋亭上一陽生，謝朓新裁錦繡成。',64,'全唐诗/poet.tang.32000.json','["白蘋亭上一陽生，謝朓新裁錦繡成。", "千嶂雪消溪影淥，幾家梅綻海波清。", "已知鷗鳥長來狎，可許汀洲獨有名。", "多媿龍門重招引，即拋田舍棹舟行。"]'),
('73f298fc-c893-4e6c-9b94-8ed9a4a97158','上裴晉公','李郢','唐','唐诗','tang','','[]','四朝憂國鬢如絲，龍馬精神海鶴姿。',64,'全唐诗/poet.tang.32000.json','["四朝憂國鬢如絲，龍馬精神海鶴姿。", "天上玉書傳詔夜，陣前金甲受降時。", "曾經庾亮三秋月，下盡羊曇兩路碁。", "惆悵舊堂扃綠野，夕陽無限鳥飛遲。"]'),
('15d1ebdb-2b3a-45cc-b5d0-575ac1276136','錢塘青山題李隱居西齋','李郢','唐','唐诗','tang','','[]','小隱西齋爲客開，翠蘿深處遍青苔。',64,'全唐诗/poet.tang.32000.json','["小隱西齋爲客開，翠蘿深處遍青苔。", "林間掃石安碁局，巖下分泉遰酒杯。", "蘭葉露光秋月上，蘆花風起夜潮來。", "湖山遶屋猶嫌淺，欲櫂漁舟近釣臺。"]'),
('a6797bc8-dd2d-461a-a3ce-b4aa924f3539','友人適越路過桐廬寄題江驛','李郢','唐','唐诗','tang','','[]','桐廬縣前洲渚平，桐廬江上晚潮生。',64,'全唐诗/poet.tang.32000.json','["桐廬縣前洲渚平，桐廬江上晚潮生。", "莫言獨有山川秀，過日仍聞官長清。", "麥隴虛涼當水店，鱸魚鮮美稱蓴羹。", "王孫客棹殘春去，相送河橋羨此行。"]'),
('c5b18759-908d-456b-bd56-6e670bae5d25','送劉谷','李郢','唐','唐诗','tang','','[]','村橋西路雪初晴，雲暖沙乾馬足輕。',64,'全唐诗/poet.tang.32000.json','["村橋西路雪初晴，雲暖沙乾馬足輕。", "寒澗渡頭芳草色，新梅嶺外鷓鴣聲。", "郵亭已送輕車發，山館誰將候火迎。", "落日千峰轉迢遰，知君回首望高城。"]'),
('2cb19acb-618c-4920-a19e-cd84e763d1e9','七夕','李郢','唐','唐诗','tang','','[]','烏鵲橋頭雙扇開，年年一度過河來。',64,'全唐诗/poet.tang.32000.json','["烏鵲橋頭雙扇開，年年一度過河來。", "莫嫌天上稀相見，猶勝人間去不回。", "欲減煙花饒俗世，暫煩煙月掩粧臺。", "別時舊路長清淺，豈肯離情似死灰。"]'),
('392b0510-cded-4247-8449-2952af101d2c','秦處士移家富春發樟亭懷寄','李郢','唐','唐诗','tang','','[]','潮落空江洲渚生，知君已上富春亭。',64,'全唐诗/poet.tang.32000.json','["潮落空江洲渚生，知君已上富春亭。", "嘗聞郭邑山多秀，更說官僚眼盡青。", "離別幾宵魂耿耿，相思一座髪星星。", "仙翁白石高歌調，無復松齋半夜聽。"]'),
('4c1956a7-e88c-4515-b7bb-6b149bb2b598','故洛陽城','李郢','唐','唐诗','tang','','[]','胡兵一動朔方塵，不使鑾輿此重巡。',64,'全唐诗/poet.tang.32000.json','["胡兵一動朔方塵，不使鑾輿此重巡。", "清洛但流嗚咽水，上陽深鎖寂寥春。", "雲收少室初晴雨，柳拂中橋晚渡津。", "欲問升平無故老，鳳樓回首落花頻。"]'),
('a95adb4a-9cbf-42fe-8814-a93153b1a160','紫極宮上元齋次呈諸道流','李郢','唐','唐诗','tang','','[]','碧簡朝天章奏頻，清宮髣髴降靈真。',64,'全唐诗/poet.tang.32000.json','["碧簡朝天章奏頻，清宮髣髴降靈真。", "五龍金角向星斗，三洞玉音愁鬼神。", "風拂亂燈山磬□，露霑仙杏石壇春。", "明朝醮罷羽客散，塵土滿城空世人。"]'),
('90956415-a133-49ae-ba98-e8d7ad172c43','立春一日江村偶興','李郢','唐','唐诗','tang','','[]','舊曆年光看卷盡，立春何用更相催。',64,'全唐诗/poet.tang.32000.json','["舊曆年光看卷盡，立春何用更相催。", "江邊野店寒無色，竹外孤村坐見梅。", "山雪乍晴嵐翠起，漁家向晚笛聲哀。", "南州近有秦中使，聞道胡兵索戰來。"]'),
('6fee5f1d-b9dc-4f9b-bdc1-9a8ac8c88084','立秋後自京歸家','李郢','唐','唐诗','tang','','[]','籬落秋歸見豆花，竹門當水岸橫槎。',64,'全唐诗/poet.tang.32000.json','["籬落秋歸見豆花，竹門當水岸橫槎。", "松齋一雨宜清簟，佛室孤燈對絳紗。", "盡日抱愁跧似鼠，移時不動嬾於虵。", "西江近有鱸魚否，張翰扁舟始到家。"]'),
('c02bff12-a87e-4c89-ae16-d84276464bd4','奉陪裴相公重陽日遊安樂池亭','李郢','唐','唐诗','tang','','[]','絳霄輕靄翊三台，稽阮襟懷管樂才。',64,'全唐诗/poet.tang.32000.json','["絳霄輕靄翊三台，稽阮襟懷管樂才。", "蓮沼昔爲王儉府，菊籬今作孟嘉杯。", "寧知北闕元勳在，却引東山舊客來。", "自笑吐茵還酩酊，日斜空從絳衣迴。"]'),
('6b2e31d7-b0ab-4585-9284-40e1fff9b193','淛河館','李郢','唐','唐诗','tang','','[]','雨濕菰蒲斜日明，茅廚煮繭掉車聲。',64,'全唐诗/poet.tang.32000.json','["雨濕菰蒲斜日明，茅廚煮繭掉車聲。", "青蛇上竹一種色，黃蝶隔溪無限情。", "何處樵漁將遠餉，故園田土憶春耕。", "千峰萬瀨水潏潏，羸馬此中愁獨行。"]'),
('5bfe7dc1-0eb7-4e8b-a2ad-c6b4c319d0d5','春日題山家','李郢','唐','唐诗','tang','','[]','偶與樵人熟，春殘日日來。',72,'全唐诗/poet.tang.32000.json','["偶與樵人熟，春殘日日來。", "依崗尋紫蕨，挽樹得青梅。", "燕靜銜泥起，蜂喧抱蘂回。", "嫩茶重攪綠，新酒畧炊醅。", "漠漠蠶生紙，涓涓水弄苔。", "丁香政堪結，留步小庭隈。"]'),
('1f9f322c-cdf0-47a0-ac0f-e9e5183c80c7','江亭晚望','李郢','唐','唐诗','tang','','[]','碧天涼冷鴈來疎，閑望江雲思有餘。',64,'全唐诗/poet.tang.32000.json','["碧天涼冷鴈來疎，閑望江雲思有餘。", "秋館池亭荷葉後，野人籬落豆花初。", "無愁自得仙人術，多病能忘太史書。", "聞說故園香稻熟，片帆歸去就鱸魚。"]'),
('b21a6826-9385-4c1f-8c98-abc2ce336e3c','長安夜訪澈上人','李郢','唐','唐诗','tang','','[]','關西木落夜霜凝，烏帽閑尋紫閣僧。',64,'全唐诗/poet.tang.32000.json','["關西木落夜霜凝，烏帽閑尋紫閣僧。", "松迥月光先照鶴，寺寒溝水忽生冰。", "琤琤曉漏喧秦禁，漠漠秋煙起漢陵。", "聞說天台舊禪處，石房獨有一龕燈。"]'),
('c0a80cec-c0dc-4b30-95d7-a009fafaad9e','送圓鑒上人遊天台','李郢','唐','唐诗','tang','','[]','西嶺草堂留不住，獨攜瓶錫向天台。',64,'全唐诗/poet.tang.32000.json','["西嶺草堂留不住，獨攜瓶錫向天台。", "霜清海寺聞潮至，日宴江船乞食回。", "華頂夜寒孤月落，石橋秋盡一僧來。", "靈溪道者相逢處，陰洞泠泠竹室開。"]'),
('2bdd7ff9-921a-4aa6-93c7-32822d6787af','送僧之台州','李郢','唐','唐诗','tang','','[]','獨尋台嶺閑遊去，豈覺靈溪道里賒。',64,'全唐诗/poet.tang.32000.json','["獨尋台嶺閑遊去，豈覺靈溪道里賒。", "三井應潮通海浪，五峰攢寺落天花。", "寒潭盥漱銅瓶潔，野店安禪錫杖斜。", "到日初尋石橋路，莫教雲雨濕袈裟。"]'),
('428b3e18-015e-4a30-974d-0162ec9d0d62','傷賈島無可','李郢','唐','唐诗','tang','','[]','却到京師事事傷，惠休歸寂賈生亡。',64,'全唐诗/poet.tang.32000.json','["却到京師事事傷，惠休歸寂賈生亡。", "何人收得文章篋，獨我來經苔蘚房。", "一命未霑爲逐客，萬緣初盡別空王。", "蕭蕭竹塢斜陽在，葉覆閑堦雪擁牆。"]'),
('eec41831-e7b0-4c31-b8f8-e0a23d8196f4','孔雀','李郢','唐','唐诗','tang','','[]','越鳥青春好顏色，晴軒入戶看呫衣。',64,'全唐诗/poet.tang.32000.json','["越鳥青春好顏色，晴軒入戶看呫衣。", "一身金翠畫不得，萬里山川來者稀。", "絲竹慣聽時獨舞，樓臺初上欲孤飛。", "刺桐花謝芳草歇，南國同巢應望歸。"]'),
('3c036111-3bef-457e-9f9e-ae1615404d94','秋晚寄題陸勳校書義興禪居時淮南從事','李郢','唐','唐诗','tang','','[]','禪居秋草晚，蕭索異前時。',96,'全唐诗/poet.tang.32000.json','["禪居秋草晚，蕭索異前時。", "蓮幕青雲貴，翱翔絕後期。", "蘚房檉架掩，山砌石盆欹。", "劒戟晨趨靜，笙歌夜散遲。", "谷寒霜狖靜，林晚磬蟲悲。", "惠遠煙霞在，方平杖履隨。", "骨清須貴達，神重有威儀。", "萬卒千蹄馬，橫鞭從信騎。"]'),
('02b92837-41cc-4527-88f7-5e153727e8ac','酬王舍人雪中見寄','李郢','唐','唐诗','tang','','["\u5199\u96ea", "\u96ea", "\u5b64\u5355"]','三日柴門擁不開，堦庭平滿白皚皚。',32,'全唐诗/poet.tang.32000.json','["三日柴門擁不開，堦庭平滿白皚皚。", "今朝踏作瓊瑤跡，爲有詩從鳳沼來。"]'),
('6c48650e-2c48-478e-b587-e7dccd27332e','蟬','李郢','唐','唐诗','tang','','[]','飲蟬驚雨落高槐，山蟻移將入石階。',32,'全唐诗/poet.tang.32000.json','["飲蟬驚雨落高槐，山蟻移將入石階。", "若使秦樓美人見，還應一爲拔金釵。"]'),
('639f0a81-65c2-47c1-9a44-a45b7b42f53f','自水口入茶山','李郢','唐','唐诗','tang','','[]','蒨蒨紅裙好女兒，相偎相倚看人時。',32,'全唐诗/poet.tang.32000.json','["蒨蒨紅裙好女兒，相偎相倚看人時。", "使君馬上應含笑，橫把金鞭爲詠詩。"]'),
('3af43ff5-183a-49ee-8365-266050d3d00f','重遊天台','李郢','唐','唐诗','tang','','[]','南國天台山水奇，石橋危險古來知。',32,'全唐诗/poet.tang.32000.json','["南國天台山水奇，石橋危險古來知。", "龍潭直下一百丈，誰見生公獨坐時。"]'),
('2fb9d7e2-b5a5-4169-bcb6-20902e866b82','山行','李郢','唐','唐诗','tang','','[]','小田微雨稻苗香，田畔清溪潏潏涼。',32,'全唐诗/poet.tang.32000.json','["小田微雨稻苗香，田畔清溪潏潏涼。", "自憶東吳榜舟日，蓼花溝水半篙強。"]'),
('935f3e8f-736c-492a-a97e-373270f5445a','上元日寄湖杭二從事','李郢','唐','唐诗','tang','','[]','戀別山燈憶水燈，山光水焰百千層。',32,'全唐诗/poet.tang.32000.json','["戀別山燈憶水燈，山光水焰百千層。", "謝公留賞山公喚，知入笙歌阿那朋。"]'),
('f6174dbd-3f25-4b0f-9636-83f10f5f0522','寒食野望','李郢','唐','唐诗','tang','','[]','舊墳新隴哭多時，流世都堪幾度悲。',32,'全唐诗/poet.tang.32000.json','["舊墳新隴哭多時，流世都堪幾度悲。", "烏鳥亂啼人未遠，野風吹散白棠梨。"]'),
('dd7d46e1-7b64-43e8-bdbb-fcabdfb9c2be','清明日題一公禪室','李郢','唐','唐诗','tang','','[]','山頭蘭若石楠春，山下清明煙火新。',32,'全唐诗/poet.tang.32000.json','["山頭蘭若石楠春，山下清明煙火新。", "此日何窮禮禪客，歸心誰是戀禪人。"]'),
('f41d9d47-9d12-4e05-a3d7-d5cedfe87113','七夕寄張氏兄弟','李郢','唐','唐诗','tang','','[]','新秋牛女會佳期，紅粉筵開玉饌時。',32,'全唐诗/poet.tang.32000.json','["新秋牛女會佳期，紅粉筵開玉饌時。", "好與檀郎寄花朵，莫教清曉羨蛛絲。"]'),
('5b511049-ee2f-4226-9fd3-32f729aaf037','春晚與諸同舍出城迎座主侍郎','李郢','唐','唐诗','tang','','[]','三十驊騮一鬨塵，來時不鎖杏園春。',32,'全唐诗/poet.tang.32000.json','["三十驊騮一鬨塵，來時不鎖杏園春。", "東風柳絮輕如雪，應有偷游曲水人。"]'),
('86a921e6-9869-4cc1-8585-8e15ce10d6c6','張郎中宅戲贈二首 一','李郢','唐','唐诗','tang','','[]','薄雪燕蓊紫燕釵，釵垂簏簌抱香懷。',32,'全唐诗/poet.tang.32000.json','["薄雪燕蓊紫燕釵，釵垂簏簌抱香懷。", "一聲歌罷劉郎醉，脫取明金壓繡鞋。"]'),
('3f290ed3-a7ec-411f-8701-ceae956a7072','張郎中宅戲贈二首 二','李郢','唐','唐诗','tang','','[]','謝家青妓邃重關，誰省春風見玉顏。',32,'全唐诗/poet.tang.32000.json','["謝家青妓邃重關，誰省春風見玉顏。", "聞道綵鸞三十六，一雙雙對碧池蓮。"]'),
('6fbb188c-449d-4776-b70f-9579edd75514','醉送','李郢','唐','唐诗','tang','','[]','江梅冷豔酒清光，急拍繁弦醉畫堂。',32,'全唐诗/poet.tang.32000.json','["江梅冷豔酒清光，急拍繁弦醉畫堂。", "無限柳條多少雪，一將春恨付劉郎。"]'),
('3fb42ef0-ada8-440f-8e8a-e5d36efc6da4','曉井','李郢','唐','唐诗','tang','','[]','桐陰覆井月斜明，百尺寒泉古甃清。',32,'全唐诗/poet.tang.32000.json','["桐陰覆井月斜明，百尺寒泉古甃清。", "越女攜瓶下金索，曉天初放轆轤聲。"]'),
('8ba518da-b0e1-4cc9-972c-b847d48dd356','南池','李郢','唐','唐诗','tang','','[]','小男供餌婦搓絲，溢榼香醪倒接䍦。',32,'全唐诗/poet.tang.32000.json','["小男供餌婦搓絲，溢榼香醪倒接䍦。", "日出兩竿魚正食，一家歡笑在南池。"]'),
('80dc0cd4-fec0-467d-b714-5191d4be6d39','偶作','李郢','唐','唐诗','tang','','[]','一杯正發吟哦興，兩盞還生去住愁。',32,'全唐诗/poet.tang.32000.json','["一杯正發吟哦興，兩盞還生去住愁。", "何似全家上船去，酒旗多處即淹留。"]'),
('ef6f5d2f-45c2-4ea3-a76e-c126036622e5','畫鼓','李郢','唐','唐诗','tang','','[]','嘗聞畫鼓動歡情，及送離人恨鼓聲。',32,'全唐诗/poet.tang.32000.json','["嘗聞畫鼓動歡情，及送離人恨鼓聲。", "兩杖一揮行纜解，暮天空使別魂驚。"]'),
('e7e33b58-d3f8-45ea-abea-0f1ebe4f7474','燕蓊花','李郢','唐','唐诗','tang','','[]','十二街中何限草，燕蓊盡欲占殘春。',32,'全唐诗/poet.tang.32000.json','["十二街中何限草，燕蓊盡欲占殘春。", "黃花撲地無窮極，愁殺江南去住人。"]'),
('9e164aa9-1051-45fb-b064-01d761fae92d','邵博士溪亭','李郢','唐','唐诗','tang','','[]','野茶無限春風葉，溪水千重返照波。',32,'全唐诗/poet.tang.32000.json','["野茶無限春風葉，溪水千重返照波。", "只去長橋三十里，誰人一解枉帆過。"]'),
('39596d01-0397-46de-9a2d-401da0b951c5','小石上見亡友題處','李郢','唐','唐诗','tang','','[]','笋石清琤入紫煙，陸雲題處是前年。',32,'全唐诗/poet.tang.32000.json','["笋石清琤入紫煙，陸雲題處是前年。", "苔侵雨打依稀在，惆悵涼風樹樹蟬。"]'),
('84f0f529-53cf-48c9-8225-f1900f14fb92','洞靈觀流泉','李郢','唐','唐诗','tang','','[]','石上苔蕪水上煙，潺湲聲在觀門前。',32,'全唐诗/poet.tang.32000.json','["石上苔蕪水上煙，潺湲聲在觀門前。", "千巖萬壑分流去，更引飛花入洞天。"]'),
('02ea6f69-4bf3-4640-8a5f-abb9b1a6cfa3','送李判官','李郢','唐','唐诗','tang','','[]','津市停橈送別難，熒熒蠟炬照更闌。',32,'全唐诗/poet.tang.32000.json','["津市停橈送別難，熒熒蠟炬照更闌。", "東風萬疊吹江月，誰伴袁襃宿夜灘。"]'),
('c62e871f-0037-4c8f-a0ce-40e9096b899f','宿杭州虛白堂','李郢','唐','唐诗','tang','','[]','秋月斜明虛白堂，寒蛩唧唧樹蒼蒼。',32,'全唐诗/poet.tang.32000.json','["秋月斜明虛白堂，寒蛩唧唧樹蒼蒼。", "江風徹曉不得睡，二十五聲秋點長。"]'),
('c7eb8bfa-54e0-4c89-b2df-448369ad56be','道林寺','崔珏','唐','唐诗','tang','','[]','臨湘之濱麓之隅，西有松寺東岸無。',288,'全唐诗/poet.tang.32000.json','["臨湘之濱麓之隅，西有松寺東岸無。", "松風千里擺不斷，竹泉瀉入于僧廚。", "宏梁大棟何足貴，山寺難有山泉俱。", "四時唯夏不敢入，燭龍安敢停斯須。", "遠公池上種何物，碧羅扇底紅鱗魚。", "香閣朝鳴大法鼓，天宮夜轉三乘書。", "野花市井栽不著，山雞飲啄聲相呼。", "金檻僧迴步步影，石盆水濺聯聯珠。", "北臨高處日正午，舉手欲摸黃金烏。", "遙江大船小於葉，遠村雜樹齊如蔬。", "潭州城郭在何處，東邊一片青模糊。", "今來古往人滿地，勞生未了歸丘墟。", "長卿之門久寂寞，五言七字誇規模。", "我吟杜詩清入骨，灌頂何必須醍醐。", "白日不照耒陽縣，皇天厄死飢寒軀。", "明珠大貝採欲盡，蚌蛤空滿赤沙湖。", "今我題詩亦無味，懷賢覽古成長吁。", "不如興罷過江去，已有好月明歸途。"]'),
('ef96daf2-7596-4663-8431-901daf08fafa','美人嘗茶行','崔珏','唐','唐诗','tang','','[]','雲鬟枕落困春泥，玉郎爲碾瑟瑟塵。',96,'全唐诗/poet.tang.32000.json','["雲鬟枕落困春泥，玉郎爲碾瑟瑟塵。", "閑教鸚鵡啄窗響，和嬌扶起濃睡人。", "銀瓶貯泉水一掬，松雨聲來乳花熟。", "朱脣啜破綠雲時，咽入香喉爽紅玉。", "明眸漸開橫秋水，手撥絲簧醉心起。", "臺時却坐推金箏，不語思量夢中事。"]'),
('8250f0c6-0aba-4a9c-92dc-03fb7c00ee57','門前柳','崔珏','唐','唐诗','tang','','[]','門前蜀柳□知春，風澹煖煙愁殺人。',220,'全唐诗/poet.tang.32000.json','["門前蜀柳□知春，風澹煖煙愁殺人。", "將謂只栽郡樓下，不知迤邐連南津。", "南津柳色連南市，南市戎州三百里。", "夷陬蠻落相連接，故鄉莫道心先死。", "我今帝里尚有家，門前嫩柳插仙霞。", "晨霑太一壇邊雨，暮宿鳳皇城裏鵶。", "別來三載當誰道，門前年年綠陰好。", "春來定解飛雪花，雨後還應庇煙草。", "憶昔當年栽柳時，新芽茁茁嫌生遲。", "如今宛轉稊著地，常向綠陰勞夢思。", "不道彼樹好，不道此樹惡。", "試將此意問野人，野人盡道生處樂。", "爲報門前楊柳栽，我應來歲當歸來。", "縱令樹下能攀折，白髮如絲心似灰。"]'),
('434b5024-590e-4bdc-8041-505bd9d04ee5','岳陽樓晚望','崔珏','唐','唐诗','tang','','["\u5cb3\u9633\u697c"]','乾坤千里水雲間，釣艇如萍去復還。',64,'全唐诗/poet.tang.32000.json','["乾坤千里水雲間，釣艇如萍去復還。", "樓上北風斜捲席，湖中西日倒銜山。", "懷沙有恨騷人往，鼓瑟無聲帝子閑。", "何事黃昏尚凝睇，數行煙樹接荆蠻。"]'),
('c0c76c75-62dc-421c-bfba-738757b44c08','哭李商隱 一','崔珏','唐','唐诗','tang','','[]','成紀星郎字義山，適歸高壤抱長歎。',64,'全唐诗/poet.tang.32000.json','["成紀星郎字義山，適歸高壤抱長歎。", "詞林枝葉三春盡，學海波瀾一夜乾。", "風雨已吹燈燭滅，姓名長在齒牙寒。", "只應物外攀琪樹，便著霓裳上絳壇。"]'),
('e814be8a-03b3-4cd6-b3d5-fac39324bf28','哭李商隱 二','崔珏','唐','唐诗','tang','','[]','虛負凌雲萬丈才，一生襟抱未曾開。',64,'全唐诗/poet.tang.32000.json','["虛負凌雲萬丈才，一生襟抱未曾開。", "鳥啼花落人何在，竹死桐枯鳳不來。", "良馬足因無主踠，舊交心爲絕弦哀。", "九泉莫嘆三光隔，又送文星入夜臺。"]'),
('890bb482-2690-47f1-be07-800f339008d7','和友人鴛鴦之什 一','崔珏','唐','唐诗','tang','','[]','翠鬣紅衣舞夕暉，水禽情似此禽稀。',64,'全唐诗/poet.tang.32000.json','["翠鬣紅衣舞夕暉，水禽情似此禽稀。", "暫分煙島猶回首，只渡寒塘亦共飛。", "映霧乍迷珠殿瓦，逐梭齊上玉人機。", "採蓮無限蘭橈女，笑指中流羨爾歸。"]'),
('fb084998-7c51-45e7-8d70-e1b37f6030eb','和友人鴛鴦之什 二','崔珏','唐','唐诗','tang','','[]','寂寂春塘煙晚時，兩心和影共依依。',48,'全唐诗/poet.tang.32000.json','["寂寂春塘煙晚時，兩心和影共依依。", "溪頭日暖眠沙穩，渡口風寒浴浪稀。", "翡翠莫誇饒彩飾，鸊鵜須羨好毛衣。"]'),
('5675ccb6-8646-436e-a7ff-32136177be54','和友人鴛鴦之什 三','崔珏','唐','唐诗','tang','','[]','舞鶴翔鸞俱別離，可憐生死兩相隨。',64,'全唐诗/poet.tang.32000.json','["舞鶴翔鸞俱別離，可憐生死兩相隨。", "紅絲毳落眠汀處，白雪花成蹙浪時。", "琴上只聞交頸語，窗前空展共飛詩。", "何如相見長相對，肯羨人間多所思。"]'),
('47f4f6a8-5567-4459-b052-f88c9a996b70','有贈 一','崔珏','唐','唐诗','tang','','[]','莫道妝成斷客腸，粉胸綿手白蓮香。',64,'全唐诗/poet.tang.32000.json','["莫道妝成斷客腸，粉胸綿手白蓮香。", "煙分頂上三層綠，劒截眸中一寸光。", "舞勝柳枝腰更軟，歌嫌珠貫曲猶長。", "雖然不似王孫女，解愛臨邛賣賦郎。"]'),
('a4a1ca53-9b7b-4a3e-84e9-d9fed977733b','有贈 二','崔珏','唐','唐诗','tang','','[]','錦里芬芳少佩蘭，風流全占似君難。',64,'全唐诗/poet.tang.32000.json','["錦里芬芳少佩蘭，風流全占似君難。", "心迷曉夢窗猶暗，粉落香肌汗未乾。", "兩臉夭桃從鏡發，一眸春水照人寒。", "自嗟此地非吾土，不得如花歲歲看。"]'),
('c9060dcd-1e8f-48c8-a62b-7eb6d8262936','和人聽歌 一','崔珏','唐','唐诗','tang','','[]','氣吐幽蘭出洞房，樂人先問調宮商。',64,'全唐诗/poet.tang.32000.json','["氣吐幽蘭出洞房，樂人先問調宮商。", "聲和細管珠纔轉，曲度沈煙雪更香。", "公子不隨腸萬結，離人須落淚千行。", "巫山唱罷行雲過，猶自微塵舞畫梁。"]'),
('40f3cb4c-cb97-4f76-a833-f224e13a65d3','和人聽歌 二','崔珏','唐','唐诗','tang','','[]','紅臉初分翠黛愁，錦筵歌板拍清秋。',64,'全唐诗/poet.tang.32000.json','["紅臉初分翠黛愁，錦筵歌板拍清秋。", "一樓春雪和塵落，午夜寒泉帶雨流。", "座上美人心盡死，尊前旅客淚難收。", "莫辭更送劉郎酒，百斛明珠異日酬。"]'),
('768d62a5-f142-4b68-bbf1-5bdf6dd4f5c5','水晶枕','崔珏','唐','唐诗','tang','','[]','千年積雪萬年冰，掌上初擎力不勝。',64,'全唐诗/poet.tang.32000.json','["千年積雪萬年冰，掌上初擎力不勝。", "南國舊知何處得，北方寒氣此中凝。", "黃昏轉燭螢飛沼，白日褰簾水在簪。", "蘄簟蜀琴相對好，裁詩乞與滌煩襟。"]'),
('4cd4ead8-d86a-47bd-a698-67a97ff5af51','席間詠琴客','崔珏','唐','唐诗','tang','','[]','七條弦上五音寒，此藝知音自古難。',32,'全唐诗/poet.tang.32000.json','["七條弦上五音寒，此藝知音自古難。", "唯有河南房次律，始終憐得董庭蘭。"]'),
('9f3a52a1-bef5-4a49-af79-abc004433a5f','句','崔珏','唐','唐诗','tang','','[]','楚王宮地羅含宅，賴許時時聽法來。',16,'全唐诗/poet.tang.32000.json','["楚王宮地羅含宅，賴許時時聽法來。"]'),
('34d81741-6166-4690-84ee-6aa26305e75b','徒相逢','曹鄴','唐','唐诗','tang','','[]','江邊野花不須採，梁頭野燕不用親。',32,'全唐诗/poet.tang.32000.json','["江邊野花不須採，梁頭野燕不用親。", "西施本是越溪女，承恩不薦越溪人。"]'),
('43c226cd-2309-433f-8942-84d90bbd85c7','雜誡','曹鄴','唐','唐诗','tang','','[]','帶香入鮑肆，香氣同鮑魚。',24,'全唐诗/poet.tang.32000.json','["帶香入鮑肆，香氣同鮑魚。", "未入猶可悟，已入當何如。"]'),
('3b22dc07-e585-42df-8866-582f58e8f6d1','捕漁謠','曹鄴','唐','唐诗','tang','','[]','天子好征戰，百姓不種桑。',36,'全唐诗/poet.tang.32000.json','["天子好征戰，百姓不種桑。", "天子好年少，無人薦馮唐。", "天子好美女，夫婦不成雙。"]'),
('cf17ecc7-5687-4c4c-bddb-ef4cfa600c7d','四怨三愁五情詩十二首 其一怨','曹鄴','唐','唐诗','tang','','[]','美人如新花，許嫁還獨守。',24,'全唐诗/poet.tang.32000.json','["美人如新花，許嫁還獨守。", "豈無青銅鏡，終日自疑醜。"]'),
('4035d30f-7eba-43c6-80fe-fd38cdf32762','四怨三愁五情詩十二首 其二怨','曹鄴','唐','唐诗','tang','','[]','庭花已結子，巖花猶弄色。',24,'全唐诗/poet.tang.32000.json','["庭花已結子，巖花猶弄色。", "誰令生處遠，用盡春風力。"]'),
('986a5c16-6321-4b5e-836f-5f7bd701f88e','四怨三愁五情詩十二首 其三怨','曹鄴','唐','唐诗','tang','','[]','短鬟一如螓，長眉一如蛾。',24,'全唐诗/poet.tang.32000.json','["短鬟一如螓，長眉一如蛾。", "相共棹蓮舟，得花不如他。"]'),
('62deae00-7f5c-4734-8ae2-261c94b3e724','四怨三愁五情詩十二首 其四怨','曹鄴','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11"]','手推嘔啞車，朝朝暮暮耕。',24,'全唐诗/poet.tang.32000.json','["手推嘔啞車，朝朝暮暮耕。", "未曾分得穀，空得老農名。"]'),
('1e6c948e-6987-4869-99e1-cdf195c1e818','四怨三愁五情詩十二首 其一愁','曹鄴','唐','唐诗','tang','','[]','遠夢如水急，白髮如草新。',24,'全唐诗/poet.tang.32000.json','["遠夢如水急，白髮如草新。", "歸期待春至，春至還送人。"]'),
('062faa2e-f31b-4ae2-bb67-fd4a96971ea3','四怨三愁五情詩十二首 其二愁','曹鄴','唐','唐诗','tang','','[]','澗草短短青，山月朗朗明。',24,'全唐诗/poet.tang.32000.json','["澗草短短青，山月朗朗明。", "此夜目不掩，屋頭烏啼聲。"]'),
('cc9d64c0-1d04-4d1e-aa0d-619039bccd8a','四怨三愁五情詩十二首 其三愁','曹鄴','唐','唐诗','tang','','[]','別家鬢未生，到城鬢似髪。',24,'全唐诗/poet.tang.32000.json','["別家鬢未生，到城鬢似髪。", "朝朝臨川望，灞水不入越。"]'),
('216c622a-f10c-4adc-8cae-699ee8db5a7a','四怨三愁五情詩十二首 其一情','曹鄴','唐','唐诗','tang','','["\u957f\u6c5f"]','東西是長江，南北是官道。',24,'全唐诗/poet.tang.32000.json','["東西是長江，南北是官道。", "牛羊不戀山，只戀山中草。"]'),
('08ad4457-3581-47b8-b42f-c02533097030','四怨三愁五情詩十二首 其二情','曹鄴','唐','唐诗','tang','','[]','阿嬌生漢宮，西施住南國。',24,'全唐诗/poet.tang.32000.json','["阿嬌生漢宮，西施住南國。", "專房莫相妒，各自有顏色。"]'),
('5f5084c3-3072-4c5c-aa90-7a7f79d4c25c','四怨三愁五情詩十二首 其三情','曹鄴','唐','唐诗','tang','','[]','蛺蝶空中飛，夭桃庭中春。',24,'全唐诗/poet.tang.32000.json','["蛺蝶空中飛，夭桃庭中春。", "見他夫婦好，有女初嫁人。"]'),
('31163e68-55f5-4ddd-986a-51125fd0c01e','四怨三愁五情詩十二首 其四情','曹鄴','唐','唐诗','tang','','[]','檳榔自無柯，椰葉自無陰。',24,'全唐诗/poet.tang.32000.json','["檳榔自無柯，椰葉自無陰。", "常羨庭邊竹，生笋高於林。"]'),
('123e0f29-cf42-4247-9563-b98729a7f47e','四怨三愁五情詩十二首 其五情','曹鄴','唐','唐诗','tang','','[]','野雀空城飢，交交復飛飛。',24,'全唐诗/poet.tang.32000.json','["野雀空城飢，交交復飛飛。", "勿怪官倉粟，官倉無空時。"]'),
('b0d637f8-3328-49e9-ad21-8be289ac07da','寄劉駕','曹鄴','唐','唐诗','tang','','[]','一川草色青褭褭，遶屋水聲如在家。',32,'全唐诗/poet.tang.32000.json','["一川草色青褭褭，遶屋水聲如在家。", "悵望美人不攜手，牆東又發數枝花。"]'),
('c44f9f8e-4770-48ff-bf7e-3a6beed463da','風人體','曹鄴','唐','唐诗','tang','','[]','出門行一步，形影便相失。',72,'全唐诗/poet.tang.32000.json','["出門行一步，形影便相失。", "何況大隄上，驄馬如箭疾。", "夜夜如織婦，尋思待成匹。", "郎只不在家，在家亦如出。", "將金與卜人，譎道遠行吉。", "念郎緣底事，不具天與日。"]'),
('1bce0d41-cefc-48f2-9ed2-bba5bac98e3d','杏園即席上同年','曹鄴','唐','唐诗','tang','','[]','岐路不在天，十年行不至。',120,'全唐诗/poet.tang.32000.json','["岐路不在天，十年行不至。", "一旦公道開，青雲在平地。", "枕上數聲鼓，衡門已如市。", "白日探得珠，不待驪龍睡。", "怱怱出九衢，僮僕顏色異。", "故衣未及換，尚有去年淚。", "晴陽照花影，落絮浮野翠。", "對酒時忽驚，猶疑夢中事。", "自憐孤飛鳥，得接鸞鳳翅。", "永懷共濟心，莫起胡越意。"]'),
('f0a23085-74ec-4927-8818-d1f994676b5b','恃寵','曹鄴','唐','唐诗','tang','','[]','二月樹色好，昭儀正驕奢。',84,'全唐诗/poet.tang.32000.json','["二月樹色好，昭儀正驕奢。", "恐君愛陽豔，斫却園中花。", "三十六宮女，髻鬟各如鴉。", "君王心所憐，獨自不見瑕。", "臺上紅燈盡，未肯下金車。", "一笑不得所，塵中悉無家。", "飛燕身更輕，何必恃容華。"]'),
('975ee657-cb12-48c3-85de-721b239af51c','題女郎廟','曹鄴','唐','唐诗','tang','','[]','數點煙香出廟門，女娥飛去影中存。',32,'全唐诗/poet.tang.32000.json','["數點煙香出廟門，女娥飛去影中存。", "年年嶺上春無主，露泣花愁斷客魂。"]'),
('40f4a98b-c036-4ff8-a5aa-5898f75199ed','四望樓','曹鄴','唐','唐诗','tang','','[]','背山見樓影，應合與山齊。',60,'全唐诗/poet.tang.32000.json','["背山見樓影，應合與山齊。", "座上日已出，城中未鳴雞。", "無限燕趙女，吹笙上金梯。", "風起洛陽東，香過洛陽西。", "公子長夜醉，不聞子規啼。"]'),
('a6719a43-4c65-4f29-a384-e2399548059f','築城三首 一','曹鄴','唐','唐诗','tang','','[]','郎有蘼蕪心，妾有芙蓉質。',24,'全唐诗/poet.tang.32000.json','["郎有蘼蕪心，妾有芙蓉質。", "不辭嫁與郎，築城無休日。"]'),
('83dd3758-fcd7-4edb-a8cc-e6d633d9c2f6','築城三首 二','曹鄴','唐','唐诗','tang','','[]','嗚嗚啄人鴉，軋軋上城車。',24,'全唐诗/poet.tang.32000.json','["嗚嗚啄人鴉，軋軋上城車。", "力盡土不盡，得歸亦無家。"]'),
('cc6ee0e2-a469-4437-869c-a9fd297327d8','築城三首 三','曹鄴','唐','唐诗','tang','','[]','築人非築城，圍秦豈圍我。',24,'全唐诗/poet.tang.32000.json','["築人非築城，圍秦豈圍我。", "不知城上土，化作宮中火。"]'),
('5ff7c5ac-a84c-4b3f-921f-642ce8344708','奉命齊州推事畢寄本府尚書','曹鄴','唐','唐诗','tang','','[]','越鳥栖不定，孤飛入齊鄉。',240,'全唐诗/poet.tang.32000.json','["越鳥栖不定，孤飛入齊鄉。", "日暮天欲雨，那兼羽翎傷。", "州民言刺史，蠹物甚於蝗。", "受命大執法，草草是行裝。", "僕隸皆分散，單車驛路長。", "四顧無相識，奔馳若投荒。", "重門下長鎖，樹影空過牆。", "驅囚遶廊屋，𧥄𧥄如牛羊。", "獄吏相對語，簿書堆滿牀。", "敲枷打鎖聲，終日在目旁。", "既捨三山侶，來餘五斗糧。", "忍學空城雀，潛身入官倉。", "國中天子令，頭上白日光。", "曲木用處多，不如直爲梁。", "恐孤食恩地，晝夜心不遑。", "仲夏天氣熱，鬢鬚忽成霜。", "社鼠不可灌，城狐不易防。", "偶於擒縱間，盡得見否臧。", "截斷姦吏舌，擘開冤人腸。", "明朝向西望，走馬歸汶陽。"]'),
('3bbd3ad2-b059-4fb7-9a47-5f2d3203b6d4','北郭閑思','曹鄴','唐','唐诗','tang','','[]','山前山後是青草，盡日出門還掩門。',32,'全唐诗/poet.tang.32000.json','["山前山後是青草，盡日出門還掩門。", "每思骨肉在天畔，來看野翁憐子孫。"]'),
('7fd118d8-0ad5-40b2-8545-eef1e5b1b536','戰城南','曹鄴','唐','唐诗','tang','','[]','千金畫陣圖，自爲弓劍苦。',48,'全唐诗/poet.tang.32000.json','["千金畫陣圖，自爲弓劍苦。", "殺盡田野人，將軍猶愛武。", "性命換他恩，功成誰作主。", "鳳皇樓上人，夜夜長歌舞。"]'),
('efdedbea-7500-4389-b538-a61fc3b631f5','自退','曹鄴','唐','唐诗','tang','','[]','寒女面如花，空寂常對影。',24,'全唐诗/poet.tang.32000.json','["寒女面如花，空寂常對影。", "況我不嫁容，甘爲瓶墮井。"]'),
('0a5fd1f2-96d6-45ca-9076-2db177bc3645','早起','曹鄴','唐','唐诗','tang','','[]','月墮滄浪西，門開樹無影。',24,'全唐诗/poet.tang.32000.json','["月墮滄浪西，門開樹無影。", "此時歸夢闌，立在梧桐井。"]'),
('e10df934-0d17-43e9-b919-be99d05fb292','古相送','曹鄴','唐','唐诗','tang','','[]','行人卜去期，白髮根已出。',60,'全唐诗/poet.tang.32000.json','["行人卜去期，白髮根已出。", "執君青松枝，空數別來日。", "心如七夕女，生死難再匹。", "且願車聲迫，莫使馬行疾。", "巫山千丈高，亦恐夢相失。"]'),
('bd229e13-32ec-4068-99a7-22c4475bb0df','甲第','曹鄴','唐','唐诗','tang','','[]','遊人未入門，花影出門前。',24,'全唐诗/poet.tang.32000.json','["遊人未入門，花影出門前。", "將軍來此住，十里無荒田。"]'),
('04a01491-ac75-4879-a39b-30198439af5a','望不來','曹鄴','唐','唐诗','tang','','[]','見花憶郎面，常願花色新。',24,'全唐诗/poet.tang.32000.json','["見花憶郎面，常願花色新。", "爲郎容貌好，難有相似人。"]'),
('39957c11-2ba2-4503-a8f4-7e1382888d1d','官倉鼠','曹鄴','唐','唐诗','tang','','[]','官倉老鼠大如斗，見人開倉亦不走。',32,'全唐诗/poet.tang.32000.json','["官倉老鼠大如斗，見人開倉亦不走。", "健兒無糧百姓飢，誰遣朝朝入君口。"]'),
('cf217212-29a8-45fd-b472-9f76c8a74166','題濮廟','曹鄴','唐','唐诗','tang','','[]','曉祭瑤齋夜扣鐘，鼇頭風起浪重重。',64,'全唐诗/poet.tang.32000.json','["曉祭瑤齋夜扣鐘，鼇頭風起浪重重。", "人間直有仙桃種，海上應無肉馬蹤。", "赤水夢沈迷象罔，翠華恩斷泣芙蓉。", "不知皇帝三宮駐，始向人間著衮龍。"]'),
('66d4ee21-7a8e-4fc7-a988-c238fdd07add','偶題','曹鄴','唐','唐诗','tang','','[]','白玉先生多在市，青牛道士不居山。',32,'全唐诗/poet.tang.32000.json','["白玉先生多在市，青牛道士不居山。", "但能共得丹田語，正是忙時身亦閑。"]'),
('7504f5f2-8425-4a19-aeb9-2ae145df7ae9','登岳陽樓有懷寄座主相公','曹鄴','唐','唐诗','tang','','["\u5cb3\u9633\u697c"]','南登岳陽樓，北眺長安道。',72,'全唐诗/poet.tang.32000.json','["南登岳陽樓，北眺長安道。", "不見昇平里，千山樹如草。", "骨肉在南楚，沈憂起常早。", "白社愁成空，秋蕪待誰掃。", "常聞詩人語，西子不宜老。", "賴識丹元君，時來語蓬島。"]'),
('a87ff370-52c9-455a-8379-530e0edef59b','出關','曹鄴','唐','唐诗','tang','','[]','山上黃犢走避人，山下女郎歌滿野。',32,'全唐诗/poet.tang.32000.json','["山上黃犢走避人，山下女郎歌滿野。", "我獨南征恨此身，更有無成出關者。"]'),
('74e4a29e-b113-4803-89fc-8025342c30ef','將赴天平職書懷寄翰林從兄','曹鄴','唐','唐诗','tang','','[]','居處絕人事，門前雀羅施。',156,'全唐诗/poet.tang.32000.json','["居處絕人事，門前雀羅施。", "誰遣辟書至，僕隸皆展眉。", "匹馬渡河洛，西風飄路岐。", "手執王粲筆，閑吟向旌旗。", "香晚翠蓮動，吟餘紅燭移。", "開口啖酒肉，將何報相知。", "況我魏公子，相願不相疑。", "豈學官倉鼠，飽食無所爲。", "白露霑碧草，芙蓉落清池。", "自小不到處，全家忽如歸。", "吾宗處清切，立在白玉墀。", "方得一侍座，單車又星飛。", "願將門底水，永託萬頃陂。"]'),
('a86077d4-d321-4bff-9003-658421d06acc','賀雪寄本府尚書','曹鄴','唐','唐诗','tang','','[]','雨雪不順時，陰陽失明晦。',96,'全唐诗/poet.tang.32000.json','["雨雪不順時，陰陽失明晦。", "麥根半成土，農夫泣相對。", "我公誠訴天，天地忽已泰。", "長飆卷白雲，散落羣峰外。", "拂砌花影明，交宮鶴翎碎。", "宿鳥晨不飛，猶疑月光在。", "碧樹香盡發，蠹蟲聲漸退。", "有客懷兔園，吟詩遶城內。"]'),
('32b868a8-bad0-4520-b062-fb6a815dd876','寄嵩陽道人','曹鄴','唐','唐诗','tang','','[]','三山浮海倚蓬瀛，路入真元險盡平。',64,'全唐诗/poet.tang.32000.json','["三山浮海倚蓬瀛，路入真元險盡平。", "華表千年孤鶴語，人間一夢晚蟬鳴。", "將龍逐虎神初王，積火焚心氣漸清。", "見說嵩陽有仙客，欲持金簡問長生。"]'),
('09dbbd55-91ec-490c-8be1-10c7f9d326ed','去不返','曹鄴','唐','唐诗','tang','','[]','寒女不自知，嫁爲公子妻。',84,'全唐诗/poet.tang.32000.json','["寒女不自知，嫁爲公子妻。", "親情未識面，明日便東西。", "但得上馬了，一去頭不回。", "雙輪如鳥飛，影盡東南街。", "九重十二門，一門四扇開。", "君從此路去，妾向此路啼。", "但得見君面，不辭插荆釵。"]'),
('8d069148-0ce1-4eb6-af19-e7feb6d4fc57','送進士下第歸南海','曹鄴','唐','唐诗','tang','','[]','數片紅霞映夕陽，攬君衣袂更移觴。',64,'全唐诗/poet.tang.32000.json','["數片紅霞映夕陽，攬君衣袂更移觴。", "行人莫歎碧雲晚，上國每年春草芳。", "雪過藍關寒氣薄，鴈回湘浦怨聲長。", "應無惆悵滄波遠，十二玉樓非我鄉。"]'),
('77544c22-c1f5-4e3c-b4e3-978cb829a6a8','送厲圖南下第歸澧州','曹鄴','唐','唐诗','tang','','[]','當春人盡歸，我獨無歸計。',108,'全唐诗/poet.tang.32000.json','["當春人盡歸，我獨無歸計。", "送君自多感，不是緣下第。", "君看山上草，盡有干雲勢。", "結根既不然，何必更掩袂。", "澧水鱸魚賤，荆門楊柳細。", "勿爲陽豔留，此處有月桂。", "言畢尊未乾，十二門欲閉。", "佇立望不見，登高更流涕。", "吟君別我詩，悵望水煙際。"]'),
('452192c3-4147-4f17-89e8-745dabec9fcc','思不見','曹鄴','唐','唐诗','tang','','[]','但見出門蹤，不見入門跡。',24,'全唐诗/poet.tang.32000.json','["但見出門蹤，不見入門跡。", "却笑山頭女，無端化爲石。"]'),
('f5326d1c-04a3-4bbd-9301-fa8132fda3e5','貴宅','曹鄴','唐','唐诗','tang','','[]','入門又到門，到門戟相對。',72,'全唐诗/poet.tang.32000.json','["入門又到門，到門戟相對。", "玉簫聲尚遠，疑似人不在。", "公子厭花繁，買藥栽庭內。", "望遠不上樓，牕中見天外。", "此地日烹羊，無異我食菜。", "自是愁人眼，見之若奢泰。"]'),
('324764f3-9736-4c3a-bd31-1a83f9aa7eec','下第寄知己','曹鄴','唐','唐诗','tang','','[]','長安孟春至，枯樹花亦發。',192,'全唐诗/poet.tang.32000.json','["長安孟春至，枯樹花亦發。", "憂人此時心，冷若松上雪。", "自知才不堪，豈敢頻泣血。", "所痛無罪者，明時屢遭刖。", "故山秋草多，一卷成古轍。", "夜來遠心起，夢見瀟湘月。", "大賢冠蓋高，何事憐屑屑。", "不令傷弓鳥，日暮飛向越。", "聞知感激語，胸中如有物。", "舉頭望青天，白日頭上沒。", "歸來通濟里，開戶山鼠出。", "中庭廣寂寥，但見薇與蕨。", "無慮數尺軀，委作泉下骨。", "唯愁攬清鏡，不見昨日髪。", "願憐閨中女，晚嫁唯守節。", "勿惜四座言，女巧難自說。"]'),
('ef02926e-8d11-4e30-8720-450e8fa3668d','吳宮宴','曹鄴','唐','唐诗','tang','','[]','吳宮城闕高，龍鳳遙相倚。',72,'全唐诗/poet.tang.32000.json','["吳宮城闕高，龍鳳遙相倚。", "四面鏗鼓鐘，中央列羅綺。", "春風時一來，蘭麝聞數里。", "三度明月落，青娥醉不起。", "江頭銕劍鳴，玉座成荒壘。", "適來歌舞處，未知身是鬼。"]'),
('23e95d93-c708-49ba-a7a6-9221cad5e3be','長相思','曹鄴','唐','唐诗','tang','','[]','翦妾身上巾，贈郎傷妾神。',48,'全唐诗/poet.tang.32000.json','["翦妾身上巾，贈郎傷妾神。", "郎車不暫停，妾貌寧長春。", "青天無停雪，滄海無停津。", "遣妾空牀夢，夜夜隨車輪。"]'),
('237d6fd8-620f-4a65-b8c9-bc6a5afbba3e','長城下','曹鄴','唐','唐诗','tang','','[]','遠水猶歸壑，征人合憶鄉。',48,'全唐诗/poet.tang.32000.json','["遠水猶歸壑，征人合憶鄉。", "泣多盈袖血，吟苦滿頭霜。", "楚國連天浪，衡門到海荒。", "何當生燕羽，時得近雕梁。"]'),
('c74bc100-e525-4aaa-8157-1825c540e887','成名後獻恩門','曹鄴','唐','唐诗','tang','','[]','爲物稍有香，心遭蠹虫嚙。',192,'全唐诗/poet.tang.32000.json','["爲物稍有香，心遭蠹虫嚙。", "平人登太行，萬萬車輪折。", "一辭桂嶺猨，九泣東門月。", "年年孟春時，看花不如雪。", "僻居城南隅，顏子須泣血。", "沈埋若九泉，誰肯開口說。", "辛勤學機杼，坐對秋燈滅。", "織錦花不常，見之盡云拙。", "自憐孤生竹，出土便有節。", "每聽浮競言，喉中似無舌。", "忽然風雷至，驚起池中物。", "拔上青雲巔，輕如一毫髪。", "瓏瓏金鎖甲，稍稍城烏絕。", "名字如鳥飛，數日便到越。", "幽蘭生雖晚，幽香亦難歇。", "何以保此身，終身事無缺。"]'),
('d129a7c0-5998-4c4f-bb36-462981c86c3d','贈道師','曹鄴','唐','唐诗','tang','','[]','舉世皆問人，唯師獨求己。',36,'全唐诗/poet.tang.32000.json','["舉世皆問人，唯師獨求己。", "一馬無四蹄，頃刻行千里。", "應笑北原上，丘墳亂如蟻。"]'),
('9ec3a6ca-627c-4404-89e2-c3b2ed761ae4','入關','曹鄴','唐','唐诗','tang','','[]','衡門亦無路，何況入西秦。',24,'全唐诗/poet.tang.32000.json','["衡門亦無路，何況入西秦。", "灸病不得穴，徒爲採艾人。"]'),
('a0c61417-2b6c-4cc4-ae33-8d4e2a16d721','聽劉尊師彈琴','曹鄴','唐','唐诗','tang','','[]','曾於清海獨聞蟬，又向空庭夜聽泉。',32,'全唐诗/poet.tang.32000.json','["曾於清海獨聞蟬，又向空庭夜聽泉。", "不似齋堂人靜處，秋聲長在七條弦。"]'),
('fd70c9ee-2527-43d0-89f6-a32bd4a3aa03','題山居','曹鄴','唐','唐诗','tang','','[]','掃葉煎茶摘葉書，心閑無夢夜窗虛。',32,'全唐诗/poet.tang.32000.json','["掃葉煎茶摘葉書，心閑無夢夜窗虛。", "只應光武恩波晚，豈是嚴君戀釣魚。"]'),
('75c8172b-2a0f-4dae-a71e-759beaa13207','關試前送進士姚潛下第歸南陽','曹鄴','唐','唐诗','tang','','[]','馬嘶殘日沒殘霞，二月東風便到家。',32,'全唐诗/poet.tang.33000.json','["馬嘶殘日沒殘霞，二月東風便到家。", "莫羨長安占春者，明年始見故園花。"]'),
('e21b24b3-dfad-42be-892b-2ab9e5a40a1b','滻川寄進士劉駕','曹鄴','唐','唐诗','tang','','[]','我家不背水，君身不向越。',48,'全唐诗/poet.tang.33000.json','["我家不背水，君身不向越。", "自是相憶苦，忽如經年別。", "山家草木寒，石上有殘雪。", "美人望不見，迢迢雲中月。"]'),
('bb3e6ce9-a0ed-4fde-bc98-20c297fc9ffa','翠孤至渚宮寄座主相公','曹鄴','唐','唐诗','tang','','[]','萬里一孤舟，春行夏方到。',192,'全唐诗/poet.tang.33000.json','["萬里一孤舟，春行夏方到。", "骨肉盡單羸，沈憂滿懷抱。", "羈孤相對泣，性命不相保。", "開戶山鼠驚，蟲聲亂秋草。", "白菌緣屋生，黃蒿擁籬倒。", "對此起長嗟，芳年亦須老。", "恩門爲宰相，出入用天道。", "忽於摧落間，收得青松操。", "全家到江陵，屋虛風浩浩。", "中腸自相伐，日夕如寇盜。", "其下有孤姪，其上有孀嫂。", "黃糧賤於土，一飯常不飽。", "天斜日光薄，地濕蟲呌噪。", "惟恐道忽消，形容益枯槁。", "古人於黃雀，豈望白環報。", "奉荅恩地恩，何慙以誠告。"]'),
('13e0bb32-de2b-4b23-a024-d97a8cabb41d','早秋宿田舍','曹鄴','唐','唐诗','tang','','[]','澗草疎疎螢火光，山月朗朗楓樹長。',32,'全唐诗/poet.tang.33000.json','["澗草疎疎螢火光，山月朗朗楓樹長。", "南村犢子夜聲急，應是欄邊新有霜。"]'),
('ea788b92-605b-4aad-8288-6413166ef2a1','旅次岳陽寄京中親故','曹鄴','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','君山南面浪連天，一客愁心兩處懸。',64,'全唐诗/poet.tang.33000.json','["君山南面浪連天，一客愁心兩處懸。", "身逐片帆歸楚澤，魂隨流水向秦川。", "月回浦北千尋雪，樹出湖東幾點煙。", "更欲登樓向西望，北風催上洞庭船。"]'),
('e9bb4b3e-bf8e-4fb8-a9cd-a6f7dba76100','題舒鄉','曹鄴','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','功名若及鴟夷子，必擬將舟泛洞庭。',32,'全唐诗/poet.tang.33000.json','["功名若及鴟夷子，必擬將舟泛洞庭。", "柳色湖光好相待，我心非醉亦非醒。"]'),
('4f6f6502-bd7f-4e24-b6a5-b5aaf60da6ed','碧尋宴上有懷知己','曹鄴','唐','唐诗','tang','','[]','荻花蘆葉滿溪流，一簇笙歌在水樓。',64,'全唐诗/poet.tang.33000.json','["荻花蘆葉滿溪流，一簇笙歌在水樓。", "金管曲長人盡醉，玉簪恩重獨生愁。", "女蘿力弱難逢地，桐樹心孤易感秋。", "莫怪當歡却惆悵，全家欲上五湖舟。"]'),
('213afecd-246c-4787-bdb4-1101de9acec5','從天平節度使遊平流園','曹鄴','唐','唐诗','tang','','[]','池塘靜於寺，俗事不到眼。',120,'全唐诗/poet.tang.33000.json','["池塘靜於寺，俗事不到眼。", "下馬如在山，令人忽疎散。", "明公有高思，到此遂長返。", "乘興挈一壺，折荷以爲盞。", "入竹藤似虵，侵牆水成蘚。", "幽鳥不識人，時來拂冠冕。", "沿流路若窮，及行路猶遠。", "洞中已云夕，洞口天未晚。", "自憐不羈者，寫物心常簡。", "飜愁此興多，引得嵇康嬾。"]'),
('eb056fbb-6fd2-4a5d-a4df-38cf4a90f587','故人寄茶','曹鄴','唐','唐诗','tang','','[]','劍外九華英，緘題下玉京。',72,'全唐诗/poet.tang.33000.json','["劍外九華英，緘題下玉京。", "開時微月上，碾處亂泉聲。", "半夜招僧至，孤吟對月烹。", "碧沈霞脚碎，香泛乳花輕。", "六腑睡神去，數朝詩思清。", "月餘不敢費，留伴肘書行。"]'),
('b2cd4b01-b82d-4f18-9c55-5f5f79b4e82c','東武吟','曹鄴','唐','唐诗','tang','','[]','心如山上虎，身若倉中鼠。',60,'全唐诗/poet.tang.33000.json','["心如山上虎，身若倉中鼠。", "惆悵倚市門，無人與之語。", "夜宴李將軍，欲望心相許。", "何曾聽我言，貪謔邯鄲女。", "獨上黃金臺，淒涼淚如雨。"]'),
('659904fd-5a08-470d-8963-1180f95540cc','薊北門行','曹鄴','唐','唐诗','tang','','[]','長河凍如石，征人夜中戍。',96,'全唐诗/poet.tang.33000.json','["長河凍如石，征人夜中戍。", "但恐筋力盡，敢憚將軍遇。", "古來死未歇，白骨礙官路。", "豈無一有功，可以高其墓。", "親戚牽衣泣，悲號自相顧。", "死者雖無言，那堪生者悟。", "不如無手足，得見齒髪暮。", "乃知七尺軀，却是速死具。"]'),
('51522634-af76-486e-af3b-38eb1f3d4137','金井怨','曹鄴','唐','唐诗','tang','','[]','西風吹急景，美人照金井。',24,'全唐诗/poet.tang.33000.json','["西風吹急景，美人照金井。", "不見面上花，却恨井中影。"]'),
('e8c77652-83ef-4e15-ac5b-0a746012a098','姑蘇臺','曹鄴','唐','唐诗','tang','','[]','南宮酒未銷，又宴姑蘇臺。',72,'全唐诗/poet.tang.33000.json','["南宮酒未銷，又宴姑蘇臺。", "美人和淚去，半夜閶門開。", "相對正歌舞，笑中聞鼓鼙。", "星散九重門，血流十二街。", "一去成萬古，臺盡人不回。", "時聞野田中，拾得黃金釵。"]'),
('7b95d2d6-592f-42b6-bd42-d58dc2bbe05c','夜坐有懷','曹鄴','唐','唐诗','tang','','[]','悄悄月出樹，東南若微霜。',72,'全唐诗/poet.tang.33000.json','["悄悄月出樹，東南若微霜。", "愁人不成寐，五月夜亦長。", "佳期杳天末，骨肉不在旁。", "年華且有恨，厥體難久康。", "人言力耕者，歲旱亦有糧。", "吾道固如此，安得苦倀倀。"]'),
('6057d85c-3a20-4225-9a40-a5abbbeab95f','寄監察從兄','曹鄴','唐','唐诗','tang','','[]','我祖居鄴地，鄴人識文星。',168,'全唐诗/poet.tang.33000.json','["我祖居鄴地，鄴人識文星。", "此地星已落，兼無古時城。", "古風既無根，千載難重生。", "空留建安書，傳說七子名。", "賤子生桂州，桂州山水清。", "自覺心貌古，兼合古人情。", "因爲二雅詩，出語有性靈。", "持來向長安，時得長者驚。", "芝草不爲瑞，還共木葉零。", "恨如轍中土，終歲填不平。", "吾宗戴豸冠，忽然入西京。", "憐其羽翼單，撫若親弟兄。", "松根已堅牢，松葉豈不榮。", "言罷眼無淚，心中如酒酲。"]'),
('83caa9e0-6022-4d7d-9057-88851ec4c280','樂府體','曹鄴','唐','唐诗','tang','','[]','蓮子房房嫩，菖蒲葉葉齊。',24,'全唐诗/poet.tang.33000.json','["蓮子房房嫩，菖蒲葉葉齊。", "共結池中根，不厭池中泥。"]'),
('04f91bb5-0deb-442b-b5fe-c95c11b3c515','棄婦','曹鄴','唐','唐诗','tang','','[]','嫁來未曾出，此去長別離。',72,'全唐诗/poet.tang.33000.json','["嫁來未曾出，此去長別離。", "父母亦有家，羞言何以歸。", "此日年且少，事姑常有儀。", "見多自成醜，不待顏色衰。", "何人不識寵，所嗟無自非。", "將欲告此意，四鄰已相疑。"]'),
('ce5fefd3-d775-4fae-94b7-b92a3f018732','讀李斯傳','曹鄴','唐','唐诗','tang','','[]','一車致三轂，本圖行地速。',60,'全唐诗/poet.tang.33000.json','["一車致三轂，本圖行地速。", "不知駕馭難，舉足成顛覆。", "欺暗尚不然，欺明當自戮。", "難將一人手，掩得天下目。", "不見三尺墳，雲陽草空綠。"]'),
('6f6ac3d7-9e04-4c74-9726-953c3455a4e6','文宗陵','曹鄴','唐','唐诗','tang','','[]','千年堯舜心，心成身已歿。',60,'全唐诗/poet.tang.33000.json','["千年堯舜心，心成身已歿。", "始隨蒼梧雲，不返蒼龍闕。", "宮女衣不香，黃金賜白髮。", "留此奉天下，所以無征伐。", "至今汨羅水，不葬大夫骨。"]'),
('c2e58e50-c4d6-47f9-bc4d-a4aa2d8509f1','偶懷','曹鄴','唐','唐诗','tang','','[]','開目不見路，常如夜中行。',60,'全唐诗/poet.tang.33000.json','["開目不見路，常如夜中行。", "最賤不自勉，中塗與誰爭。", "蓬爲沙所危，還向沙上生。", "一年秋不熟，安得便廢耕。", "顏子命未達，亦遇時人輕。"]'),
('b7862a36-d686-41f4-ab41-1218ec41e8fa','代羅敷誚使君','曹鄴','唐','唐诗','tang','','[]','常言愛嵩山，別妾向東京。',72,'全唐诗/poet.tang.33000.json','["常言愛嵩山，別妾向東京。", "朝來見人說，却知在石城。", "未必菖蒲花，只向石城生。", "自是使君眼，見物皆有情。", "麋鹿同上山，蓮藕同在泥。", "莫學天上日，朝東暮還西。"]'),
('5ba844ae-3349-45f1-81ba-435377b926a5','怨歌行','曹鄴','唐','唐诗','tang','','[]','丈夫好弓劍，行坐說金吾。',96,'全唐诗/poet.tang.33000.json','["丈夫好弓劍，行坐說金吾。", "喜聞有行役，結束不待車。", "官田贈倡婦，留妾待舅姑。", "舅姑皆已死，庭花半是蕪。", "中妹尋適人，生女亦嫁夫。", "何曾寄消息，他處却有書。", "嚴風厲中野，女子心易孤。", "貧賤又相負，封侯意何如。"]'),
('a22763d6-eb7f-4487-a68d-dad57e5ef898','南征怨','曹鄴','唐','唐诗','tang','','[]','萬浪東不回，昭王南征早。',36,'全唐诗/poet.tang.33000.json','["萬浪東不回，昭王南征早。", "龍舟沒何處，獨樹江上老。", "吾欲問水濱，宮殿已生草。"]'),
('5d51e68c-b647-45fd-9d4d-60f6b6134862','和潘安仁金谷集','曹鄴','唐','唐诗','tang','','[]','太守龍爲馬，將軍金作車。',48,'全唐诗/poet.tang.33000.json','["太守龍爲馬，將軍金作車。", "香飄十里風，風下綠珠歌。", "莫怪坐上客，歎君庭前花。", "明朝此池館，不是石崇家。"]'),
('14ba1dd5-dcb9-4023-9242-18c0893f1e54','不可見','曹鄴','唐','唐诗','tang','','[]','常聞貧賤夫，頭白終相待。',48,'全唐诗/poet.tang.33000.json','["常聞貧賤夫，頭白終相待。", "自從嫁黔婁，終歲長不在。", "君夢有雙影，妾夢空四鄰。", "常思勁北風，吹折雙車輪。"]'),
('43b18fa6-1a74-4a2c-9a82-515afc7c7c97','秦後作','曹鄴','唐','唐诗','tang','','[]','大道不居謙，八荒安苟得。',144,'全唐诗/poet.tang.33000.json','["大道不居謙，八荒安苟得。", "木中不生火，高殿禍頃刻。", "誰將白帝子，踐我禮義域。", "空持拔山志，欲奪天地德。", "軹道人不回，壯士斷消息。", "父母骨成薪，蟲蛇自相食。", "鼎亂陰陽疑，戰盡鬼神力。", "東郊龍見血，九土玄黃色。", "鼙鼓裂二景，妖星動中國。", "圓丘無日月，曠野失南北。", "徒流殺人血，神器終不忒。", "一馬渡空江，始知賢者賊。"]'),
('d59139f6-d716-432e-9366-a8aec7877108','薄命妾','曹鄴','唐','唐诗','tang','','[]','薄命常惻惻，出門見南北。',48,'全唐诗/poet.tang.33000.json','["薄命常惻惻，出門見南北。", "劉郎馬蹄疾，何處去不得？", "淚珠不可收，蟲絲不可織。", "知君綠桑下，更有新相識。"]'),
('cb2a401e-c1e8-475d-b784-8408f90836c4','放歌行','曹鄴','唐','唐诗','tang','','[]','莫唱放歌行，此歌臨楚水。',36,'全唐诗/poet.tang.33000.json','["莫唱放歌行，此歌臨楚水。", "人皆惡此聲，唱者終不已。", "三閭有何罪，不向枕上死。"]'),
('af3006ce-e15b-4d76-926e-280d575bc088','江西送人','曹鄴','唐','唐诗','tang','','[]','八月江上樓，西風令人愁。',84,'全唐诗/poet.tang.33000.json','["八月江上樓，西風令人愁。", "攜酒樓上別，盡見四山秋。", "但愁今日知，莫作他時疑。", "郎本不住此，無人泣望歸。", "何水不生波，何木不改柯。", "遙知明日恨，不如今日多。", "將心速投人，路遠人如何。"]'),
('7af8c5bf-75c5-4fed-a031-38451791bd4c','始皇陵下作','曹鄴','唐','唐诗','tang','','[]','千金買魚燈，泉下照狐兔。',60,'全唐诗/poet.tang.33000.json','["千金買魚燈，泉下照狐兔。", "行人上陵過，却弔扶蘇墓。", "纍纍壙中物，多於養生具。", "若使山可移，應將秦國去。", "舜歿雖在前，今猶未封樹。"]'),
('2ce227e4-72f0-41be-9bd2-570be177f1b7','洛原西望','曹鄴','唐','唐诗','tang','','[]','築城畏不堅，城堅心自毀。',36,'全唐诗/poet.tang.33000.json','["築城畏不堅，城堅心自毀。", "秦樹滿平原，秦人不居此。", "猶爲泣路者，無力報天子。"]'),
('49f9024b-7011-4947-ae86-7defeb5f67aa','趙城懷古','曹鄴','唐','唐诗','tang','','[]','邯鄲舊公子，騎馬又鳴珂。',60,'全唐诗/poet.tang.33000.json','["邯鄲舊公子，騎馬又鳴珂。", "手揮白玉鞭，不避五侯車。", "閑愁春日短，沽酒入倡家。", "一笑千萬金，醉中贈秦娥。", "如今高原上，樹樹白楊花。"]'),
('25d567c1-d798-453b-9d93-03c4b6e27cd5','代班姬','曹鄴','唐','唐诗','tang','','[]','寵極多妒容，乘車上金階。',84,'全唐诗/poet.tang.33000.json','["寵極多妒容，乘車上金階。", "歘然趙飛燕，不語到日西。", "手把菖蒲花，君王喚不來。", "常嫌鬢蟬重，乞人白玉釵。", "君心無定波，咫尺流不回。", "後宮門不掩，每夜黃鳥啼。", "買得千金賦，花顏已如灰。"]'),
('58df1f9b-e999-4898-92cb-b269b97c84da','庭草','曹鄴','唐','唐诗','tang','','[]','庭草根自淺，造化無遺功。',24,'全唐诗/poet.tang.33000.json','["庭草根自淺，造化無遺功。", "低回一寸心，不敢怨春風。"]'),
('6d61a1c1-8ab4-493c-b778-f3c2d7b4e5a2','過白起墓','曹鄴','唐','唐诗','tang','','[]','[夷]陵火焰滅，長平生氣低。',26,'全唐诗/poet.tang.33000.json','["[夷]陵火焰滅，長平生氣低。", "將軍臨老病，賜劍咸陽西。"]'),
('b148ee89-cd8e-45ff-ad26-fab4cc6a8d5e','對酒','曹鄴','唐','唐诗','tang','','[]','愛酒知是僻，難與性相捨。',36,'全唐诗/poet.tang.33000.json','["愛酒知是僻，難與性相捨。", "未必獨醒人，便是不飲者。", "晚歲無此物，何由住田野。"]'),
('422b759c-ce1f-4b20-9a7f-48df0b2f5417','續幽憤','曹鄴','唐','唐诗','tang','','[]','繁霜作陰起，朱火乘夕發。',108,'全唐诗/poet.tang.33000.json','["繁霜作陰起，朱火乘夕發。", "清晝冷無光，蘭膏坐銷歇。", "惟公執天憲，身是臺中傑。", "一逐楚大夫，何人爲君雪。", "怱怱鬼方路，不許辭雙闕。", "過門似他鄉，舉趾如遺轍。", "八月黃草生，洪濤入雲熱。", "危魂沒太行，客弔空骨節。", "千年瘴江水，恨聲流不絕。"]'),
('c2c5611d-3cf9-4262-b6c2-76663785c655','古詞','曹鄴','唐','唐诗','tang','','[]','高闕礙飛鳥，人言是君家。',48,'全唐诗/poet.tang.33000.json','["高闕礙飛鳥，人言是君家。", "經年不歸去，愛妾面上花。", "妾面雖有花，妾心非女蘿。", "郎妻自不重，於妾欲如何。"]'),
('6bf47740-a44c-45f3-8224-e11bcfd29dfd','和謝豫章從宋公戲馬臺送孔令謝病','曹鄴','唐','唐诗','tang','','[]','碧樹杳云暮，朔風自西來。',48,'全唐诗/poet.tang.33000.json','["碧樹杳云暮，朔風自西來。", "佳人憶山水，置酒在高臺。", "不必問流水，坐來日已西。", "勸君速歸去，正及鷓鴣啼。"]'),
('64458e92-e680-4804-99da-aebca507210b','送進士李殷下第遊汾河','曹鄴','唐','唐诗','tang','','[]','上國花照地，遣君向西征。',120,'全唐诗/poet.tang.33000.json','["上國花照地，遣君向西征。", "旁人亦有恨，況復故人情。", "單車欲云去，別酒忽然醒。", "如何今夜夢，半作道路程。", "邊士不好禮，全家住軍城。", "城中鼓角嚴，旅客常夜驚。", "中有左記室，逢人眼光明。", "西門未歸者，下馬如到京。", "還應一開卷，爲子心不平。", "慇懃說忠抱，壯志勿自輕。"]'),
('55ae2bd6-7f22-471b-9e23-dd5d5df57061','相思極','曹鄴','唐','唐诗','tang','','[]','妾顏與日空，君心與日新。',60,'全唐诗/poet.tang.33000.json','["妾顏與日空，君心與日新。", "三年得一書，猶在湘之濱。", "料君相輕意，知妾無至親。", "況當受明禮，不令再嫁人。", "願君從此日，化質爲妾身。"]'),
('03cabdcf-db1c-4fb4-9d61-3a6b759849e1','代謝玄暉新亭送范零陵','曹鄴','唐','唐诗','tang','','[]','楚水洪無際，滄茫接天涯。',60,'全唐诗/poet.tang.33000.json','["楚水洪無際，滄茫接天涯。", "相看不能語，獨鳥下江蘺。", "蓬子悉有戀，蓬根却無期。", "車輪自不住，何必怨路岐。", "孟冬衣食薄，夢寐亦未遺。"]'),
('e9f4610e-7446-42fc-a7f5-ac149738b241','山中效陶','曹鄴','唐','唐诗','tang','','[]','落第非有罪，茲山聊歸止。',84,'全唐诗/poet.tang.33000.json','["落第非有罪，茲山聊歸止。", "山猨隔雲住，共飲山中水。", "讀書時有興，坐石忘却起。", "西山忽然暮，往往遺巾履。", "經時一出門，兼候僮僕喜。", "常被山翁笑，求名豈如此。", "齒髪老未衰，何如且求己。"]'),
('ebad722c-fbd2-497c-9124-6e6525bddecf','城南野居寄知己','曹鄴','唐','唐诗','tang','','[]','奔走未到我，在城如在村。',72,'全唐诗/poet.tang.33000.json','["奔走未到我，在城如在村。", "出門既無意，豈如常閉門。", "作詩二十載，闕下名不聞。", "無人爲開口，君子獨有言。", "身爲苦寒士，一笑亦感恩。", "慇懃中途上，勿使車無輪。"]'),
('9ab43e7f-3842-49bf-8592-7b75963a6d37','古莫買妾行','曹鄴','唐','唐诗','tang','','[]','千扉不當路，未似開一門。',24,'全唐诗/poet.tang.33000.json','["千扉不當路，未似開一門。", "若遣綠珠醜，石家應尚存。"]'),
('4d3e0c3b-f55b-41c7-b443-700e9822c07e','霽後作','曹鄴','唐','唐诗','tang','','[]','新霽辨草木，晚塘明衣衿。',48,'全唐诗/poet.tang.33000.json','["新霽辨草木，晚塘明衣衿。", "乳燕不歸宿，雙雙飛向林。", "微照露花影，輕雲浮麥陰。", "無人可招隱，盡日登山吟。"]'),
('14d9b7e4-9dd5-403f-8e83-79726a10b48a','田家効陶','曹鄴','唐','唐诗','tang','','[]','黑黍舂來釀酒飲，青禾刈了驅牛載。',32,'全唐诗/poet.tang.33000.json','["黑黍舂來釀酒飲，青禾刈了驅牛載。", "大姑小叔常在眼，却笑長安在天外。"]'),
('9d1ed4f9-2be3-42fe-8437-5dc19c364b1c','寄賈馳先輩','曹鄴','唐','唐诗','tang','','[]','游子想萬里，何必登高臺。',96,'全唐诗/poet.tang.33000.json','["游子想萬里，何必登高臺。", "聞君燕女吟，如自薊北來。", "長安高蓋多，健馬東西街。", "盡說蒿簪古，將錢買金釵。", "我祖西園事，言之獨傷懷。", "如今數君子，如鳥無樹棲。", "濟水一入河，便與清流乖。", "聞君欲自持，勿使吾道低。"]'),
('5d334072-026f-4e51-94ee-547266ce3559','送友人入塞','曹鄴','唐','唐诗','tang','','[]','亂蓬無根日，送子入青塞。',72,'全唐诗/poet.tang.33000.json','["亂蓬無根日，送子入青塞。", "蒼茫萬里秋，如見原野大。", "鳥雀寒不下，山川迥相對。", "一馬沒黃雲，登高望猶在。", "驚風忽然起，白日黯已晦。", "如何怨路長，出門天涯外。"]'),
('a0910ea0-295f-4444-9ce5-e12893ccd785','寄陽朔友人','曹鄴','唐','唐诗','tang','','[]','桂林須產千株桂，未解當天影日開。',32,'全唐诗/poet.tang.33000.json','["桂林須產千株桂，未解當天影日開。", "我到月中收得種，爲君移向故園栽。"]'),
('6f703808-03cc-4233-b67f-abd51a6e5856','題廣福巖','曹鄴','唐','唐诗','tang','','[]','未有天地先融結，方廣高深無丈尺。',32,'全唐诗/poet.tang.33000.json','["未有天地先融結，方廣高深無丈尺。", "書言不盡畫難成，留與人間作奇特。"]'),
('72d8bd9e-e6f4-4b5d-9de7-80f393387e6c','送曾德邁歸寧宜春','曹鄴','唐','唐诗','tang','','[]','湘東山水有清輝，袁水詞人得意歸。',64,'全唐诗/poet.tang.33000.json','["湘東山水有清輝，袁水詞人得意歸。", "幾府爭馳毛義檄，一鄉看侍老萊衣。", "筵開灞岸臨清淺，路去藍關入翠微。", "想到宜陽更無事，併將歡慶奉庭闈。"]'),
('05969c54-0adb-46cd-a50e-77903fee841f','送鄭谷歸宜春','曹鄴','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','無成歸故國，上馬亦高歌。',48,'全唐诗/poet.tang.33000.json','["無成歸故國，上馬亦高歌。", "況是飛鳴後，殊爲喜慶多。", "暑銷嵩嶽雨，涼吹洞庭波。", "莫便閑吟去，須期接盛科。"]'),
('165592d9-132a-4e3d-a2f2-7648bc4912a5','老圃堂','曹鄴','唐','唐诗','tang','','[]','邵平瓜地接吾廬，穀雨乾時手自鋤。',32,'全唐诗/poet.tang.33000.json','["邵平瓜地接吾廬，穀雨乾時手自鋤。", "昨日春風欺不在，就牀吹落讀殘書。"]'),
('d7c00b92-63f5-4b63-82d3-1c1593120bf0','登蕪城','儲嗣宗','唐','唐诗','tang','','[]','昔人登此地，丘壠已前悲。',24,'全唐诗/poet.tang.33000.json','["昔人登此地，丘壠已前悲。", "今日又非昔，春風能幾時。"]'),
('63d4cee5-6784-4c85-80fe-c44b706c3c8d','滄浪峽','儲嗣宗','唐','唐诗','tang','','[]','滄浪臨古道，道上石成塵。',24,'全唐诗/poet.tang.33000.json','["滄浪臨古道，道上石成塵。", "自有滄浪峽，誰爲無事人。"]'),
('f38ff230-45c0-4eb7-b7dc-32ca0c7595c9','垓城','儲嗣宗','唐','唐诗','tang','','[]','百戰未言非，孤軍驚夜圍。',24,'全唐诗/poet.tang.33000.json','["百戰未言非，孤軍驚夜圍。", "山河意氣盡，淚濕美人衣。"]'),
('ff4bb671-6a7e-45ac-b70b-7f529a5e340e','南陂遠望','儲嗣宗','唐','唐诗','tang','','[]','閑門橫古塘，紅樹已驚霜。',48,'全唐诗/poet.tang.33000.json','["閑門橫古塘，紅樹已驚霜。", "獨立望秋草，野人耕夕陽。", "孤煙起蝸舍，飛鷺下漁梁。", "唯有田家事，依依似故鄉。"]'),
('a318c56a-bb7b-413a-93b1-c8fa74e0a44d','宿玉簫宮','儲嗣宗','唐','唐诗','tang','','[]','塵飛不到空，露濕翠微宮。',48,'全唐诗/poet.tang.33000.json','["塵飛不到空，露濕翠微宮。", "鶴影石橋月，簫聲松殿風。", "綠毛辭世女，白髮入壺翁。", "借問燒丹處，桃花幾遍紅。"]'),
('ff0b746f-956d-4839-b04f-6692143dab99','晚眺徐州延福寺','儲嗣宗','唐','唐诗','tang','','[]','杉風振旅塵，晚景籍芳茵。',48,'全唐诗/poet.tang.33000.json','["杉風振旅塵，晚景籍芳茵。", "片水明在野，萬花深見人。", "靜依歸鶴思，遠惜舊山春。", "今日惜攜手，寄懷吟白蘋。"]'),
('51691ff6-b2b0-41f3-a438-1ed553c05963','宿甘棠館','儲嗣宗','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','塵跡入門盡，悄然江海心。',48,'全唐诗/poet.tang.33000.json','["塵跡入門盡，悄然江海心。", "水聲巫峽遠，山色洞庭深。", "風桂落寒子，嵐煙凝夕陰。", "前軒鶴歸處，蘿月思沈沈。"]'),
('2ee654cb-7831-4f83-bac6-7b9df8a1e4ae','和茅山高拾遺憶山中雜題五首 山泉','儲嗣宗','唐','唐诗','tang','','[]','香味清機仙府回，縈紆亂石便流桮。',32,'全唐诗/poet.tang.33000.json','["香味清機仙府回，縈紆亂石便流桮。", "春風莫泛桃花去，恐引凡人入洞來。"]'),
('af37e371-bdf1-4ce9-8a11-8a3a5dbc9ad5','和茅山高拾遺憶山中雜題五首 巢鶴','儲嗣宗','唐','唐诗','tang','','[]','千萬雲間丁令威，殷勤仙骨莫先飛。',32,'全唐诗/poet.tang.33000.json','["千萬雲間丁令威，殷勤仙骨莫先飛。", "若逢茅氏傳消息，貞白先生不久歸。"]'),
('6772214c-f5e9-490d-b036-995940eaf5aa','和茅山高拾遺憶山中雜題五首 胡山','儲嗣宗','唐','唐诗','tang','','[]','犬入五雲音信絕，鳳樓凝碧悄無聲。',32,'全唐诗/poet.tang.33000.json','["犬入五雲音信絕，鳳樓凝碧悄無聲。", "焚香古洞步虛夜，露濕松花空月明。"]'),
('5bf35a29-fa16-42e8-b003-eeb90a810059','和茅山高拾遺憶山中雜題五首 小樓','儲嗣宗','唐','唐诗','tang','','[]','松杉風外亂山青，曲几焚香對石屏。',32,'全唐诗/poet.tang.33000.json','["松杉風外亂山青，曲几焚香對石屏。", "空憶去年春雨後，燕泥時污太玄經。"]'),
('67021893-3b84-49c4-aab6-a1b4c385abc8','和茅山高拾遺憶山中雜題五首 山鄰','儲嗣宗','唐','唐诗','tang','','[]','石橋春澗已歸遲，夢入仙山山不知。',32,'全唐诗/poet.tang.33000.json','["石橋春澗已歸遲，夢入仙山山不知。", "柱史從來非俗吏，青牛道士莫相疑。"]'),
('ad155069-4162-4677-8719-bb1185d00fce','送道士','儲嗣宗','唐','唐诗','tang','','[]','泠然御風客，與道自浮沈。',36,'全唐诗/poet.tang.33000.json','["泠然御風客，與道自浮沈。", "黃鶴有歸語，白雲無忌心。", "藥爐經月淨，天路入壺深。"]'),
('732a95b0-510c-413f-a9ac-9114fad2c7e4','宿山館','儲嗣宗','唐','唐诗','tang','','[]','寂寞對衰草，地涼凝露華。',48,'全唐诗/poet.tang.33000.json','["寂寞對衰草，地涼凝露華。", "蟬鳴月中樹，風落客前花。", "山館無宿伴，秋琴初別家。", "自憐千萬里，筆硯寄生涯。"]'),
('764f8d40-8232-4f03-a23e-4eb1162d9c9b','入浮石山','儲嗣宗','唐','唐诗','tang','','[]','斜日出門去，殘花已過春。',48,'全唐诗/poet.tang.33000.json','["斜日出門去，殘花已過春。", "鳥聲穿葉遠，虎跡渡溪新。", "入洞幾時路，耕田何代人。", "自慙非避俗，不敢問迷津。"]'),
('428a56ca-f04a-4362-a970-d68d59665a5b','送人歸故園','儲嗣宗','唐','唐诗','tang','','[]','遠節慘言別，況予心久違。',48,'全唐诗/poet.tang.33000.json','["遠節慘言別，況予心久違。", "從來憶家淚，今日送君歸。", "野路正風雪，還鄉猶布衣。", "里中耕稼者，應笑讀書非。"]'),
('b0d55f12-3584-4d12-b363-f13377b3344f','得越中書','儲嗣宗','唐','唐诗','tang','','[]','芳草離離思，悠悠春夢餘。',48,'全唐诗/poet.tang.33000.json','["芳草離離思，悠悠春夢餘。", "池亭千里月，煙水一封書。", "詩想懷康樂，文應弔子胥。", "扁舟戀南越，豈獨爲鱸魚。"]'),
('a5d43c3e-dc53-4e87-9ea8-4d88b58c1cae','秋墅','儲嗣宗','唐','唐诗','tang','','[]','欲暮候樵者，望山空翠微。',48,'全唐诗/poet.tang.33000.json','["欲暮候樵者，望山空翠微。", "虹隨餘雨散，鵶帶夕陽歸。", "窮巷長秋草，孤村時擣衣。", "誰知多病客，寂寞掩柴扉。"]'),
('46355098-8657-4f78-9520-e647414a9b6a','哭彭先生','儲嗣宗','唐','唐诗','tang','','[]','谷口溪聲客自傷，那堪嗚咽弔殘陽。',64,'全唐诗/poet.tang.33000.json','["谷口溪聲客自傷，那堪嗚咽弔殘陽。", "空階鶴戀丹青影，秋雨苔封白石牀。", "主祭孤兒初學語，無媒旅櫬未還鄉。", "門人遠赴心喪夜，月滿千山舊草堂。"]'),
('6578c29d-0080-4b10-ba30-1dbb2f3fe55a','和顧非熊先生題茅山處士閑居','儲嗣宗','唐','唐诗','tang','','[]','歸耕地肺絕塵喧，匣裏青萍未報恩。',64,'全唐诗/poet.tang.33000.json','["歸耕地肺絕塵喧，匣裏青萍未報恩。", "濁酒自憐終日醉，古風時得野人言。", "鳥啼碧樹閑臨水，花滿青山靜掩門。", "唯有階前芳草色，年年惆悵憶王孫。"]'),
('2e1ca25e-b18e-4463-b5ec-bc5f9c90c779','長安懷古','儲嗣宗','唐','唐诗','tang','','[]','禍稔蕭牆終不知，生人力屈盡邊陲。',64,'全唐诗/poet.tang.33000.json','["禍稔蕭牆終不知，生人力屈盡邊陲。", "赤龍已赴東方暗，黃犬徒懷上蔡悲。", "面缺崩城山寂寂，土埋冤骨草離離。", "秋風解怨扶蘇死，露泣煙愁紅樹枝。"]'),
('2f43ccde-077b-4649-9885-5de654e2ba99','過王右丞書堂二首 一','儲嗣宗','唐','唐诗','tang','','[]','澄潭昔臥龍，章句世爲宗。',48,'全唐诗/poet.tang.33000.json','["澄潭昔臥龍，章句世爲宗。", "獨步聲名在，千巖水石空。", "野禽悲灌木，落日弔清風。", "後學攀遺址，秋山聞草蟲。"]'),
('5e523309-797b-47ff-9912-177983673fb5','過王右丞書堂二首 二','儲嗣宗','唐','唐诗','tang','','[]','萬樹影參差，石牀藤半垂。',48,'全唐诗/poet.tang.33000.json','["萬樹影參差，石牀藤半垂。", "螢光雖散草，鳥跡尚臨池。", "風雅傳今日，雲山想昔時。", "感深蘇屬國，千載五言詩。"]'),
('e41c8c12-4c7f-42d9-b745-b6510fd08826','孤鴈','儲嗣宗','唐','唐诗','tang','','[]','孤鴈暮飛急，蕭蕭天地秋。',48,'全唐诗/poet.tang.33000.json','["孤鴈暮飛急，蕭蕭天地秋。", "關河正黃葉，消息斷青樓。", "湘渚煙波遠，驪山風雨愁。", "此時萬里道，魂夢遶滄洲。"]'),
('3044df48-9157-42e3-ba26-22b173c89d65','贈隱者','儲嗣宗','唐','唐诗','tang','','[]','盡室居幽谷，亂山爲四鄰。',48,'全唐诗/poet.tang.33000.json','["盡室居幽谷，亂山爲四鄰。", "霧深知有術，窗靜似無人。", "鶴語松上月，花明雲裏春。", "生涯更何許，尊酒與垂綸。"]'),
('b9aa0413-27a1-47de-bc93-aabf3655165c','早春懷薛公裕','儲嗣宗','唐','唐诗','tang','','[]','幽獨自成愚，柴門日漸蕪。',48,'全唐诗/poet.tang.33000.json','["幽獨自成愚，柴門日漸蕪。", "陸機初入洛，孫楚又遊吳。", "失意怨楊柳，異鄉聞鷓鴣。", "相思復相望，春草滿南湖。"]'),
('54badba5-d4ae-4421-a311-520951f1a6de','村月','儲嗣宗','唐','唐诗','tang','','[]','月午籬南道，前村半隱林。',24,'全唐诗/poet.tang.33000.json','["月午籬南道，前村半隱林。", "田翁獨歸處，蕎麥露花深。"]'),
('3e18e103-c4b3-4ef3-babe-ab3b98182945','早春','儲嗣宗','唐','唐诗','tang','','[]','野樹花初發，空山獨見時。',24,'全唐诗/poet.tang.33000.json','["野樹花初發，空山獨見時。", "踟躕歷陽道，鄉思滿南枝。"]'),
('b7bfdeee-d96a-4d85-b80f-d3f847e9d312','送友人遊吳','儲嗣宗','唐','唐诗','tang','','[]','吳山青楚吟，草色異鄉心。',48,'全唐诗/poet.tang.33000.json','["吳山青楚吟，草色異鄉心。", "一酌水邊酒，數聲花下琴。", "登樓舊國遠，探穴九疑深。", "更想逢秋節，那堪聞夜砧。"]'),
('210de100-1572-4311-a05a-e1e58d9115fa','贈別','儲嗣宗','唐','唐诗','tang','','[]','蘭澤傷秋色，臨風遠別期。',48,'全唐诗/poet.tang.33000.json','["蘭澤傷秋色，臨風遠別期。", "東城草雖綠，南浦柳無枝。", "直道豈易枉，暗投誰不疑。", "因君問行役，有淚濕江蘺。"]'),
('f3d4413c-87b8-4b03-9aa5-cae1db62356d','經故人舊居','儲嗣宗','唐','唐诗','tang','','[]','萬里訪遺塵，鶯聲淚濕巾。',48,'全唐诗/poet.tang.33000.json','["萬里訪遺塵，鶯聲淚濕巾。", "古書無主散，廢宅與山鄰。", "宿草風悲夜，荒村月弔人。", "淒涼問殘柳，今日爲誰春。"]'),
('fb03ecdc-7906-496d-8ce1-145e70d52627','隨邊使過五原','儲嗣宗','唐','唐诗','tang','','[]','偶逐星車犯虜塵，故鄉常恐到無因。',32,'全唐诗/poet.tang.33000.json','["偶逐星車犯虜塵，故鄉常恐到無因。", "五原西去陽關廢，日漫平沙不見人。"]'),
('387175f8-82d3-4590-ba08-86d56440f020','春懷寄秣陵知友','儲嗣宗','唐','唐诗','tang','','[]','廬江城外柳堪攀，萬里行人尚未還。',32,'全唐诗/poet.tang.33000.json','["廬江城外柳堪攀，萬里行人尚未還。", "借問景陽臺下客，謝家誰更臥東山。"]'),
('08e7991b-66c5-4c5d-8a80-03991b22b337','宋州月夜感懷','儲嗣宗','唐','唐诗','tang','','[]','鴈池衰草露霑衣，河水東流萬事微。',32,'全唐诗/poet.tang.33000.json','["鴈池衰草露霑衣，河水東流萬事微。", "寂寞青陵臺上月，秋風滿樹鵲南飛。"]'),
('bfe4266e-2a85-4118-bb52-d4ffb5734b64','吳宮','儲嗣宗','唐','唐诗','tang','','[]','荒臺荆棘多，忠諫竟如何。',48,'全唐诗/poet.tang.33000.json','["荒臺荆棘多，忠諫竟如何。", "細草迷宮巷，閑花悞綺羅。", "前溪徒自綠，子夜不聞歌。", "悵望清江暮，悠悠東去波。"]'),
('c05d5900-1103-49c8-99e2-52a7cb8d64f6','春遊望仙谷','儲嗣宗','唐','唐诗','tang','','[]','清無車馬塵，深洞百花春。',48,'全唐诗/poet.tang.33000.json','["清無車馬塵，深洞百花春。", "雞犬疑霑藥，耕桑似避秦。", "登山採樵路，臨水浣紗人。", "若得心無事，移家便卜鄰。"]'),
('bc03cca9-a731-446d-86fb-e3f29c2a59e7','聖女祠','儲嗣宗','唐','唐诗','tang','','[]','石屏苔色涼，流水遶祠堂。',48,'全唐诗/poet.tang.33000.json','["石屏苔色涼，流水遶祠堂。", "巢鵲疑天漢，潭花似鏡妝。", "神來雲雨合，神去蕙蘭香。", "不復聞雙佩，山門空夕陽。"]'),
('6f211bfd-f0d2-4856-9c22-6ae0da212fb8','宿范水','儲嗣宗','唐','唐诗','tang','','[]','行人倦遊宦，秋草宿湖邊。',48,'全唐诗/poet.tang.33000.json','["行人倦遊宦，秋草宿湖邊。", "露濕芙蓉渡，月明漁網船。", "寒機深竹裏，遠浪到門前。", "何處思鄉甚，歌聲聞採蓮。"]'),
('8ff9d653-e25b-4768-bf03-272309414280','送顧陶校書歸錢塘','儲嗣宗','唐','唐诗','tang','','[]','清苦月偏知，南歸瘦馬遲。',48,'全唐诗/poet.tang.33000.json','["清苦月偏知，南歸瘦馬遲。", "橐輕緣換酒，髪白爲吟詩。", "水色西陵渡，松聲伍相祠。", "聖朝思直諫，不是挂冠時。"]'),
('6aace010-a5b3-4fad-8335-bf2d350b954c','題雲陽高少府衙齋','儲嗣宗','唐','唐诗','tang','','[]','大隱能兼濟，軒窗逐勝開。',48,'全唐诗/poet.tang.33000.json','["大隱能兼濟，軒窗逐勝開。", "遠含雲水思，深得棟梁材。", "吏散山逾靜，庭閑鳥自來。", "更憐幽砌色，秋雨長莓苔。"]'),
('9c66bf95-23a4-413d-93c7-e513af0f8356','早春山行','于武陵','唐','唐诗','tang','','[]','江草暖初綠，雁行皆北飛。',48,'全唐诗/poet.tang.33000.json','["江草暖初綠，雁行皆北飛。", "異鄉那久客，野鳥尚思歸。", "十載過如夢，素心應已違。", "行行家漸遠，更苦得書稀。"]'),
('3e97a7ac-d782-4b1a-be5d-19f4e7254885','宿友生林居因懷賈區','于武陵','唐','唐诗','tang','','[]','繞屋樹森森，多棲紫閣禽。',48,'全唐诗/poet.tang.33000.json','["繞屋樹森森，多棲紫閣禽。", "暫過當永夜，微得話前心。", "入楚行應遠，經湘恨必深。", "那堪對寒燭，更賦別離吟。"]'),
('77500d86-66f5-4c69-9a16-a6c015ff1316','贈賣松人','于武陵','唐','唐诗','tang','','[]','入市雖求利，憐君意獨真。',48,'全唐诗/poet.tang.33000.json','["入市雖求利，憐君意獨真。", "劚將寒澗樹，賣與翠樓人。", "瘦葉幾經雪，淡花應少春。", "長安重桃李，徒染六街塵。"]'),
('9e1ba79b-15a6-4918-b802-5a850339f895','友人南遊不回因而有寄','于武陵','唐','唐诗','tang','','[]','相思春樹綠，千里亦依依。',48,'全唐诗/poet.tang.33000.json','["相思春樹綠，千里亦依依。", "鄠杜月頻滿，瀟湘人未歸。", "桂花風半落，煙草蝶雙飛。", "一別無消息，水南車跡稀。"]'),
('993d3680-c8df-4d06-951f-d9ac0b1b0fd6','送酇縣董明府之任','于武陵','唐','唐诗','tang','','[]','南北行已久，憐君知苦辛。',48,'全唐诗/poet.tang.33000.json','["南北行已久，憐君知苦辛。", "萬家同草木，三載得陽春。", "東道聽遊子，夷門歌主人。", "空持語相送，應怪不沾巾。"]'),
('86b2dd1e-6064-4bec-a82c-e676358bca13','山上樹','于武陵','唐','唐诗','tang','','[]','日暖上山路，鳥啼知已春。',48,'全唐诗/poet.tang.33000.json','["日暖上山路，鳥啼知已春。", "忽逢幽隱處，如見獨醒人。", "石冷開常晚，風多落亦頻。", "樵夫應不識，歲久伐爲薪。"]'),
('d4e17e65-563a-444a-8425-585b85c1a690','長信宮二首 一','于武陵','唐','唐诗','tang','','[]','簟涼秋氣初，長信恨何如。',48,'全唐诗/poet.tang.33000.json','["簟涼秋氣初，長信恨何如。", "拂黛月生指，解鬟雲滿梳。", "一從悲畫扇，幾度泣前魚。", "坐聽南宮樂，涼風搖翠裾。"]'),
('c17ac577-70aa-4c87-a92e-33449e28e2e4','長信宮二首 二','于武陵','唐','唐诗','tang','','[]','一失輦前恩，綺羅生暗塵。',48,'全唐诗/poet.tang.33000.json','["一失輦前恩，綺羅生暗塵。", "惟應深夜月，獨伴向隅人。", "長信翠蛾老，昭陽紅粉新。", "君心似秋節，不使草長春。"]'),
('8e55b522-700b-450a-b06b-2a0154760960','洛陽道','于武陵','唐','唐诗','tang','','[]','浮世若浮雲，千回故復新。',50,'全唐诗/poet.tang.33000.json','["浮世若浮雲，千回故復新。", "旋添青草塚，更有白頭人。", "歲暮容將老，雪晴山欲春。", "行行車與馬，不盡洛陽[塵]。"]'),
('87313651-f5ef-4a96-b735-33e041492482','東門路','于武陵','唐','唐诗','tang','','[]','東門車馬路，此路在浮沈。',48,'全唐诗/poet.tang.33000.json','["東門車馬路，此路在浮沈。", "白日若不落，紅塵應更深。", "從來名利地，皆起是非心。", "所以青青草，年年生漢陰。"]'),
('8c210115-e684-45e9-a22a-03134280ab2a','江樓春望','于武陵','唐','唐诗','tang','','["\u957f\u6c5f"]','樓下長江路，舟車晝不閑。',48,'全唐诗/poet.tang.33000.json','["樓下長江路，舟車晝不閑。", "鳥聲非故國，春色是他山。", "一望雲復水，幾重河與關。", "愁心隨落日，萬里各西還。"]'),
('062843e1-5ecb-4cd6-a345-5c3df2c723bc','洛中晴望','于武陵','唐','唐诗','tang','','[]','九陌盡風塵，囂囂晝復昏。',48,'全唐诗/poet.tang.33000.json','["九陌盡風塵，囂囂晝復昏。", "古今人不斷，南北路長存。", "葉落上陽樹，草衰金谷園。", "亂鴉歸未已，殘日半前軒。"]'),
('af61ba07-a8a5-4490-8690-92885211bf8b','西歸','于武陵','唐','唐诗','tang','','[]','不繫與舟閑，悠悠吳楚間。',48,'全唐诗/poet.tang.33000.json','["不繫與舟閑，悠悠吳楚間。", "羞將新白髮，却到舊青山。", "一葉忽離樹，幾人同入關。", "長安家尚在，秋至又西還。"]'),
('5e631c0c-f828-4741-b846-03a43846dbb1','南遊','于武陵','唐','唐诗','tang','','[]','窮秋幾日雨，處處生蒼苔。',48,'全唐诗/poet.tang.33000.json','["窮秋幾日雨，處處生蒼苔。", "舊國寄書後，涼天方雁來。", "露繁山草濕，洲暖水花開。", "去盡同行客，一帆猶未回。"]'),
('4f61b869-0092-48ac-9666-788a5efd4062','南遊有感','于武陵','唐','唐诗','tang','','[]','杜陵無厚業，不得駐車輪。',48,'全唐诗/poet.tang.33000.json','["杜陵無厚業，不得駐車輪。", "重到曾遊處，多非舊主人。", "東風千嶺樹，西日一洲蘋。", "又渡湘江去，湘江水復春。"]'),
('c56ad06f-0556-40c9-a32b-cdd4cc2536c8','夜泊湘江','于武陵','唐','唐诗','tang','','[]','北風吹楚樹，此地獨先秋。',48,'全唐诗/poet.tang.33000.json','["北風吹楚樹，此地獨先秋。", "何事屈原恨，不隨湘水流。", "涼天生片月，竟夕伴孤舟。", "一作南行客，無成空白頭。"]'),
('b4063941-d6b5-44fa-8314-8d21ce7c72f6','客中','于武陵','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','楚人歌竹枝，遊子淚沾衣。',48,'全唐诗/poet.tang.33000.json','["楚人歌竹枝，遊子淚沾衣。", "異國久爲客，寒宵頻夢歸。", "一封書未返，千樹葉皆飛。", "南過洞庭水，更應消息稀。"]'),
('05550026-ed07-485f-8d78-30ff5efe139f','夜尋僧不遇','于武陵','唐','唐诗','tang','','[]','數歇度煙水，漸非塵俗間。',36,'全唐诗/poet.tang.33000.json','["數歇度煙水，漸非塵俗間。", "泉聲入秋寺，月色遍寒山。", "石路幾回雪，竹房猶閉關。"]'),
('377085fe-7f0d-4d15-a2bb-b549953c8756','訪道者不遇','于武陵','唐','唐诗','tang','','[]','人間惟此路，長得綠苔衣。',48,'全唐诗/poet.tang.33000.json','["人間惟此路，長得綠苔衣。", "及戶無行跡，遊方應未歸。", "平生無限事，到此盡知非。", "獨倚松門久，陰雲昏翠微。"]'),
('c77b72bd-fa5f-4cd2-a246-8a7f917a538e','贈王隱者山居','于武陵','唐','唐诗','tang','','[]','石室掃無塵，人寰與此分。',48,'全唐诗/poet.tang.33000.json','["石室掃無塵，人寰與此分。", "飛來南浦樹，半是華山雲。", "浮世幾多事，先生應不聞。", "寒山滿西日，空照雁成羣。"]'),
('64865458-b209-4602-903b-368e33557c97','寄北客','于武陵','唐','唐诗','tang','','[]','窮邊足風慘，何處醉樓臺？',48,'全唐诗/poet.tang.33000.json','["窮邊足風慘，何處醉樓臺？", "家去幾千里，月圓十二回。", "寒阡隨日遠，雪路向城開。", "遊子久無信，年年空雁來。"]'),
('787ee6f3-1a8b-4819-beee-66cbd3d4dda6','寄友人','于武陵','唐','唐诗','tang','','[]','長安清渭東，遊子跡重重。',48,'全唐诗/poet.tang.33000.json','["長安清渭東，遊子跡重重。", "此去紅塵路，難尋君馬蹤。", "昔時輕一別，漸老貴相逢。", "應戀嵩陽住，嵩陽饒古松。"]'),
('35dbf691-52f0-4794-8249-9a65a7c40ba0','夜與故人別','于武陵','唐','唐诗','tang','','[]','白日去難駐，故人非舊容。',48,'全唐诗/poet.tang.33000.json','["白日去難駐，故人非舊容。", "今宵一別後，何處更相逢？", "過楚水千里，到秦山幾重。", "語來天又曉，月落滿城鐘。"]'),
('4f2e509b-439e-4f70-85c3-3873b6188c57','別故人','于武陵','唐','唐诗','tang','','[]','行子與秋葉，各隨南北風。',48,'全唐诗/poet.tang.33000.json','["行子與秋葉，各隨南北風。", "雖非千里別，還阻一宵同。", "過盡少年日，尚如長轉蓬。", "猶爲布衣客，羞入故關中。"]'),
('e6ae9cbf-9abc-4ddb-9eb6-dd963a0d64a0','送客東歸','于武陵','唐','唐诗','tang','','[]','一聽遊子歌，秋計覺蹉跎。',48,'全唐诗/poet.tang.33000.json','["一聽遊子歌，秋計覺蹉跎。", "四海少平地，百川無定波。", "共驚年已暮，俱向客中多。", "又駕征輪去，東歸事若何。"]'),
('ed30533d-9b96-409e-a24a-157b44f80a05','過侯王故第','于武陵','唐','唐诗','tang','','[]','過此一酸辛，行人淚有痕。',36,'全唐诗/poet.tang.33000.json','["過此一酸辛，行人淚有痕。", "獨殘新碧樹，猶擁舊朱門。", "歌歇雲初散，簷空燕尚存。"]'),
('6bc9ff18-42a8-4070-942e-97b5491b8304','孤雲','于武陵','唐','唐诗','tang','','[]','南北各萬里，有雲心更閑。',48,'全唐诗/poet.tang.33000.json','["南北各萬里，有雲心更閑。", "因風離海上，伴月到人間。", "洛浦少高樹，長安無舊山。", "裴回不可駐，漠漠又空還。"]'),
('a4bc87d1-917a-49ce-b44a-774c2a772495','遠水','于武陵','唐','唐诗','tang','','[]','悔作望南浦，望中生遠愁。',48,'全唐诗/poet.tang.33000.json','["悔作望南浦，望中生遠愁。", "因知人易老，爲有水東流。", "欲附故鄉信，不逢歸客舟。", "萋萋兩岸草，又度一年秋。"]'),
('b12ab264-3bcb-4ff5-9a20-18a3539de09a','詠蟬','于武陵','唐','唐诗','tang','','[]','江頭一聲起，芳歲已難留。',48,'全唐诗/poet.tang.33000.json','["江頭一聲起，芳歲已難留。", "聽此高林上，遙知故國秋。", "應催風落葉，似勸客回舟。", "不是新蟬苦，年年自有愁。"]'),
('b0a9ac64-29ab-4736-ba5a-b6ef1c63709d','感情','于武陵','唐','唐诗','tang','','[]','青山長寂寞，南望獨高歌。',48,'全唐诗/poet.tang.33000.json','["青山長寂寞，南望獨高歌。", "四海故人盡，九原新壠多。", "西沈浮世日，東注逝川波。", "不使年華駐，此生能幾何。"]'),
('13f4b6aa-0b05-4e9b-bd72-3342943eaabf','早春日山居寄城郭知己','于武陵','唐','唐诗','tang','','[]','陽和潛發蕩寒陰，便使川原景象新。',64,'全唐诗/poet.tang.33000.json','["陽和潛發蕩寒陰，便使川原景象新。", "入戶風泉聲瀝瀝，當軒雲岫色沈沈。", "殘雲帶雨輕飄雪，嫩柳含煙小綻金。", "雖有眼前詩酒興，遨遊爭得稱閑心。"]'),
('76be7b9b-f0df-4352-b6fc-5476cdd9b86d','勸酒','于武陵','唐','唐诗','tang','','[]','勸君金屈巵，滿酌不須辭。',24,'全唐诗/poet.tang.33000.json','["勸君金屈巵，滿酌不須辭。", "花發多風雨，人生足別離。"]'),
('0f922efa-e0fb-4785-8b8e-2858871e463a','感懷','于武陵','唐','唐诗','tang','','[]','東風吹草色，空使客蹉跎。',48,'全唐诗/poet.tang.33000.json','["東風吹草色，空使客蹉跎。", "不設太平險，更應遊子多。", "幾傷行處淚，一曲醉中歌。", "盡向青門外，東隨渭水波。"]'),
('341677a8-5309-4c40-876c-bd9b8ebf00b4','友人亭松','于武陵','唐','唐诗','tang','','[]','俛仰不能去，如逢舊友同。',48,'全唐诗/poet.tang.33000.json','["俛仰不能去，如逢舊友同。", "曾因春雪散，見在華山中。", "何處有明月，訪君聽遠風。", "相將歸未得，各占石巖東。"]'),
('69c0403c-51ad-4c83-8897-3871bf6599cf','遊中梁山','于武陵','唐','唐诗','tang','','[]','僻地好泉石，何人曾陸沈。',48,'全唐诗/poet.tang.33000.json','["僻地好泉石，何人曾陸沈。", "不知青嶂外，更有白雲深。", "因此見喬木，幾回思舊林。", "慇懃猨與鳥，惟我獨何心。"]'),
('f5ecb93c-e460-4f49-ac31-981eacb358ec','尋山','于武陵','唐','唐诗','tang','','[]','到此絕車輪，萋萋草樹春。',48,'全唐诗/poet.tang.33000.json','["到此絕車輪，萋萋草樹春。", "青山如有利，白石亦成塵。", "水闊應無路，松深不見人。", "如知巢與許，千載跡猶新。"]'),
('5d86d3d3-2f4b-460c-9daa-901ad94d48a1','宿江口','于武陵','唐','唐诗','tang','','[]','南渡人來絕，喧喧雁滿沙。',48,'全唐诗/poet.tang.33000.json','["南渡人來絕，喧喧雁滿沙。", "自生江上月，長有客思家。", "半夜下霜岸，北風吹荻花。", "自驚歸夢斷，不得到天涯。"]'),
('cc95a4cf-7a62-4222-bfd2-ace824d91c46','秋夜達蕭關','于武陵','唐','唐诗','tang','','[]','擾擾浮梁路，人忙月自閑。',48,'全唐诗/poet.tang.33000.json','["擾擾浮梁路，人忙月自閑。", "去年爲塞客，今夜宿蕭關。", "辭國幾經歲，望鄉空見山。", "不知江葉下，又作布衣還。"]'),
('754d42b3-6014-4d86-952e-563b2ea215c3','斜谷道','于武陵','唐','唐诗','tang','','[]','亂峰連疊嶂，千里綠峨峨。',48,'全唐诗/poet.tang.33000.json','["亂峰連疊嶂，千里綠峨峨。", "蜀國路如此，遊人車亦過。", "遠煙當葉歛，驟雨逐風多。", "獨憶紫芝叟，臨風歌舊歌。"]'),
('5c3305e2-bd75-4885-9f1b-bb8e7a6c9fc1','過百牢關貽舟中者','于武陵','唐','唐诗','tang','','[]','蜀國少平地，方思京洛間。',48,'全唐诗/poet.tang.33000.json','["蜀國少平地，方思京洛間。", "遠爲千里客，來度百牢關。", "帆影清江水，鈴聲碧草山。", "不因名與利，爾我各應閑。"]'),
('a4a806a9-c7c3-4edd-abcf-884b670ca0f5','客中覽鏡','于武陵','唐','唐诗','tang','','[]','何當開此鏡，即見髪如絲。',48,'全唐诗/poet.tang.33000.json','["何當開此鏡，即見髪如絲。", "白日急於水，一年能幾時。", "每逢芳草處，長返故園遲。", "所以多爲客，蹉跎欲怨誰。"]'),
('a4f44ad7-76e1-4cb6-a9e7-a9b696c43dfd','長安逢隱者','于武陵','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','征車千里至，碾遍六街塵。',48,'全唐诗/poet.tang.33000.json','["征車千里至，碾遍六街塵。", "向此有營地，忽逢無事人。", "昔時顏未改，浮世路多新。", "且脫衣沽酒，終南山欲春。"]'),
('6cee9033-b776-47f3-a32d-376ca9a8b54a','與僧話舊','于武陵','唐','唐诗','tang','','[]','草堂前有山，一見一相寬。',48,'全唐诗/poet.tang.33000.json','["草堂前有山，一見一相寬。", "處世貴僧靜，青松因歲寒。", "他山逢舊侶，盡日話長安。", "所以閑行跡，千回遶藥欄。"]'),
('e58d8017-26e6-4a1a-a02a-8134ca7179ee','贈王道士','于武陵','唐','唐诗','tang','','[]','日日市朝路，何時無苦辛。',48,'全唐诗/poet.tang.33000.json','["日日市朝路，何時無苦辛。", "不隨丹竈客，終作白頭人。", "浮世度千載，桃源方一春。", "歸來華表上，應笑北邙塵。"]'),
('143d7943-75ea-46d3-8e19-cc66d5aee566','匣中琴','于武陵','唐','唐诗','tang','','[]','世人無正心，蟲網匣中琴。',48,'全唐诗/poet.tang.33000.json','["世人無正心，蟲網匣中琴。", "何以經時廢，非爲娛耳音。", "獨令高韻在，誰感隙塵深。", "應是南風曲，聲聲不合今。"]'),
('b1f3cfe0-e301-41c3-b900-05de34fd4775','過洛陽城','于武陵','唐','唐诗','tang','','[]','古來利與名，俱在洛陽城。',48,'全唐诗/poet.tang.33000.json','["古來利與名，俱在洛陽城。", "九陌鼓初起，萬車輪已行。", "周秦時幾變，伊洛水猶清。", "二月中橋路，鳥啼春草生。"]'),
('d95572e7-1166-419e-ad7c-3e14f75d722f','望月','于武陵','唐','唐诗','tang','','[]','離家凡幾宵，一望一寥寥。',48,'全唐诗/poet.tang.33000.json','["離家凡幾宵，一望一寥寥。", "新魄又將滿，故鄉應漸遙。", "獨臨彭蠡水，遠憶洛陽橋。", "更有乘舟客，悽然亦駐橈。"]'),
('5a4abe7b-5b80-47f3-b3ef-4179383d40a1','王將軍宅夜聽歌','于武陵','唐','唐诗','tang','','[]','朱檻滿明月，美人歌落梅。',48,'全唐诗/poet.tang.33000.json','["朱檻滿明月，美人歌落梅。", "忽驚塵起處，疑有鳳飛來。", "一曲聽初徹，幾年愁暫開。", "東南正雲雨，不得見陽臺。"]'),
('4ab3bbbd-f261-439c-b404-75bf5faec101','長信宮','于武陵','唐','唐诗','tang','','[]','莫問古宮名，古宮空有城。',24,'全唐诗/poet.tang.33000.json','["莫問古宮名，古宮空有城。", "惟應東去水，不改舊時聲。"]'),
('9336eb1e-413b-4c58-b289-85d3bf38ec77','高樓','于武陵','唐','唐诗','tang','','[]','遠天明月出，照此誰家樓。',24,'全唐诗/poet.tang.33000.json','["遠天明月出，照此誰家樓。", "上有羅衣裳，涼風吹不休。"]'),
('793710bd-0fdf-40e4-a8e1-8ae10a9589a6','感古','司馬扎','唐','唐诗','tang','','[]','九折無停波，三光如轉燭。',48,'全唐诗/poet.tang.33000.json','["九折無停波，三光如轉燭。", "玄珠人不識，徒愛燕趙玉。", "祖龍已深惑，漢氏遠狥欲。", "驪山與茂陵，相對秋草綠。"]'),
('7b5f194c-1dec-411d-ac23-98e612da21c6','贈王道士','司馬扎','唐','唐诗','tang','','[]','玉洞秋有花，蓬山夜無鬼。',72,'全唐诗/poet.tang.33000.json','["玉洞秋有花，蓬山夜無鬼。", "豈知浮雲世，生死逐流水。", "瑤臺歌一曲，曲盡五煙起。", "悠然望虛路，玉京在海裏。", "青籙秘不聞，黃鶴去不止。", "願隨執輕策，往結周太子。"]'),
('ccff72d5-b22e-4d0e-a377-492bebaa63a5','古思','司馬扎','唐','唐诗','tang','','["\u957f\u6c5f"]','春華惜妾態，秋草念妾心。',48,'全唐诗/poet.tang.33000.json','["春華惜妾態，秋草念妾心。", "始知井邊桐，不如堂上琴。", "月落却羨鏡，花飛猶委苔。", "門前長江水，一去終不回。"]'),
('6a53dabd-7d2c-4ede-8b7e-de5ad4312e67','獵客','司馬扎','唐','唐诗','tang','','[]','五陵射鵰客，走馬占春光。',122,'全唐诗/poet.tang.33000.json','["五陵射鵰客，走馬占春光。", "下馬青樓前，華裾獨煌煌。", "自言家咸京，世族如金張。", "擊鐘傳鼎食，爾來八十強。", "朱門爭先開，車輪滿路傍。", "娥娥燕趙人，珠箔閉高堂。", "清歌雜妙舞，臨歡度曲長。", "朝遊園花新，夜宴池月涼。", "更以馳驟多，意氣事[彊]梁。", "君王正年少，終日在長楊。"]'),
('b00d447d-61e3-4e41-881a-c7d5086d5c52','送進士苗縱歸紫邏山居','司馬扎','唐','唐诗','tang','','[]','汝上多奇山，高懷愜清境。',72,'全唐诗/poet.tang.33000.json','["汝上多奇山，高懷愜清境。", "強來干名地，冠帶不能整。", "常言夢歸處，泉石寒更靜。", "鶴聲夜無人，空月隨松影。", "今朝拋我去，春物傷明景。", "悵望相送還，微陽在東嶺。"]'),
('fa9dbfb9-c242-4e05-9490-352407fe97da','賣花者','司馬扎','唐','唐诗','tang','','[]','少壯彼何人，種花荒苑外。',120,'全唐诗/poet.tang.33000.json','["少壯彼何人，種花荒苑外。", "不知力田苦，却笑耕耘輩。", "當春賣春色，來往經幾代。", "長安甲第多，處處花堪愛。", "良金不惜費，競取園中最。", "一蕊纔占煙，歌聲已高會。", "自言種花地，終日擁軒蓋。", "農夫官役時，獨與花相對。", "那令賣花者，久爲生人害。", "貴粟不貴花，生人自應泰。"]'),
('fa3344f0-808f-4513-8abf-8a49a0239f31','彈琴','司馬扎','唐','唐诗','tang','','[]','涼室無外響，空桑七弦分。',48,'全唐诗/poet.tang.33000.json','["涼室無外響，空桑七弦分。", "所彈非新聲，俗耳安肯聞。", "月落未終曲，暗中泣湘君。", "如傳我心苦，千里蒼梧雲。"]'),
('14276ab6-8a27-4943-bd15-b69ec7ea9b18','古邊卒思歸','司馬扎','唐','唐诗','tang','','[]','有田不得耕，身臥遼陽城。',72,'全唐诗/poet.tang.33000.json','["有田不得耕，身臥遼陽城。", "夢中稻花香，覺後戰血腥。", "漢武在深殿，唯思廓寰瀛。", "中原半烽火，此屋皆點行。", "邊土無膏腴，閑地何必爭。", "徒令執耒者，刀下死縱橫。"]'),
('07399eed-2d4e-41ae-825c-d35caadcc6f7','美劉太保','司馬扎','唐','唐诗','tang','','[]','常愛魯仲連，退身得其趣。',96,'全唐诗/poet.tang.33000.json','["常愛魯仲連，退身得其趣。", "不知鴟夷子，更入五湖去。", "雲霞恣搖曳，鴻鵠無低翥。", "萬里天地空，清飆在平楚。", "藏名向寵節，辭疾去公務。", "夜盡醉弦歌，日高臥煙樹。", "豈嗤生前樂，千載自垂裕。", "論道復論功，皆可黃金鑄。"]'),
('925af261-c6ac-46c0-a24a-ae8ff4f615f9','蠶女','司馬扎','唐','唐诗','tang','','[]','養蠶先養桑，蠶老人亦衰。',72,'全唐诗/poet.tang.33000.json','["養蠶先養桑，蠶老人亦衰。", "苟無園中葉，安得機上絲。", "妾家非豪門，官賦日相追。", "鳴梭夜達曉，猶恐不及時。", "但憂蠶與桑，敢問結髮期。", "東鄰女新嫁，照鏡弄蛾眉。"]'),
('2850ab41-f74d-4d9d-aff0-dabc4a1c7923','效陶彭澤','司馬扎','唐','唐诗','tang','','[]','一夢倏已盡，百年如露草。',72,'全唐诗/poet.tang.33000.json','["一夢倏已盡，百年如露草。", "獨有南山高，不與人共老。", "尊中貯靈味，無事即醉倒。", "何必鳴鼓鍾，然後樂懷抱。", "輕波向海疾，浮雲歸谷早。", "形役良可嗟，唯能狥天道。"]'),
('bdf08d0a-1edf-4bd4-a382-0c28f5a6f948','鋤草怨','司馬扎','唐','唐诗','tang','','[]','種田望雨多，雨多長蓬蒿。',96,'全唐诗/poet.tang.33000.json','["種田望雨多，雨多長蓬蒿。", "亦念官賦急，寧知荷鋤勞。", "亭午霽日明，鄰翁醉陶陶。", "鄉吏不到門，禾黍苗自高。", "獨有辛苦者，屢爲州縣徭。", "罷鋤田又廢，戀鄉不忍逃。", "出門吏相促，鄰家滿倉穀。", "鄰翁不可告，盡日向田哭。"]'),
('a03fc20d-f7bd-4f9c-a7c4-376629deb79d','山中晚興寄裴侍御','司馬扎','唐','唐诗','tang','','[]','雷息疎雨散，空山夏雲晴。',72,'全唐诗/poet.tang.33000.json','["雷息疎雨散，空山夏雲晴。", "南軒對林晚，籬落新蛩鳴。", "白酒一樽滿，坐歌天地清。", "十年身未閑，心在人間名。", "永懷君親恩，久賤難退情。", "安得蓬丘侶，提攜採瑤英。"]'),
('28b8a470-9971-4eaa-9acf-e9feefc5aa02','築臺','司馬扎','唐','唐诗','tang','','[]','魏國昔強盛，宮中金玉多。',108,'全唐诗/poet.tang.33000.json','["魏國昔強盛，宮中金玉多。", "徵丁築層臺，唯恐不巍峩。", "結構切星漢，躋攀橫綺羅。", "朝觀細腰舞，夜聽皓齒歌。", "詎念人力勞，安問黍與禾。", "一朝國既傾，千仞堂亦平。", "舞模衰柳影，歌留草蟲聲。", "月照白露寒，蒼蒼故鄴城。", "漢文有遺美，對此清飆生。"]'),
('d390439e-39c6-4d25-8e71-1f206941e71d','道中早發','司馬扎','唐','唐诗','tang','','[]','野店雞一聲，蕭蕭客車動。',72,'全唐诗/poet.tang.33000.json','["野店雞一聲，蕭蕭客車動。", "西峯帶曉月，十里猶相送。", "繁弦滿長道，羸馬四蹄重。", "遙羨青樓人，錦衾方遠夢。", "功名不我與，孤劍何所用。", "行役難自休，家山憶秋洞。"]'),
('18d967a7-1d37-4625-8e54-5516bf7f0d94','滄浪峽','司馬扎','唐','唐诗','tang','','[]','山下水聲深，水邊山色聚。',72,'全唐诗/poet.tang.33000.json','["山下水聲深，水邊山色聚。", "月照秋自清，花名春不去。", "似非人間境，又近紅塵路。", "乍入洞中天，更移雲外步。", "我殊惺惺者，猶得滄浪趣。", "可以濯吾纓，斯言誠所慕。"]'),
('2327a4c2-734a-41a8-8bfa-47a99ff25862','感螢','司馬扎','唐','唐诗','tang','','[]','愛爾持照書，臨書嘆吾道。',36,'全唐诗/poet.tang.33000.json','["愛爾持照書，臨書嘆吾道。", "青熒一點光，曾誤幾人老。", "夜久獨此心，環垣閉秋草。"]'),
('408d91c7-a918-421c-8e68-22b6a50bc77e','自渭南晚次華州','司馬扎','唐','唐诗','tang','','[]','前樓仙鼎原，西經赤水渡。',96,'全唐诗/poet.tang.33000.json','["前樓仙鼎原，西經赤水渡。", "火雲入村巷，餘雨依驛樹。", "我行傷去國，疲馬屢回顧。", "有如無窠鳥，觸熱不得住。", "峨峨華峰近，城郭生夕霧。", "逆旅何人尋，行客暗中住。", "却思林丘臥，自愜平生素。", "勞役今若茲，羞吟招隱句。"]'),
('21e3fc6e-0322-41b8-b586-76e6c93ee064','近別','司馬扎','唐','唐诗','tang','','[]','咫尺不相見，便同天一涯。',48,'全唐诗/poet.tang.33000.json','["咫尺不相見，便同天一涯。", "何必隔關山，乃言傷別離。", "君心與我心，脈脈無由知。", "誰堪近別苦，遠別猶有期。"]'),
('97310e23-b545-4b6e-a530-a74edb94401a','江上秋夕','司馬扎','唐','唐诗','tang','','[]','茂陵歸路絕，誰念此淹留。',48,'全唐诗/poet.tang.33000.json','["茂陵歸路絕，誰念此淹留。", "極目月沈浦，苦吟霜滿舟。", "孤猨啼後夜，久客病高秋。", "欲寄鄉關恨，寒江無北流。"]'),
('2e561f18-2348-45a6-80b1-364824ff031a','送歸客','司馬扎','唐','唐诗','tang','','[]','多才與命違，末路隱柴扉。',48,'全唐诗/poet.tang.33000.json','["多才與命違，末路隱柴扉。", "白髮何人問，青山一劍歸。", "晴煙獨鳥沒，野渡亂花飛。", "寂寞長亭外，依然空落暉。"]'),
('81fe9653-efb5-48c7-a8a7-f21889bd5abb','東門晚望','司馬扎','唐','唐诗','tang','','[]','青門聊極望，何事久離羣。',48,'全唐诗/poet.tang.33000.json','["青門聊極望，何事久離羣。", "芳草失歸路，故鄉空暮雲。", "信回陵樹老，夢斷灞流分。", "兄弟正南北，鴻聲堪獨聞。"]'),
('b0056e0d-8129-47bd-a339-3ecf5bc6e0a4','上巳日曲江有感','司馬扎','唐','唐诗','tang','','[]','萬花明曲水，車馬動秦川。',48,'全唐诗/poet.tang.33000.json','["萬花明曲水，車馬動秦川。", "此日不得意，青春徒少年。", "晴沙下鷗鷺，幽沚生蘭荃。", "向晚積歸念，江湖心渺然。"]'),
('c3a336f9-70cf-42be-bda3-5868cf31cc4e','宿壽安甘棠館','司馬扎','唐','唐诗','tang','','[]','行人方倦役，到此似還鄉。',48,'全唐诗/poet.tang.33000.json','["行人方倦役，到此似還鄉。", "流水來關外，青山近洛陽。", "溪雲歸洞鶴，松月半軒霜。", "坐恐晨鐘動，天涯道路長。"]'),
('4dd0bb50-33ec-4f6e-bbc1-f3cf7004e248','送友人下第東遊','司馬扎','唐','唐诗','tang','','[]','出門皆有託，君去獨何親。',48,'全唐诗/poet.tang.33000.json','["出門皆有託，君去獨何親。", "闕下新交少，天涯舊業貧。", "煙寒嶽樹暝，雪後嶺梅春。", "聖代留崑玉，那令愧郄詵。"]'),
('7164b5a2-b1ac-4a35-a5e4-9104ac73507a','山齋會別','司馬扎','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','春草平陵路，荷衣醉別離。',48,'全唐诗/poet.tang.33000.json','["春草平陵路，荷衣醉別離。", "將尋洛陽友，共結洞庭期。", "星月半山盡，天雞出海遲。", "無輕此分手，他日重相思。"]'),
('f4e05646-6b81-4a6d-89d6-027127804642','曉過伊水寄龍門僧','司馬扎','唐','唐诗','tang','','[]','龍門樹色暗蒼蒼，伊水東流客恨長。',64,'全唐诗/poet.tang.33000.json','["龍門樹色暗蒼蒼，伊水東流客恨長。", "病馬獨嘶殘夜月，行人欲渡滿船霜。", "幾家煙火依村步，何處漁歌似故鄉？", "山下禪菴老師在，願將形役問空王。"]'),
('d140535d-2598-4a93-ac7d-de1aeba2c9cd','送孔恂入洛','司馬扎','唐','唐诗','tang','','[]','洛陽古城秋色多，送君此去心如何。',64,'全唐诗/poet.tang.33000.json','["洛陽古城秋色多，送君此去心如何。", "青山欲暮惜別酒，碧草未盡傷離歌。", "前朝冠帶掩金谷，舊遊花月經銅駝。", "行人正苦奈分手，日落遠水生微波。"]'),
('32052178-e4ac-4dc9-b6c0-4b962261632f','觀郊禮','司馬扎','唐','唐诗','tang','','[]','鐘鼓旌旗引六飛，玉皇初著畫龍衣。',32,'全唐诗/poet.tang.33000.json','["鐘鼓旌旗引六飛，玉皇初著畫龍衣。", "泰壇煙盡星河曉，萬國心隨彩仗歸。"]'),
('47422314-a323-4b8f-b83b-76093f835055','宮怨','司馬扎','唐','唐诗','tang','','[]','柳色參差掩畫樓，曉鶯啼送滿宮愁。',32,'全唐诗/poet.tang.33000.json','["柳色參差掩畫樓，曉鶯啼送滿宮愁。", "年年花落無人見，空逐春泉出御溝。"]'),
('9964321a-16ed-4fe4-ba73-a18465c25d7e','南徐夕眺','司馬扎','唐','唐诗','tang','','[]','行吟向暮天，何處不悽然？',48,'全唐诗/poet.tang.33000.json','["行吟向暮天，何處不悽然？", "岸影幾家柳，笛聲何處船。", "樓分瓜步月，鳥入秣陵煙。", "故里無人到，鄉書誰爲傳。"]'),
('b4b61949-735e-4b22-8c02-ca7fcab890aa','題清上人','司馬扎','唐','唐诗','tang','','[]','古院閉松色，入門人自閑。',48,'全唐诗/poet.tang.33000.json','["古院閉松色，入門人自閑。", "罷經來宿鳥，支策對秋山。", "客念蓬梗外，禪心煙霧間。", "空憐濯纓處，階下水潺潺。"]'),
('89f8ca30-783d-4cf7-b000-8e460681c961','塗中寄薛中裕','司馬扎','唐','唐诗','tang','','[]','貧交千里外，失路更傷離。',48,'全唐诗/poet.tang.33000.json','["貧交千里外，失路更傷離。", "曉淚芳草盡，夜魂明月知。", "空山連野外，寒鳥下霜枝。", "此景正寥落，爲君玄髪衰。"]'),
('06357ff7-17ed-47dc-af95-662a1aba2e71','白馬津阻雨','司馬扎','唐','唐诗','tang','','[]','津樹蕭蕭旅館空，坐看疎葉繞堦紅。',64,'全唐诗/poet.tang.33000.json','["津樹蕭蕭旅館空，坐看疎葉繞堦紅。", "故鄉千里楚雲外，歸鴈一聲煙雨中。", "漳浦病多愁易老，茂陵書在信難通。", "功名儻遂身無事，終向溪頭伴釣翁。"]'),
('7cdf2d9b-29c2-452b-b35b-d1232f7f3f3e','秋日懷儲嗣宗','司馬扎','唐','唐诗','tang','','[]','故人北遊久不回，塞鴈南渡聲何哀。',32,'全唐诗/poet.tang.33000.json','["故人北遊久不回，塞鴈南渡聲何哀。", "相思聞鴈更惆悵，却向單于臺下來。"]'),
('0043d602-6f92-4761-ba75-92691019f99d','夜聽李山人彈琴','司馬扎','唐','唐诗','tang','','[]','瑤琴夜久弦秋清，楚客一奏湘煙生。',32,'全唐诗/poet.tang.33000.json','["瑤琴夜久弦秋清，楚客一奏湘煙生。", "曲中聲盡意不盡，月照竹軒紅葉明。"]'),
('e3deaed4-56e7-47d6-9e77-1f928f5cace3','隱者','司馬扎','唐','唐诗','tang','','[]','松間開一徑，秋草自相依。',48,'全唐诗/poet.tang.33000.json','["松間開一徑，秋草自相依。", "終日不冠帶，空山無是非。", "投綸溪鳥伴，曝藥谷雲飛。", "時向鄰家去，狂歌夜醉歸。"]'),
('1ea99c1a-40f3-461e-8167-8b52b77acd70','登河中鸛[雀]樓','司馬扎','唐','唐诗','tang','','[]','樓中見千里，樓影入通津。',48,'全唐诗/poet.tang.33000.json','["樓中見千里，樓影入通津。", "煙樹遙分陝，山河曲向秦。", "興亡留白日，今古共紅塵。", "鸛雀飛何處，城隅草自春。"]'),
('450db7df-1306-47dc-b4f8-d7809129bfe2','漾陂晚望','司馬扎','唐','唐诗','tang','','[]','遠客家水國，此來如到鄉。',48,'全唐诗/poet.tang.33000.json','["遠客家水國，此來如到鄉。", "何人垂白髮，一葉釣殘陽。", "柳暗鳥乍起，渚深蘭自芳。", "因知帝城下，有路向滄浪。"]'),
('1ff35c04-74ea-4ccf-96b6-e997b65cd299','賀襄陽副使節判同加章綬','徐商','唐','唐诗','tang','','[]','朱紫花前賀故人，兼榮此會頗關身。',64,'全唐诗/poet.tang.33000.json','["朱紫花前賀故人，兼榮此會頗關身。", "同年坐上聯賓榻，宗姓亭中布錦裀。", "晴日照旗紅灼爍，韶光入隊影玢璘。", "芳菲解助今朝喜，嫩蘂青條滿眼新。"]'),
('cecb3152-105e-464a-8d92-36a546b522e3','句','徐商','唐','唐诗','tang','','[]','萍聚只因今日浪，荻斜都爲夜來風。',16,'全唐诗/poet.tang.33000.json','["萍聚只因今日浪，荻斜都爲夜來風。"]'),
('ab9b9e43-8233-4259-adf8-6a7014dc94f7','和薛逢贈別','高璩','唐','唐诗','tang','','[]','劒外綿州第一州，尊前偏喜接君留。',64,'全唐诗/poet.tang.33000.json','["劒外綿州第一州，尊前偏喜接君留。", "歌聲婉轉添長恨，管色淒涼似到秋。", "但務歡娛思曉角，獨耽雲水上高樓。", "莫言此去難相見，怨別徵黃是順流。"]'),
('4aecab54-86f7-4f26-9ac3-28498c80f0e9','句','高璩','唐','唐诗','tang','','[]','公齋一到人非舊，詩板重尋墨尚新。',16,'全唐诗/poet.tang.33000.json','["公齋一到人非舊，詩板重尋墨尚新。"]'),
('e65a5187-14c1-4e30-97fa-3ff1b269f189','和李尚書命妓餞崔侍御','高湘','唐','唐诗','tang','','[]','謝安春渚餞袁宏，千里仁風一扇清。',32,'全唐诗/poet.tang.33000.json','["謝安春渚餞袁宏，千里仁風一扇清。", "歌黛慘時方酩酊，不知公子重飛觥。"]'),
('e9d06ed5-b9e1-4e17-b2c8-b73a39f2df69','句','高湘','唐','唐诗','tang','','[]','惟有高州是當家。',8,'全唐诗/poet.tang.33000.json','["惟有高州是當家。"]');
